async def solo_game_timer(context, chat_id, match, player_type, player_name):
    """Timer specifically for Solo Mode (45s)"""
    try:
        # Wait 30 seconds
        await asyncio.sleep(30)
        try:
            await context.bot.send_message(
                chat_id, 
                f"⏳ <b>Hurry Up {player_name}!</b>\n─────────────────\n⚠️ Only <b>15 seconds</b> left → play your ball!", 
                parse_mode=ParseMode.HTML
            )
        except: pass
        
        # Remaining 15 Seconds
        await asyncio.sleep(15)
        
        # Timeout Trigger
        await handle_solo_timeout(context, chat_id, match, player_type)
            
    except asyncio.CancelledError:
        pass

async def handle_solo_timeout(context, chat_id, match, player_type):
    """Handle Penalties for Solo Mode Timeouts"""
    
    # --- BATSMAN TIMEOUT ---
    if player_type == "batsman":
        batter = match.solo_players[match.current_solo_bat_idx]
        batter.batting_timeouts += 1
        
        # 3 Timeouts = AUTO OUT
        if batter.batting_timeouts >= 3:
            msg = f"🚫 <b>AUTO-OUT!</b> {batter.first_name} timed out 3 times.\n❌ <b>Result:</b> Wicket!"
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
            
            # Simulate Wicket Logic
            match.current_ball_data["batsman_number"] = match.current_ball_data["bowler_number"]
            await process_solo_turn_result(context, chat_id, match)
            return

        # < 3 Timeouts = -6 Penalty
        else:
            penalty = 6
            batter.runs -= penalty
            if batter.runs < 0: batter.runs = 0
            
            msg = f"⏰ <b>TIMEOUT WARNING!</b> ({batter.batting_timeouts}/3)\n"
            msg = f"─────────────────\n"
            msg += f"📉 <b>Penalty:</b> -6 Runs deducted!\n"
            msg += f"📊 <b>Current Score:</b> {batter.runs}"
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
            
            batter.balls_faced += 1
            await rotate_solo_bowler(context, chat_id, match)

    # --- BOWLER TIMEOUT ---
    elif player_type == "bowler":
        bowler = match.solo_players[match.current_solo_bowl_idx]
        batter = match.solo_players[match.current_solo_bat_idx]
        bowler.bowling_timeouts += 1
        
        # 3 Timeouts = BANNED
        if bowler.bowling_timeouts >= 3:
            bowler.is_bowling_banned = True
            msg = f"🚫 <b>BANNED!</b> {bowler.first_name} timed out 3 times!\n"
            msg += "⚠️ <b>They are removed from bowling rotation!</b>"
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
            
            await rotate_solo_bowler(context, chat_id, match, force_new_bowler=True)
            return
            
        # < 3 Timeouts = NO BALL + FREE HIT
        else:
            batter.runs += 1
            match.is_free_hit = True
            
            msg = f"⏰ <b>BOWLER TIMEOUT!</b> ({bowler.bowling_timeouts}/3)\n"
            msg = "─────────────────\n"
            msg += "🚫 <b>Result:</b> DEAD BALL! (+1 Run)\n"
            msg += "⚡ <b>Next ball is a NORMAL BALL!</b>\n"
            msg += "🔄 <i>Bowler must bowl again!</i>"
            await context.bot.send_message(chat_id, msg, parse_mode=ParseMode.HTML)
            
            match.ball_timeout_task = asyncio.create_task(
                solo_game_timer(context, chat_id, match, "bowler", bowler.first_name)
            )

# Helper to Rotate Bowler in Solo (Handles the Skip Logic)
async def rotate_solo_bowler(context, chat_id, match, force_new_bowler=False):
    """Rotates bowler, skipping banned players"""
    
    if not force_new_bowler:
        match.solo_balls_this_spell += 1

    if match.solo_balls_this_spell >= 3 or force_new_bowler:
        match.solo_balls_this_spell = 0
        
        original_idx = match.current_solo_bowl_idx
        attempts = 0
        total_players = len(match.solo_players)
        
        while True:
            match.current_solo_bowl_idx = (match.current_solo_bowl_idx + 1) % total_players
            
            if match.current_solo_bowl_idx == match.current_solo_bat_idx:
                match.current_solo_bowl_idx = (match.current_solo_bowl_idx + 1) % total_players
                
            next_bowler = match.solo_players[match.current_solo_bowl_idx]
            
            if not next_bowler.is_bowling_banned:
                break
            
            attempts += 1
            if attempts > total_players:
                await context.bot.send_message(chat_id, "⚠️ All players banned! Game Over.")
                await end_solo_game_logic(context, chat_id, match)
                return

        new_bowler = match.solo_players[match.current_solo_bowl_idx]
        await context.bot.send_message(chat_id, f"🔄 <b>New Bowler:</b> {new_bowler.first_name}", parse_mode=ParseMode.HTML)

    await trigger_solo_ball(context, chat_id, match)

async def check_user_started_bot(bot, user_id: int) -> bool:
    """
    Check if a user has started the bot by attempting to send them a
    chat action. Returns True if reachable, False if Forbidden (bot not started).
    """
    try:
        await bot.send_chat_action(user_id, "typing")
        return True
    except Forbidden:
        return False
    except Exception:
        # Other errors (network, etc.) — assume reachable to avoid false negatives
        return True


# Start command handler
async def start_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Welcome message with Add to Group button"""

    # ── Handle "Deliver Bowl" deep link: ?start=bowl_{group_id} ──
    if context.args and context.args[0].startswith('bowl_'):
        try:
            group_id = int(context.args[0].split('_')[1])
            user = update.effective_user

            match = active_matches.get(group_id)
            # Support both TEAM (MATCH_IN_PROGRESS) and SOLO (SOLO_MATCH) phases
            if not match or match.phase not in (GamePhase.MATCH_IN_PROGRESS, GamePhase.SOLO_MATCH):
                await update.message.reply_text(
                    "⚠️ <b>No active match found!</b>\n"
                    "<i>The match may have ended or not started yet.</i>",
                    parse_mode=ParseMode.HTML
                )
                return

            # ── Build group redirect button ──
            try:
                _cid_str = str(abs(group_id))
                _tme_gid = _cid_str[3:] if _cid_str.startswith("100") else _cid_str
                _game_url = f"https://t.me/c/{_tme_gid}/{match.main_message_id or 1}"
                _go_group_markup = InlineKeyboardMarkup([[
                    InlineKeyboardButton("🏟️ Go to Game", url=_game_url)
                ]])
            except Exception:
                _go_group_markup = None

            # ── SOLO MODE ──
            if match.phase == GamePhase.SOLO_MATCH:
                if match.current_solo_bowl_idx < len(match.solo_players):
                    bowler = match.solo_players[match.current_solo_bowl_idx]
                    if bowler.user_id == user.id:
                        if match.current_ball_data.get("bowler_number") is not None:
                            await update.message.reply_text(
                                "✅ <b>You've already bowled this ball!</b>\n"
                                "<i>Wait for the batsman to play their shot.</i>",
                                parse_mode=ParseMode.HTML,
                                reply_markup=_go_group_markup
                            )
                            return
                        batter = match.solo_players[match.current_solo_bat_idx] if match.current_solo_bat_idx < len(match.solo_players) else None
                        dm_text = (
                            f"⚔️ <b>SOLO MATCH — YOUR TURN TO BOWL!</b>\n"
                            f"─────────────────\n"
                        )
                        if batter:
                            sr = round((batter.runs / max(batter.balls_faced, 1)) * 100, 1)
                            dm_text += f"🏏 Batsman: <b>{batter.first_name}</b>  {batter.runs}({batter.balls_faced})  SR {sr}\n"
                        dm_text += (
                            f"─────────────────\n"
                            f"📩 <b>Send a number (0–6) to bowl!</b>\n"
                            f"⏱ <i>Timer is running!</i>"
                        )
                        await update.message.reply_text(dm_text, parse_mode=ParseMode.HTML, reply_markup=_go_group_markup)
                        return
                    else:
                        await update.message.reply_text(
                            "⚠️ <b>You are not the current bowler!</b>",
                            parse_mode=ParseMode.HTML,
                            reply_markup=_go_group_markup
                        )
                        return
                return

            # ── TEAM MODE ──
            bowl_team = match.current_bowling_team
            if bowl_team and bowl_team.current_bowler_idx is not None:
                bowler = bowl_team.players[bowl_team.current_bowler_idx]
                if bowler.user_id == user.id:
                    # Player is the current bowler → send them the bowl prompt
                    if match.current_ball_data.get("bowler_number") is not None:
                        await update.message.reply_text(
                            "✅ <b>You've already bowled this ball!</b>\n"
                            "<i>Wait for the batsman to play their shot.</i>",
                            parse_mode=ParseMode.HTML,
                            reply_markup=_go_group_markup
                        )
                        return

                    bat_team = match.current_batting_team
                    striker = bat_team.players[bat_team.current_batsman_idx] if bat_team.current_batsman_idx is not None else None

                    dm_text = f"⚾ <b>YOUR TURN TO BOWL!</b>\n"
                    dm_text += f"─────────────────\n"
                    if striker:
                        dm_text += f"🏏 Batsman: <b>{striker.first_name}</b>  ({striker.runs}/{striker.balls_faced})\n"
                    dm_text += f"📊 Score: <b>{bat_team.score}/{bat_team.wickets}</b>  ({format_overs(bat_team.balls)} ov)\n"
                    if match.innings == 2:
                        runs_needed = match.target - bat_team.score
                        balls_left = (match.total_overs * 6) - bat_team.balls
                        dm_text += f"🎯 Defend: <b>{runs_needed} runs</b> in <b>{balls_left} balls</b>\n"
                    if match.is_free_hit:
                        dm_text += "⚡ <b>FREE HIT!</b> → Batsman cannot be dismissed!\n"
                    dm_text += f"─────────────────\n"
                    dm_text += "📩 <b>Send a number (0–6) to bowl!</b>\n"
                    dm_text += "⏱ <i>Timer is running!</i>"

                    await update.message.reply_text(dm_text, parse_mode=ParseMode.HTML, reply_markup=_go_group_markup)
                    return
                else:
                    await update.message.reply_text(
                        "⚠️ <b>You are not the current bowler!</b>",
                        parse_mode=ParseMode.HTML,
                        reply_markup=_go_group_markup
                    )
                    return
            else:
                await update.message.reply_text(
                    "⚠️ <b>No bowler is set right now.</b>\n<i>Please wait for the over to start.</i>",
                    parse_mode=ParseMode.HTML,
                    reply_markup=_go_group_markup
                )
                return
        except Exception as e:
            logger.error(f"bowl deep link error: {e}")
            # Fall through to normal start

    # Check for registration deep link
    if context.args and context.args[0].startswith('reg_'):
        try:
            parts = context.args[0].split('_')
            group_id = int(parts[1])
            base_price = int(parts[2])
            
            user_id = update.effective_user.id
            username = update.effective_user.username or 'NoUsername'
            full_name = update.effective_user.full_name
            
            # ✅ FIX 6: Check if registration is still active (link expiry)
            is_active = False
            if group_id in REGISTRATION_ACTIVE:
                end_dt = REGISTRATION_ACTIVE[group_id].get('end_date')
                if end_dt and end_dt > datetime.now():
                    is_active = True
            
            if not is_active:
                # Check DB — must be is_active=1 AND end_date in future
                conn_check = sqlite3.connect(TOURNAMENT_DB_PATH)
                c_check = conn_check.cursor()
                c_check.execute(
                    "SELECT is_active, end_date FROM registration_periods WHERE group_id = ? AND is_active = 1",
                    (group_id,)
                )
                row = c_check.fetchone()
                conn_check.close()
                if row:
                    try:
                        end_dt_db = datetime.fromisoformat(row[1])
                        if end_dt_db > datetime.now():
                            is_active = True
                    except Exception:
                        pass
            
            if not is_active:
                await update.message.reply_text(
                    "⏰ <b>Registration Closed!</b>\n"
                    "─────────────────\n"
                    "This registration link has expired.\n"
                    "<i>Contact your group admin for more info.</i>",
                    parse_mode=ParseMode.HTML
                )
                return
            
            # Check if already registered
            conn = sqlite3.connect(TOURNAMENT_DB_PATH)
            c = conn.cursor()
            c.execute('SELECT user_id FROM registered_players WHERE user_id = ? AND group_id = ?', (user_id, group_id))
            if c.fetchone():
                conn.close()
                await update.message.reply_text(
                    "✅ <b>Already Registered!</b>\n"
                    "─────────────────\n"
                    "You are already registered for this tournament.\n"
                    "<i>Good luck, champion! 🏏</i>",
                    parse_mode=ParseMode.HTML
                )
                return
            
            # Register the player
            c.execute(
                'INSERT INTO registered_players (group_id, user_id, username, full_name, base_price, registered_at) VALUES (?, ?, ?, ?, ?, ?)',
                (group_id, user_id, username, full_name, base_price, datetime.now())
            )
            conn.commit()
            conn.close()
            
            # Get tournament name
            tour_name = REGISTRATION_ACTIVE.get(group_id, {}).get('tournament_name', 'Tournament')
            
            # Send confirmation to user
            await update.message.reply_photo(
                photo=REGISTRATION_OPEN_PHOTO,
                caption=(
                    f"✅ <b>REGISTRATION SUCCESSFUL!</b>\n"
                    f"─────────────────\n"
                    f"🏆 <b>Tournament:</b> {tour_name}\n"
                    f"👤 <b>Name:</b> {full_name}\n"
                    f"🔖 <b>Username:</b> @{username}\n"
                    f"💰 <b>Base Price:</b> {base_price} coins\n"
                    f"─────────────────\n"
                    f"🍀 <i>All the best, champion! May the best player win!</i>"
                ),
                parse_mode=ParseMode.HTML
            )
            
            # Notify in group
            try:
                await context.bot.send_photo(
                    chat_id=group_id,
                    photo=PLAYER_REGISTERED_PHOTO,
                    caption=(
                        f"🎊 <b>NEW PLAYER REGISTERED!</b>\n"
                        f"─────────────────\n"
                        f"👤 <b>{full_name}</b>\n"
                        f"🔖 @{username}\n"
                        f"💰 <b>Base Price:</b> {base_price} coins\n"
                        f"─────────────────\n"
                        f"🏆 Welcome to <b>{tour_name}</b>! 🍀"
                    ),
                    parse_mode=ParseMode.HTML
                )
            except Exception:
                pass
            
            return
        except Exception as e:
            logger.error(f"Registration link error: {e}")
            await update.message.reply_text(
                "❌ <b>Registration Failed!</b>\n"
                "Invalid link or an error occurred. Please try again or contact your group admin.",
                parse_mode=ParseMode.HTML
            )
            return

    user = update.effective_user
    chat = update.effective_chat
    
    is_new_user = False
    
    if user.id not in user_data:
        user_data[user.id] = {
            "user_id": user.id,
            "username": user.username or "",
            "first_name": user.first_name,
            "started_at": datetime.now().isoformat(),
            "total_matches": 0
        }
        init_player_stats(user.id)
        save_data()
        is_new_user = True

        if chat.type == "private":
            try:
                await context.bot.send_message(
                    chat_id=SUPPORT_GROUP_ID,
                    text=f"🆕 <b>New User Started Bot</b>\n👤 {user.first_name} (<a href='tg://user?id={user.id}'>{user.id}</a>)\n🎈 @{user.username}",
                    parse_mode=ParseMode.HTML
                )
            except: pass

    welcome_text = (
        "╭━━ 🏏 CRICOVERSE ━━━━━━━━━━━━━━━🏟️\n"
        "┃ ⚡ THE ULTIMATE HAND CRICKET BOT\n"
        "┃\n"
        "┃ 🎮 GAME MODES\n"
        "┃ ├ 👥 Team Match   ➔ 2-team battles\n"
        "┃ ├ ⚔️ Solo Battle  ➔ Free-for-all\n"
        "┃ ├ 🤖 AI Mode      ➔ Play vs bot\n"
        "┃ └ 🔮 Magic Ball   ➔ Wild card mode\n"
        "┃\n"
        "┃ 🏆 FEATURES\n"
        "┃ ├ 📺 DRS Reviews  ┃ 🎙️ Commentary\n"
        "┃ ├ 📊 Career Stats ┃ 🏅 Tournaments\n"
        "┃ └ 🔥 Leaderboards ┃ 🧢 Captaincy\n"
        "┃\n"
        "┃ 👇 Add me to your group!\n"
        "┃ ⚙ Use: /game to get started\n"
        "╰━━━━━━━━━━━━━━━━━━━━━━━━━━"
    )

    
    if chat.type == "private":
        # Add to Group button
        bot_username = (await context.bot.get_me()).username
        keyboard = [
            [InlineKeyboardButton("➕ Add to Group", url=f"https://t.me/{bot_username}?startgroup=true")]
        ]
        
        await update.message.reply_photo(
            photo=MEDIA_ASSETS["welcome"],
            caption=welcome_text,
            reply_markup=InlineKeyboardMarkup(keyboard),
            parse_mode=ParseMode.HTML
        )
    else:
        await update.message.reply_text("Bot is ready! Use /game to start.\n Please give me the command to Schedule your match")

