async def teamcreate_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Create a tournament team: /teamcreate [team name]"""
    chat = update.effective_chat
    user = update.effective_user

    if chat.type == "private":
        await update.message.reply_text("Use this command in a group!")
        return

    group_id = chat.id

    # Check approval → silently ignore unapproved groups
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return

    # Admin check
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("🚫 Only group admins can create teams!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "📋 Usage: <code>/teamcreate [team name]</code>\nExample: <code>/teamcreate Team Alpha</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    team_name = " ".join(context.args).strip()
    
    if team_name in tournament_teams[group_id]:
        await update.message.reply_text(f"⚠️ Team '<b>{team_name}</b>' already exists!", parse_mode=ParseMode.HTML)
        return
    
    tournament_teams[group_id][team_name] = {"players": [], "captain": None}
    
    await update.message.reply_text(
        f"✅ <b>Team Created!</b>\n"
        f"─────────────────\n"
        f"🏏 <b>Team:</b> {team_name}\n\n"
        f"Now add players:\n"
        f"<code>/teamadd {team_name} @username @username2...</code>",
        parse_mode=ParseMode.HTML
    )


async def teamadd_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Add players to tournament team: /teamadd [team] @user @user2...
    Also supports reply to add single user, or user IDs."""
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.type == "private":
        await update.message.reply_text("Use this command in a group!")
        return
    
    group_id = chat.id
    
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("🚫 Only admins can add players!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "📋 Usage: <code>/teamadd [team name] @user @user2...</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    # Parse: first arg(s) might be multi-word team name, then @mentions
    args = context.args
    teams = tournament_teams.get(group_id, {})
    
    # Find team name (try progressively longer phrases)
    team_name = None
    player_args_start = 0
    for i in range(len(args), 0, -1):
        potential = " ".join(args[:i])
        if potential in teams:
            team_name = potential
            player_args_start = i
            break
    
    if not team_name:
        team_list = ", ".join(teams.keys()) if teams else "None"
        await update.message.reply_text(
            f"⚠️ Team not found!\nAvailable teams: {team_list}",
            parse_mode=ParseMode.HTML
        )
        return
    
    player_args = args[player_args_start:]
    added = []
    failed = []
    
    # Parse mentions and user IDs
    entities = update.message.entities or []
    mentioned_users = []
    for entity in entities:
        if entity.type == "mention":
            username = update.message.text[entity.offset+1:entity.offset+entity.length]
            try:
                chat_member = await context.bot.get_chat_member(group_id, f"@{username}")
                mentioned_users.append({
                    "user_id": chat_member.user.id,
                    "username": chat_member.user.username or "",
                    "first_name": chat_member.user.first_name
                })
            except:
                failed.append(f"@{username}")
        elif entity.type == "text_mention" and entity.user:
            mentioned_users.append({
                "user_id": entity.user.id,
                "username": entity.user.username or "",
                "first_name": entity.user.first_name
            })
    
    # Also check numeric user IDs in args
    for arg in player_args:
        if arg.isdigit():
            try:
                cm = await context.bot.get_chat_member(group_id, int(arg))
                mentioned_users.append({
                    "user_id": cm.user.id,
                    "username": cm.user.username or "",
                    "first_name": cm.user.first_name
                })
            except:
                failed.append(arg)
    
    team_data = tournament_teams[group_id][team_name]
    existing_ids = {p["user_id"] for p in team_data["players"]}
    
    not_started = []  # Users who haven't started the bot
    for p in mentioned_users:
        if p["user_id"] not in existing_ids:
            # ✅ Check if player has started the bot before adding
            started = await check_user_started_bot(context.bot, p["user_id"])
            if not started:
                not_started.append(p["first_name"])
                # Still add them — but warn the admin
            team_data["players"].append(p)
            existing_ids.add(p["user_id"])
            added.append(p["first_name"])
    
    bot_username = context.bot.username
    msg = f"✅ <b>Players Added to {team_name}</b>\n─────────────────\n"
    if added:
        msg += f"✅ Added: {', '.join(added)}\n"
    if failed:
        msg += f"⚠️ Not found in group: {', '.join(failed)}\n"
    if not_started:
        msg += (
            f"\n⚠️ <b>Hasn't started bot:</b> {', '.join(not_started)}\n"
            f"👉 Ask them to start: <a href='https://t.me/{bot_username}'>@{bot_username}</a>\n"
            f"<i>They won't receive bowl/bat DMs until they do!</i>\n"
        )
    msg += f"\n📊 <b>Team size:</b> {len(team_data['players'])} players"
    
    await update.message.reply_text(msg, parse_mode=ParseMode.HTML, disable_web_page_preview=True)


async def teamremove_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Remove player(s) from tournament team: /teamremove [team] @user @user2..."""
    chat = update.effective_chat
    user = update.effective_user
    
    if chat.type == "private":
        return
    
    group_id = chat.id
    
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("🚫 Only admins can remove players!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "📋 Usage: <code>/teamremove [team name] @user @user2...</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    args = context.args
    teams = tournament_teams.get(group_id, {})
    
    team_name = None
    player_args_start = 0
    for i in range(len(args), 0, -1):
        potential = " ".join(args[:i])
        if potential in teams:
            team_name = potential
            player_args_start = i
            break
    
    if not team_name:
        await update.message.reply_text("⚠️ Team not found!")
        return
    
    # Collect IDs to remove
    ids_to_remove = set()
    entities = update.message.entities or []
    for entity in entities:
        if entity.type == "mention":
            username = update.message.text[entity.offset+1:entity.offset+entity.length]
            try:
                cm = await context.bot.get_chat_member(group_id, f"@{username}")
                ids_to_remove.add(cm.user.id)
            except:
                pass
        elif entity.type == "text_mention" and entity.user:
            ids_to_remove.add(entity.user.id)
    
    for arg in context.args[player_args_start:]:
        if arg.isdigit():
            ids_to_remove.add(int(arg))
    
    team_data = tournament_teams[group_id][team_name]
    before = len(team_data["players"])
    team_data["players"] = [p for p in team_data["players"] if p["user_id"] not in ids_to_remove]
    after = len(team_data["players"])
    removed = before - after
    
    await update.message.reply_text(
        f"✅ <b>Removed {removed} player(s) from {team_name}</b>\n"
        f"📊 <b>Team size:</b> {after} players",
        parse_mode=ParseMode.HTML
    )


async def tourresult_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Record tournament match result: /tourresult [winning_team]"""
    chat = update.effective_chat
    user = update.effective_user
    group_id = chat.id
    
    if chat.type == "private":
        return
    
    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return
    
    member = await context.bot.get_chat_member(group_id, user.id)
    if member.status not in ["administrator", "creator"]:
        await update.message.reply_text("🚫 Only admins can record results!")
        return
    
    if group_id not in pending_tour_match:
        await update.message.reply_text("⚠️ No active tournament match found!")
        return
    
    if not context.args:
        await update.message.reply_text(
            "📋 Usage: <code>/tourresult [winning team name]</code>\nOr <code>/tourresult tie</code>",
            parse_mode=ParseMode.HTML
        )
        return
    
    tm = pending_tour_match[group_id]
    t1 = tm["team1"]
    t2 = tm["team2"]
    match_id = tm["match_id"]
    winner_arg = " ".join(context.args).strip().lower()
    
    pts = tournament_points[group_id]
    for tn in [t1, t2]:
        if tn not in pts:
            pts[tn] = {"played": 0, "won": 0, "lost": 0, "tied": 0, "pts": 0, "nrr": 0.0}
    
    if winner_arg == "tie":
        pts[t1]["played"] += 1
        pts[t2]["played"] += 1
        pts[t1]["tied"] += 1
        pts[t2]["tied"] += 1
        pts[t1]["pts"] += 1
        pts[t2]["pts"] += 1
        result_str = "Tie"
    else:
        # Match team name
        winner = None
        for tn in [t1, t2]:
            if tn.lower() == winner_arg or winner_arg in tn.lower():
                winner = tn
                break
        
        if not winner:
            await update.message.reply_text(f"⚠️ Team not found! Valid teams: {t1}, {t2}")
            return
        
        loser = t2 if winner == t1 else t1
        pts[winner]["played"] += 1
        pts[loser]["played"] += 1
        pts[winner]["won"] += 1
        pts[loser]["lost"] += 1
        pts[winner]["pts"] += 2
        result_str = f"{winner} won"
    
    # Update fixture
    for fix in tournament_fixtures[group_id]:
        if fix["match_id"] == match_id:
            fix["result"] = result_str
            break
    
    del pending_tour_match[group_id]
    
    await update.message.reply_text(
        f"✅ <b>RESULT RECORDED!</b>\n"
        f"─────────────────\n"
        f"⚔️ <b>{t1}</b> vs <b>{t2}</b>\n"
        f"🏆 <b>Result:</b> {result_str}\n\n"
        f"Points table has been updated!",
        parse_mode=ParseMode.HTML
    )


async def tourlb_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Tournament leaderboard: /tourlb → attractive paginated image version"""
    chat = update.effective_chat
    user = update.effective_user
    group_id = chat.id

    if chat.type == "private":
        await update.message.reply_text("Use in a group!")
        return

    if group_id not in TOURNAMENT_APPROVED_GROUPS:
        return

    # Build category text
    def _tourlb_text(group_id: int, metric: str = "runs") -> str:
        all_runs = {}
        all_wickets = {}
        all_sixes = {}
        all_fours = {}

        for match_id, stats in tour_match_stats.get(group_id, {}).items():
            for pid, val in stats.get("player_runs", {}).items():
                all_runs.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val
            for pid, val in stats.get("player_wickets", {}).items():
                all_wickets.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val
            for pid, val in stats.get("player_sixes", {}).items():
                all_sixes.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val
            for pid, val in stats.get("player_fours", {}).items():
                all_fours.setdefault(pid, {"name": str(pid), "total": 0})["total"] += val

        medals = ["🥇", "🥈", "🥉", "4️⃣", "5️⃣", "6️⃣", "7️⃣", "8️⃣", "9️⃣", "🔟"]

        if metric == "runs":
            title = "🏃 TOP RUN SCORERS"
            data = sorted(all_runs.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  →  {d['total']} runs" for i, d in enumerate(data[:10])]
        elif metric == "wickets":
            title = "⚾ TOP WICKET TAKERS"
            data = sorted(all_wickets.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  →  {d['total']} wkts" for i, d in enumerate(data[:10])]
        elif metric == "sixes":
            title = "🚀 MOST SIXES"
            data = sorted(all_sixes.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  →  {d['total']} 🚀" for i, d in enumerate(data[:10])]
        elif metric == "fours":
            title = "4️⃣ MOST FOURS"
            data = sorted(all_fours.values(), key=lambda x: -x["total"])
            lines = [f"{medals[i]} <b>{d['name'][:18]}</b>  →  {d['total']} fours" for i, d in enumerate(data[:10])]
        else:
            title = "🏃 TOP RUN SCORERS"
            lines = []

        total_matches = len(tour_match_stats.get(group_id, {}))
        text = f"🏆 <b>TOURNAMENT LEADERBOARD</b>\n"
        text += f"─────────────────\n"
        text += f"📊 {total_matches} match(es) played\n"
        text += f"─────────────────\n"
        text += f"<b>{title}</b>\n\n"
        if lines:
            text += "\n".join(lines)
        else:
            text += "<i>No data yet → complete some matches!</i>"
        text += "\n─────────────────"
        return text

    metric = "runs"
    text = _tourlb_text(group_id, metric)
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("🏃 Runs",    callback_data=f"tourlb_{group_id}_runs"),
         InlineKeyboardButton("⚾ Wickets", callback_data=f"tourlb_{group_id}_wickets")],
        [InlineKeyboardButton("🚀 Sixes",   callback_data=f"tourlb_{group_id}_sixes"),
         InlineKeyboardButton("4️⃣ Fours",   callback_data=f"tourlb_{group_id}_fours")],
    ])

    # Try generate image
    try:
        img_bio = await asyncio.to_thread(generate_tour_leaderboard_image, group_id)
    except Exception:
        img_bio = None

    try:
        if img_bio:
            await update.message.reply_photo(photo=img_bio, caption=text, parse_mode=ParseMode.HTML, reply_markup=kb)
        else:
            photo = MEDIA_ASSETS.get("tournament_mode")
            await update.message.reply_photo(photo=photo, caption=text, parse_mode=ParseMode.HTML, reply_markup=kb)
    except:
        await update.message.reply_text(text, parse_mode=ParseMode.HTML, reply_markup=kb)


async def update_solo_board(context, chat_id, match):
    """Updates the Solo Joining List with Host Tag"""
    count = len(match.solo_players)
    
    # Time Calc
    remaining = int(match.solo_join_end_time - time.time())
    if remaining < 0: remaining = 0
    mins, secs = divmod(remaining, 60)
    
    # Generate Host Tag
    if match.host_id and match.host_name:
        host_tag = f"<a href='tg://user?id={match.host_id}'>{match.host_name}</a>"
    else:
        host_tag = "Unknown"
    
    msg = "⚔️ <b>SOLO BATTLE ROYALE</b> ⚔️\n"
    msg += "─────────────────\n"
    msg += f"🎙 <b>Host:</b> {host_tag}\n"
    msg += f"⏳ <b>Time Left:</b> <code>{mins:02d}:{secs:02d}</code>\n"
    msg += f"👥 <b>Players Joined:</b> {count}\n\n"
    
    msg += "<b>PLAYER LIST:</b>\n"
    if match.solo_players:
        for i, p in enumerate(match.solo_players, 1):
            ptag = f"<a href='tg://user?id={p.user_id}'>{p.first_name}</a>"
            msg += f"  {i}. {ptag}\n"
    else:
        msg += "  <i>Waiting for players...</i>\n"
        
    msg += "\n─────────────────\n"
    msg += "👇 <i>Click Join to Enter the Ground!</i>"
    
    # Buttons
    keyboard = [
        [InlineKeyboardButton("✅ Join Battle", callback_data="solo_join"),
         InlineKeyboardButton("🚪 Leave", callback_data="solo_leave")]
    ]
    
    # Show START button if enough players
    if count >= 2:
        keyboard.append([InlineKeyboardButton("🚀 START MATCH", callback_data="solo_start_game")])
        
    await refresh_game_message(context, chat_id, match, msg, InlineKeyboardMarkup(keyboard), media_key="joining")

async def start_team_mode(query, context: ContextTypes.DEFAULT_TYPE, chat, user):
    """Initialize team mode with Fancy Image"""
    # Create new match
    match = Match(chat.id, chat.title)
    active_matches[chat.id] = match
    
    # Set time (2 minutes)
    match.team_join_end_time = time.time() + get_gc_setting(match.group_id, "lobby_time", 120)
    
    # Buttons
    keyboard = [
        [InlineKeyboardButton("🧊 Join Team X", callback_data="join_team_x"),
         InlineKeyboardButton("🔥 Join Team Y", callback_data="join_team_y")],
        [InlineKeyboardButton("🚪 Leave Team", callback_data="leave_team")]
    ]
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    # Fancy Text
    text = get_team_join_message(match)
    
    # Send using Master Function (With Image)
    await refresh_game_message(context, chat.id, match, text, reply_markup, media_key="joining")
    
    # Start Timer
    match.join_phase_task = asyncio.create_task(
        team_join_countdown(context, chat.id, match)
    )

def get_team_join_message(match: Match) -> str:
    """Generate Professional Joining List"""
    remaining = max(0, int(match.team_join_end_time - time.time()))
    minutes = remaining // 60
    seconds = remaining % 60
    
    total_p = len(match.team_x.players) + len(match.team_y.players)
    
    # Mode label
    mode_label = ""
    if getattr(match, "magic_ball_mode", False) or getattr(match, "game_mode", "") == "MAGICBALL":
        mode_label = "  🔮 <i>Magic Ball Mode!</i>"
    
    msg = "🏟️ <b>CRICOVERSE ARENA</b>\n"
    msg += "─────────────────\n"
    msg += f"⏱️ <b>Time Remaining:</b> <code>{minutes:02d}:{seconds:02d}</code>\n"
    msg += f"👥 <b>Players Joined:</b> <code>{total_p}</code>{mode_label}\n"
    msg += "─────────────────\n\n"
    
    # Team X List
    msg += "❄️ <b>TEAM ALPHA (X)</b>"
    if match.team_x.captain_id:
        cap = match.team_x.get_player(match.team_x.captain_id)
        if cap:
            msg += f"  👑 <i>{cap.first_name}</i>"
    msg += "\n──────────────────────\n"
    if match.team_x.players:
        for i, p in enumerate(match.team_x.players, 1):
            crown = "👑" if p.user_id == match.team_x.captain_id else "🔹"
            msg += f" {crown} <b>{i}.</b> {p.first_name}\n"
    else:
        msg += "  ⏳ <i>Waiting for players...</i>\n"
    
    # Team Y List
    msg += "\n🔥 <b>TEAM BETA (Y)</b>"
    if match.team_y.captain_id:
        cap = match.team_y.get_player(match.team_y.captain_id)
        if cap:
            msg += f"  👑 <i>{cap.first_name}</i>"
    msg += "\n──────────────────────\n"
    if match.team_y.players:
        for i, p in enumerate(match.team_y.players, 1):
            crown = "👑" if p.user_id == match.team_y.captain_id else "🔸"
            msg += f" {crown} <b>{i}.</b> {p.first_name}\n"
    else:
        msg += "  ⏳ <i>Waiting for players...</i>\n"
    
    msg += "\n─────────────────\n"
    msg += "📢 <i>Tap the buttons below to lock in your squad!</i>"
    
    return msg


async def team_join_countdown(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """Countdown timer that updates the Board safely"""
    try:
        warning_sent = False
        while True:
            # ✅ FIX: Agar Phase Joining nahi hai, to Timer band kar do
            if match.phase != GamePhase.TEAM_JOINING:
                break

            remaining = match.team_join_end_time - time.time()
            
            # 30 Seconds Warning
            if remaining <= 30 and remaining > 20 and not warning_sent:
                await context.bot.send_message(
                    group_id, 
                    "⏰ <b>LAST CALL!</b> 30 seconds left to join!\n─────────────────\n👇 Tap below NOW → hurry up! 🏏", 
                    parse_mode=ParseMode.HTML
                )
                warning_sent = True
            if remaining <= 0:
                await end_team_join_phase(context, group_id, match)
                break
            
            # Wait 10 seconds
            await asyncio.sleep(10)
            
            # ✅ FIX: Update karne se pehle phir check karo
            if match.phase == GamePhase.TEAM_JOINING:
                await update_joining_board(context, group_id, match)
            
    except asyncio.CancelledError:
        pass
    except Exception as e:
        logger.error(f"Timer error: {e}")

async def end_team_join_phase(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """End joining phase and start Host Selection"""
    total_players = len(match.team_x.players) + len(match.team_y.players)
    
    # Min 4 Players Check
    if total_players < 4:
        await context.bot.send_message(
            chat_id=group_id,
            text="❌ <b>Match Cancelled!</b>\nYou need at least 4 players (2 per team) to start.",
            parse_mode=ParseMode.HTML
        )
        try: await context.bot.unpin_chat_message(group_id, match.main_message_id)
        except: pass
        del active_matches[group_id]
        return
    
    match.phase = GamePhase.HOST_SELECTION
    
    keyboard = [[InlineKeyboardButton("🙋‍♂️ I Want to be Host", callback_data="become_host")]]
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    host_text = f"🚨 <b>REGISTRATION CLOSED</b> 🚨\n"
    host_text += "─────────────────\n"
    host_text += f"👥 <b>Locked In:</b> <code>{total_players} Players</code>\n\n"
    host_text += "🎙️ <b>Lobby Host Selection:</b>\n"
    host_text += "<i>• The Host controls match settings, overs, and team edits.</i>\n"
    host_text += "<i>• Step up if you are ready to moderate this match!</i>\n\n"
    host_text += "─────────────────\n"
    host_text += "👇 <i>Tap below to claim the Host seat:</i>"

    
    # Send with Host Image and Pin
    await refresh_game_message(context, group_id, match, host_text, reply_markup, media_key="host")

# Team join/leave callback handlers
async def team_join_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle team join/leave with tagging alerts & Auto-Update"""
    query = update.callback_query
    
    # Quick answer to stop loading animation
    await query.answer()
    
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches:
        return
    
    match = active_matches[chat.id]
    
    if match.phase != GamePhase.TEAM_JOINING:
        await context.bot.send_message(chat.id, "⚠️ Joining phase has ended!")
        return
    
    # Initialize User Data
    if user.id not in user_data:
        user_data[user.id] = {
            "user_id": user.id,
            "username": user.username or "",
            "first_name": user.first_name,
            "started_at": datetime.now().isoformat(),
            "total_matches": 0
        }
        init_player_stats(user.id)
        save_data()

    user_tag = f"<a href='tg://user?id={user.id}'>{user.first_name}</a>"
    alert_msg = ""
    updated = False

    # JOIN LOGIC
    if query.data == "join_team_x":
        if not match.team_x.get_player(user.id):
            if match.team_y.get_player(user.id):
                match.team_y.remove_player(user.id)
            
            player = Player(user.id, user.username or "", user.first_name)
            match.team_x.add_player(player)
            alert_msg = f"✅ {user_tag} joined <b>Team X</b>!"
            updated = True
    
    elif query.data == "join_team_y":
        if not match.team_y.get_player(user.id):
            if match.team_x.get_player(user.id):
                match.team_x.remove_player(user.id)
            
            player = Player(user.id, user.username or "", user.first_name)
            match.team_y.add_player(player)
            alert_msg = f"✅ {user_tag} joined <b>Team Y</b>!"
            updated = True
    
    elif query.data == "leave_team":
        if match.team_x.remove_player(user.id) or match.team_y.remove_player(user.id):
            alert_msg = f"👋 {user_tag} left the team."
            updated = True

    # 1. Send Alert in Group (Naya message)
    if alert_msg:
        await context.bot.send_message(chat.id, alert_msg, parse_mode=ParseMode.HTML)

    # 2. Update the Board (Agar change hua hai)
    if updated:
        await update_joining_board(context, chat.id, match)

# Extend command (Admins only) → auto-detects Team/Solo mode
async def extend_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Extend joining time - ADMIN ONLY, MAX 180 seconds. Works for Team and Solo modes."""
    chat_id = update.effective_chat.id
    user_id = update.effective_user.id

    match = active_matches.get(chat_id)
    if not match:
        await update.message.reply_text("❌ No active match!")
        return

    # Check if user is admin
    try:
        member = await context.bot.get_chat_member(chat_id, user_id)
        is_admin = member.status in ['creator', 'administrator']
    except:
        is_admin = False

    if not is_admin:
        await update.message.reply_text("❌ Only group admins can extend time!")
        return

    if not context.args:
        await update.message.reply_text(
            "❌ Usage: /extend <seconds>\n"
            "Example: /extend 120\n"
            "⚠️ Maximum: 180 seconds"
        )
        return

    try:
        seconds = int(context.args[0])
    except ValueError:
        await update.message.reply_text("❌ Please provide a valid number!")
        return

    if seconds > 180:
        await update.message.reply_text("❌ Maximum extension is 180 seconds (3 minutes)!")
        return

    if seconds <= 0:
        await update.message.reply_text("❌ Extension must be greater than 0!")
        return

    # ── Solo joining phase ──
    if getattr(match, 'game_mode', None) in ["SOLO", "MAGICBALL"] or match.phase == GamePhase.SOLO_JOINING:
        match.solo_join_end_time += seconds
        await update.message.reply_text(f"✅ Solo joining time extended by {seconds} seconds!")
        return

    # ── Team joining phase ──
    match.last_activity = time.time() + seconds
    new_deadline = datetime.fromtimestamp(match.last_activity)

    await update.message.reply_text(
        f"⏰ <b>Match Extended!</b>\n\n"
        f"⏱️ Added <b>{seconds} seconds</b> to the match.\n"
        f"🕐 New deadline: <b>{new_deadline.strftime('%I:%M:%S %p')}</b>",
        parse_mode=ParseMode.HTML
    )
    
    # Refresh Game Board
    text = get_team_join_message(match)
    keyboard = [
        [InlineKeyboardButton("🧊 Join Team X", callback_data="join_team_x"),
         InlineKeyboardButton("🔥 Join Team Y", callback_data="join_team_y")],
        [InlineKeyboardButton("🚪 Leave Team", callback_data="leave_team")]
    ]
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    # Use master function to keep it at bottom and pinned
    await refresh_game_message(context, chat_id, match, text, reply_markup=reply_markup, media_key="joining")

# Host selection callback
async def host_selection_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Host Selection safely with 4-20 Overs"""
    query = update.callback_query
    await query.answer()
    
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches:
        return
        
    match = active_matches[chat.id]
    
    # Check if someone is already host
    if match.host_id is not None:
        await query.answer("Host already selected!", show_alert=True)
        return

    # Set Host
    match.host_id = user.id
    match.host_name = user.first_name
    match.last_activity = time.time()  # Reset timer
    
    match.phase = GamePhase.OVER_SELECTION
    
    # --- LOGIC FOR 1 TO 20 OVERS ---
    keyboard = []
    row = []
    # Loop from 1 to 20 (inclusive)
    for i in range(1, 21):
        # Add button to current row
        row.append(InlineKeyboardButton(f"{i}", callback_data=f"overs_{i}"))
        
        # If row has 5 buttons, add it to keyboard and start new row
        if len(row) == 5:
            keyboard.append(row)
            row = []
            
    # Add any remaining buttons
    if row:
        keyboard.append(row)
    
    reply_markup = InlineKeyboardMarkup(keyboard)
    
    # --- FIX: Generate User Tag ---
    user_tag = get_user_tag(user)
    
    msg = f"🎙 <b>HOST: {user_tag}</b>\n"
    msg += "─────────────────\n"
    msg += "Host, please select the number of overs for this match.\n"
    msg += "Range: <b>1 to 20 Overs</b>"
    
    # Use Safe Refresh Function
    await refresh_game_message(context, chat.id, match, msg, reply_markup, media_key="host")

# Captain selection callback
async def captain_selection_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Captain Selection and move to Toss safely"""
    query = update.callback_query
    
    chat = query.message.chat
    user = query.from_user
    
    if chat.id not in active_matches:
        await query.answer("No active match.", show_alert=True)
        return
    
    match = active_matches[chat.id]
    
    # Check Phase
    if match.phase != GamePhase.CAPTAIN_SELECTION:
        await query.answer("Captain selection phase has ended.", show_alert=True)
        return
    
    # Logic for Team X
    if query.data == "captain_team_x":
        if not match.team_x.get_player(user.id):
            await query.answer("You must be in Team X!", show_alert=True)
            return
        if match.team_x.captain_id:
            await query.answer("Team X already has a captain.", show_alert=True)
            return
        match.team_x.captain_id = user.id
        await query.answer("You are Captain of Team X!")
    
    # Logic for Team Y
    elif query.data == "captain_team_y":
        if not match.team_y.get_player(user.id):
            await query.answer("You must be in Team Y!", show_alert=True)
            return
        if match.team_y.captain_id:
            await query.answer("Team Y already has a captain.", show_alert=True)
            return
        match.team_y.captain_id = user.id
        await query.answer("You are Captain of Team Y!")
    
    # Check if BOTH are selected
    if match.team_x.captain_id and match.team_y.captain_id:
        # ✅ FLOW FIX: Captains ke baad Toss aayega
        match.phase = GamePhase.TOSS
        await start_toss(query, context, match)
        
    else:
        # Update Message (Show who is selected)
        captain_x = match.team_x.get_player(match.team_x.captain_id)
        captain_y = match.team_y.get_player(match.team_y.captain_id)
        
        cap_x_name = captain_x.first_name if captain_x else "Not Selected"
        cap_y_name = captain_y.first_name if captain_y else "Not Selected"
        
        keyboard = [
            [InlineKeyboardButton("Become Captain - Team X", callback_data="captain_team_x")],
            [InlineKeyboardButton("Become Captain - Team Y", callback_data="captain_team_y")]
        ]
        reply_markup = InlineKeyboardMarkup(keyboard)
        
        msg = "🧢 <b>CAPTAIN SELECTION</b>\n"
        msg += "─────────────────\n"
        msg += f"🧊 <b>Team X:</b> {cap_x_name}\n"
        msg += f"🔥 <b>Team Y:</b> {cap_y_name}\n\n"
        msg += "<i>Waiting for both captains...</i>"
        
        # ✅ FIX: Use refresh_game_message instead of risky edits
        await refresh_game_message(context, chat.id, match, msg, reply_markup, media_key="squads")

async def start_team_edit_phase(query, context: ContextTypes.DEFAULT_TYPE, match: Match):
    """Start team edit phase with Safety Checks"""
    match.phase = GamePhase.TEAM_EDIT
    
