async def ai_play_ball(context: ContextTypes.DEFAULT_TYPE, user_id: int):
    """AI plays a ball automatically"""
    if user_id not in ai_matches:
        return
    
    match = ai_matches[user_id]
    difficulty = match["difficulty"]
    
    # AI bowling selection - IMPROVED INTELLIGENCE
    user_score = match["user_score"]
    user_balls = match["user_balls"]
    target = match.get("target", 0)
    
    if difficulty == "easy":
        # Easy: Random but slightly favors middle numbers
        weights = [1, 1.2, 1.5, 1.5, 1.5, 1.2, 1]
        ai_choice = random.choices([0, 1, 2, 3, 4, 5, 6], weights=weights)[0]
    elif difficulty == "medium":
        # Medium: Strategic bowling based on match situation
        if match["innings"] == 2:  # Defending
            runs_needed = target - user_score
            balls_left = (match["overs"] * 6) - user_balls
            if runs_needed < balls_left:  # User ahead - be aggressive
                weights = [1.5, 1.5, 2, 2, 2, 1.8, 1.5]  # Favor middle
            else:  # Tight match - vary
                weights = [1.2, 1.5, 1.8, 2, 1.8, 1.5, 1.2]
        else:  # First innings
            weights = [1, 1.5, 2, 2.5, 2, 1.5, 1]  # Slightly favor 3
        ai_choice = random.choices([0, 1, 2, 3, 4, 5, 6], weights=weights)[0]
    else:  # HARD - GOD LEVEL BOWLING 😈
        # Track user's batting history to predict their shots
        user_wickets = match["user_wickets"]
        
        if "user_bat_history" not in match:
            match["user_bat_history"] = []
        
        # Find user's most common batting numbers - bowl THOSE to get them out
        predicted_shot = None
        if len(match["user_bat_history"]) >= 3:
            recent = match["user_bat_history"][-6:]
            freq = {}
            for n in recent:
                freq[n] = freq.get(n, 0) + 1
            predicted_shot = max(freq, key=freq.get)  # Bowl user's favorite number!
        
        if match.get("ai_batting_first") and match["innings"] == 1:
            # Defending in first innings (user batting, AI bowling)
            # Bowl to contain user's score
            user_run_rate = user_score / max(user_balls, 1)
            if user_run_rate > 4:  # User scoring fast - bowl variations
                weights = [2.5, 2.5, 2.5, 2.5, 2.5, 2.5, 2.5]  # Pure random to confuse
            elif user_wickets == 0 and user_balls > 3:  # User surviving - attack
                weights = [1.0, 1.5, 2.5, 3.5, 2.5, 1.5, 1.0]
            else:
                weights = [1.5, 2.0, 2.5, 3.0, 2.5, 2.0, 1.5]
        elif match["innings"] == 2:  # Defending a target (user chasing)
            runs_needed = target - user_score
            balls_left = (match["overs"] * 6) - user_balls
            
            if runs_needed <= 0:  # User won, shouldn't happen
                weights = [1, 1, 1, 1, 1, 1, 1]
            elif runs_needed <= 3 and balls_left > 0:  # VERY TIGHT - bowl user's fav
                weights = [1.5, 2.0, 3.0, 3.5, 3.0, 2.0, 1.5]
            elif balls_left <= 3:  # Death bowling - pressure
                weights = [1.5, 2.0, 3.0, 4.0, 3.0, 2.0, 1.5]
            elif runs_needed > balls_left * 4:  # User needs to slog
                # They'll play 5s and 6s - bowl those!
                weights = [1.0, 1.5, 2.0, 2.5, 4.0, 5.0, 4.0]
            elif runs_needed < balls_left * 1.5:  # User coasting
                # They'll play safe - bowl 1,2,3
                weights = [2.0, 4.0, 4.5, 4.0, 2.0, 1.5, 1.0]
            else:
                weights = [1.5, 2.5, 3.0, 4.0, 3.0, 2.5, 1.5]
        else:  # First innings user batting (AI bowling normally)
            if user_wickets == 0 and user_balls > 6:
                # User is set - try variations
                weights = [2.0, 2.5, 3.0, 3.5, 3.0, 2.5, 2.0]
            elif user_score > user_balls * 3:  # High run rate
                # They're attacking - bowl 4,5,6 area to catch them
                weights = [1.0, 1.5, 2.0, 2.5, 4.0, 4.5, 4.0]
            else:
                weights = [1.5, 2.0, 2.5, 3.5, 2.5, 2.0, 1.5]
        
        # Generate bowling choice
        ai_choice = random.choices([0, 1, 2, 3, 4, 5, 6], weights=weights)[0]
        
        # GOD MODE: Override to bowl user's predicted shot (50% chance if we have data)
        if predicted_shot is not None and random.random() < 0.50:
            ai_choice = predicted_shot  # Bowl exactly what user likes to play!
        
        # 5% true random to avoid being completely predictable
        if random.random() < 0.05:
            ai_choice = random.randint(0, 6)
    
    match["ai_number"] = ai_choice
    match["phase"] = "waiting_user"
    
    # Notify user to play
    msg = f"🤖 <b>AI HAS BOWLED!</b>\n\n"
    msg += f"📊 <b>Score:</b> {match['user_score']}/{match['user_wickets']}\n"
    msg += f"⚾ <b>Balls:</b> {match['user_balls']}/{match['overs']*6}\n\n"
    msg += "🏏 <b>Send your shot (0-6)!</b>"
    
    try:
        # Send bowling animation
        await context.bot.send_animation(
            user_id, 
            animation="https://t.me/kyanaamrkhe/7",
            caption=msg, 
            parse_mode=ParseMode.HTML
        )
    except:
        await context.bot.send_message(user_id, msg, parse_mode=ParseMode.HTML)


async def aistats_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show current AI match stats"""
    user = update.effective_user
    
    if user.id not in ai_matches:
        await update.message.reply_text("⚠️ No active AI match! Use /aistart to begin.")
        return
    
    match = ai_matches[user.id]
    
    msg = "🤖 <b>LIVE AI MATCH</b>\n"
    msg += "─────────────────\n\n"
    
    if match["innings"] == 1:
        msg += f"🏏 <b>YOU:</b> {match['user_score']}/{match['user_wickets']} ({match['user_balls']//6}.{match['user_balls']%6})\n"
        msg += f"🎯 <b>Target:</b> Beat AI's score!\n"
    else:
        msg += f"🎯 <b>Target:</b> {match['target']}\n"
        msg += f"🏏 <b>YOU:</b> {match['user_score']}/{match['user_wickets']} ({match['user_balls']//6}.{match['user_balls']%6})\n"
        msg += f"🤖 <b>AI:</b> {match['ai_score']}/{match['ai_wickets']}\n"
    
    await update.message.reply_text(msg, parse_mode=ParseMode.HTML)


async def aiquit_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Quit current AI match"""
    user = update.effective_user
    
    if user.id not in ai_matches:
        await update.message.reply_text("⚠️ No active AI match!")
        return
    
    del ai_matches[user.id]
    await update.message.reply_text("✅ AI match ended.")


async def ai_bat_innings(context: ContextTypes.DEFAULT_TYPE, user_id: int):
    """Start AI batting innings - user will bowl ball by ball"""
    if user_id not in ai_matches:
        return
    
    match = ai_matches[user_id]
    target = match["target"]
    
    # Add penalty runs if user spammed while batting
    penalty_runs = match.get("ai_penalty_runs", 0)
    if penalty_runs > 0:
        match["ai_score"] += penalty_runs
    
    # Send innings start message
    msg = "🤖 <b>AI IS BATTING NOW!</b>\n"
    msg += "─────────────────\n\n"
    msg += f"🎯 <b>Target:</b> {target}\n"
    if penalty_runs > 0:
        msg += f"⚠️ <b>AI starts with {penalty_runs} penalty run(s)</b>\n"
    msg += f"📊 <b>AI Score:</b> {match['ai_score']}/{match['ai_wickets']}\n\n"
    msg += "⚾ <b>You're bowling!</b>\n"
    msg += "Send a number (0-6) to bowl!"
    
    try:
        await context.bot.send_photo(
            user_id,
            photo=MEDIA_ASSETS.get("toss"),
            caption=msg,
            parse_mode=ParseMode.HTML
        )
    except:
        await context.bot.send_message(user_id, msg, parse_mode=ParseMode.HTML)
    
    # Set match phase to waiting for user to bowl
    match["phase"] = "waiting_user"


async def ai_bat_ball(context: ContextTypes.DEFAULT_TYPE, user_id: int, user_bowl: int):
    """AI plays a single ball when user is bowling - FIXED FOR FIRST INNINGS"""
    if user_id not in ai_matches:
        return
    
    match = ai_matches[user_id]
    difficulty = match["difficulty"]
    target = match.get("target", 0)
    is_first_innings = match.get("ai_batting_first", False) and match["innings"] == 1
    
    # AI batting logic - IMPROVED DIFFICULTY
    if difficulty == "easy":
        # Easy: Random but slightly smart
        ai_bat = random.randint(0, 6)
    elif difficulty == "medium":
        # Medium: Strategic batting
        runs_needed = target - match["ai_score"]
        balls_left = (match["overs"] * 6) - match["ai_balls"]
        
        if runs_needed <= 0:  # Already won
            ai_bat = random.randint(1, 6)
        else:
            if balls_left <= 3:  # Last 3 balls - go big
                weights = [0.2, 0.3, 0.5, 0.8, 2, 2.5, 3]
            elif runs_needed > balls_left * 5:  # Need to accelerate
                weights = [0.3, 0.5, 0.8, 1.2, 2.5, 2.8, 3.5]
            elif runs_needed < balls_left * 2:  # Easy chase
                weights = [1, 2, 2.5, 2, 1.5, 0.8, 0.5]
            else:  # Normal chase
                weights = [0.8, 1.5, 2, 2, 1.8, 1.2, 1]
            ai_bat = random.choices([0, 1, 2, 3, 4, 5, 6], weights=weights)[0]
    else:  # hard - GOD LEVEL ULTIMATE AI 😈
        runs_needed = target - match["ai_score"]
        balls_left = (match["overs"] * 6) - match["ai_balls"]
        wickets_left = 1 - match["ai_wickets"]  # Only 1 wicket
        
        # Track user bowling patterns for god-level prediction
        if "user_bowl_history" not in match:
            match["user_bowl_history"] = []
        
        # Predict and avoid user's most common bowling number
        predicted_avoid = None
        if len(match["user_bowl_history"]) >= 3:
            recent = match["user_bowl_history"][-6:]
            freq = {}
            for n in recent:
                freq[n] = freq.get(n, 0) + 1
            predicted_avoid = max(freq, key=freq.get)
        
        if runs_needed <= 0:  # Already winning
            ai_bat = random.randint(1, 4)
        else:
            if balls_left <= 1:  # LAST BALL - maximum aggression
                weights = [0.0, 0.05, 0.1, 0.2, 2.5, 3.5, 6.0]
            elif balls_left <= 3:  # Last 3 balls
                if runs_needed >= balls_left * 4:
                    weights = [0.0, 0.05, 0.1, 0.3, 2.5, 4.0, 6.0]
                else:
                    weights = [0.1, 0.2, 0.5, 1.0, 3.0, 4.0, 5.0]
            elif balls_left <= 6:  # Last over
                required_rr = runs_needed / balls_left
                if required_rr >= 5:
                    weights = [0.0, 0.1, 0.2, 0.5, 2.5, 4.0, 6.0]
                elif required_rr >= 3:
                    weights = [0.1, 0.2, 0.8, 1.5, 3.0, 4.0, 5.0]
                elif required_rr >= 2:
                    weights = [0.3, 0.8, 2.0, 2.8, 2.8, 3.0, 3.5]
                else:
                    weights = [0.5, 2.0, 3.0, 3.0, 2.0, 1.5, 1.0]
            else:
                # Strategic play based on required run rate
                required_rr = runs_needed / max(balls_left, 1)
                if required_rr >= 5:
                    weights = [0.05, 0.1, 0.3, 0.8, 2.5, 4.0, 6.0]
                elif required_rr >= 3.5:
                    weights = [0.1, 0.2, 0.8, 1.5, 3.0, 4.5, 5.0]
                elif required_rr >= 2.5:
                    weights = [0.2, 0.5, 1.5, 2.5, 3.5, 4.0, 4.0]
                elif required_rr >= 1.5:
                    weights = [0.5, 1.2, 2.5, 3.5, 3.0, 2.5, 2.0]
                elif required_rr >= 1.0:
                    weights = [1.0, 2.5, 3.5, 3.5, 2.5, 1.5, 0.8]
                else:  # Cruise control
                    weights = [2.0, 3.5, 4.0, 3.0, 1.5, 0.8, 0.3]
            
            # Generate shot
            ai_bat = random.choices([0, 1, 2, 3, 4, 5, 6], weights=weights)[0]
            
            # God mode: avoid user's predicted delivery number
            if predicted_avoid is not None and ai_bat == predicted_avoid:
                avoid_weights = weights.copy()
                avoid_weights[predicted_avoid] = 0.01  # Almost never pick predicted
                ai_bat = random.choices([0, 1, 2, 3, 4, 5, 6], weights=avoid_weights)[0]
            
            # 5% surprise shot (keeps it slightly human-like)
            if random.random() < 0.05:
                ai_bat = random.randint(0, 6)
    
    # Process result
    if ai_bat == user_bowl:
        # WICKET!
        match["ai_wickets"] = 1
        match["ai_balls"] += 1
        
        result_msg = f"🎯 <b>WICKET!</b>\n\n"
        result_msg += f"You bowled: {user_bowl} | AI: {ai_bat}\n\n"
        result_msg += f"📊 AI Final: {match['ai_score']}/1 ({match['ai_balls']//6}.{match['ai_balls']%6})\n"
        
        if is_first_innings:
            # First innings wicket - AI innings ends, now user bats
            result_msg += f"\n─────────────────\n"
            result_msg += f"<b>AI INNINGS ENDED!</b>\n"
            result_msg += f"🎯 <b>Target for you: {match['ai_score'] + 1}</b>\n\n"
            result_msg += "🏏 Now you're batting!\n"
            result_msg += "Send a number (0-6) to start batting!"
            
            try:
                await context.bot.send_animation(
                    user_id,
                    animation=random.choice(GIFS[MatchEvent.WICKET]),
                    caption=result_msg,
                    parse_mode=ParseMode.HTML
                )
            except:
                await context.bot.send_message(user_id, result_msg, parse_mode=ParseMode.HTML)
            
            # Switch to second innings
            match["target"] = match["ai_score"] + 1
            match["innings"] = 2
            match["ai_batting_first"] = False
            match["phase"] = "waiting_user"
            
            await asyncio.sleep(2)
            await ai_play_ball(context, user_id)
            return
        else:
            # Second innings wicket - AI is out, user wins
            result_msg += f"🎯 Needed: {target - match['ai_score']} more runs\n"
            await ai_end_match(context, user_id, "user_won")
            return
    else:
        # Runs!
        match["ai_score"] += ai_bat
        match["ai_balls"] += 1
        match["ai_stats"]["runs"] += ai_bat
        
        result_msg = f"{'🔥' if ai_bat >= 4 else '✅'} <b>AI scored {ai_bat}!</b>\n\n"
        result_msg += f"You bowled: {user_bowl} | AI: {ai_bat}\n\n"
        result_msg += f"📊 AI: {match['ai_score']}/{match['ai_wickets']} ({match['ai_balls']//6}.{match['ai_balls']%6})\n"
        result_msg += f"🎯 Need: {target - match['ai_score']} runs\n"
        
        # Check if first innings or second innings
        if is_first_innings:
            # First innings - check if overs complete
            if match["ai_balls"] >= match["overs"] * 6:
                # First innings complete, user bats now
                result_msg += f"\n─────────────────\n"
                result_msg += f"<b>AI INNINGS COMPLETE!</b>\n"
                result_msg += f"🎯 <b>Target: {match['ai_score'] + 1}</b>\n\n"
                result_msg += "🏏 Now you're batting!\n"
                result_msg += "Send a number (0-6) to start!"
                
                try:
                    await context.bot.send_animation(
                        user_id,
                        animation=random.choice(GIFS.get(MatchEvent.INNINGS_BREAK, GIFS[MatchEvent.DOT_BALL])),
                        caption=result_msg,
                        parse_mode=ParseMode.HTML
                    )
                except:
                    await context.bot.send_message(user_id, result_msg, parse_mode=ParseMode.HTML)
                
                # Switch to second innings
                match["target"] = match["ai_score"] + 1
                match["innings"] = 2
                match["ai_batting_first"] = False
                match["phase"] = "waiting_user"
                
                await asyncio.sleep(2)
                await ai_play_ball(context, user_id)
                return
        else:
            # Second innings - check if target chased
            if match["ai_score"] >= target:
                await ai_end_match(context, user_id, "ai_won")
                return
            
            # Check if overs complete
            if match["ai_balls"] >= match["overs"] * 6:
                await ai_end_match(context, user_id, "user_won")
                return
        
        try:
            # Send appropriate GIF
            if ai_bat == 0:
                gif = random.choice(GIFS[MatchEvent.DOT_BALL])
            elif ai_bat == 1:
                gif = random.choice(GIFS[MatchEvent.RUNS_1])
            elif ai_bat == 2:
                gif = random.choice(GIFS[MatchEvent.RUNS_2])
            elif ai_bat == 3:
                gif = random.choice(GIFS[MatchEvent.RUNS_3])
            elif ai_bat == 4:
                gif = random.choice(GIFS[MatchEvent.RUNS_4])
            elif ai_bat == 5:
                gif = random.choice(GIFS[MatchEvent.RUNS_5])
            else:  # 6
                gif = random.choice(GIFS[MatchEvent.RUNS_6])
            
            await context.bot.send_animation(
                user_id,
                animation=gif,
                caption=result_msg,
                parse_mode=ParseMode.HTML
            )
        except:
            await context.bot.send_message(user_id, result_msg, parse_mode=ParseMode.HTML)
        
        match["phase"] = "waiting_user"
        match["ai_number"] = None
        
        if not is_first_innings:
            await asyncio.sleep(1)
            await context.bot.send_message(user_id, "⚾ Send your next delivery (0-6)!", parse_mode=ParseMode.HTML)


async def ai_end_match(context: ContextTypes.DEFAULT_TYPE, user_id: int, result: str):
    """End AI match and show results"""
    if user_id not in ai_matches:
        return
    
    match = ai_matches[user_id]
    
    msg = "🏆 <b>MATCH ENDED!</b>\n"
    msg += "─────────────────\n\n"
    
    if result == "user_won":
        msg += "🎉 <b>YOU WON!</b> 🎉\n\n"
        margin = match["user_score"] - match["ai_score"]
        if match["innings"] == 1:
            msg += f"Victory by {match['user_score'] - match['ai_score']} runs!\n"
        else:
            msg += f"Victory by {10 - match['ai_wickets']} wickets!\n"
        victory_gif = random.choice(GIFS[MatchEvent.VICTORY]) if MatchEvent.VICTORY in GIFS else None
    else:
        msg += "💔 <b>AI WON!</b>\n\n"
        if match["innings"] == 1:
            msg += f"AI won by {10 - match['ai_wickets']} wickets!\n"
        else:
            msg += f"AI won by {match['ai_score'] - match['user_score']} runs!\n"
        victory_gif = None
    
    msg += f"\n📊 <b>YOUR SCORE:</b> {match['user_score']}/{match['user_wickets']} ({match['user_balls']//6}.{match['user_balls']%6})\n"
    msg += f"🤖 <b>AI SCORE:</b> {match['ai_score']}/{match['ai_wickets']} ({match['ai_balls']//6}.{match['ai_balls']%6})\n\n"
    
    # Add batting stats
    if match["user_stats"]["balls"] > 0:
        sr = round((match["user_stats"]["runs"] / match["user_stats"]["balls"]) * 100, 1)
        msg += f"\n🏏 <b>Your Batting:</b>\n"
        msg += f"   Strike Rate: {sr}\n"
        if match["user_stats"]["fours"] > 0 or match["user_stats"]["sixes"] > 0:
            msg += f"   Boundaries: {match['user_stats']['fours']}×4, {match['user_stats']['sixes']}×6\n"
    
    msg += "\n─────────────────\n"
    msg += "Use /aistart to play again!"
    
    try:
        # Send victory/defeat GIF
        if result == "user_won" and victory_gif:
            await context.bot.send_animation(
                user_id,
                animation=victory_gif,
                caption=msg,
                parse_mode=ParseMode.HTML
            )
        else:
            # Send photo for defeat or fallback
            await context.bot.send_photo(
                user_id,
                photo=MEDIA_ASSETS.get("scorecard"),
                caption=msg,
                parse_mode=ParseMode.HTML
            )
    except:
        await context.bot.send_message(user_id, msg, parse_mode=ParseMode.HTML)
    
    # Update stats
    if user_id in player_stats:
        # Safely update stats with get() to avoid KeyError
        player_stats[user_id]["total_runs"] = player_stats[user_id].get("total_runs", 0) + match["user_stats"]["runs"]
        player_stats[user_id]["total_balls_faced"] = player_stats[user_id].get("total_balls_faced", 0) + match["user_stats"]["balls"]
        player_stats[user_id]["total_sixes"] = player_stats[user_id].get("total_sixes", 0) + match["user_stats"]["sixes"]
        player_stats[user_id]["total_fours"] = player_stats[user_id].get("total_fours", 0) + match["user_stats"]["fours"]
        player_stats[user_id]["matches_played"] = player_stats[user_id].get("matches_played", 0) + 1
        if result == "user_won":
            player_stats[user_id]["matches_won"] = player_stats[user_id].get("matches_won", 0) + 1
        save_data()
    
    # Save AI stats to database
    try:
        difficulty = match.get("difficulty", "easy")
        won = 1 if result == "user_won" else 0
        user_runs = match["user_stats"]["runs"]
        user_sixes = match["user_stats"]["sixes"]
        user_fours = match["user_stats"]["fours"]
        
        conn = sqlite3.connect(DB_PATH)
        c = conn.cursor()
        
        # Create table if not exists (migration safety)
        c.execute('''CREATE TABLE IF NOT EXISTS ai_stats (
            user_id INTEGER PRIMARY KEY,
            total_matches INTEGER DEFAULT 0,
            wins INTEGER DEFAULT 0,
            losses INTEGER DEFAULT 0,
            easy_matches INTEGER DEFAULT 0,
            medium_matches INTEGER DEFAULT 0,
            hard_matches INTEGER DEFAULT 0,
            easy_wins INTEGER DEFAULT 0,
            medium_wins INTEGER DEFAULT 0,
            hard_wins INTEGER DEFAULT 0,
            highest_score INTEGER DEFAULT 0,
            total_runs INTEGER DEFAULT 0,
            total_sixes INTEGER DEFAULT 0,
            total_fours INTEGER DEFAULT 0,
            last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )''')
        
        c.execute("SELECT user_id FROM ai_stats WHERE user_id = ?", (user_id,))
        exists = c.fetchone()
        
        if not exists:
            c.execute("""INSERT INTO ai_stats 
                (user_id, total_matches, wins, losses,
                 easy_matches, medium_matches, hard_matches,
                 easy_wins, medium_wins, hard_wins,
                 highest_score, total_runs, total_sixes, total_fours)
                VALUES (?, 1, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                (user_id, won, 1 - won,
                 1 if difficulty == "easy" else 0,
                 1 if difficulty == "medium" else 0,
                 1 if difficulty == "hard" else 0,
                 won if difficulty == "easy" else 0,
                 won if difficulty == "medium" else 0,
                 won if difficulty == "hard" else 0,
                 user_runs, user_runs, user_sixes, user_fours))
        else:
            c.execute("""UPDATE ai_stats SET
                total_matches = total_matches + 1,
                wins = wins + ?,
                losses = losses + ?,
                easy_matches = easy_matches + ?,
                medium_matches = medium_matches + ?,
                hard_matches = hard_matches + ?,
                easy_wins = easy_wins + ?,
                medium_wins = medium_wins + ?,
                hard_wins = hard_wins + ?,
                highest_score = MAX(highest_score, ?),
                total_runs = total_runs + ?,
                total_sixes = total_sixes + ?,
                total_fours = total_fours + ?,
                last_updated = CURRENT_TIMESTAMP
                WHERE user_id = ?""",
                (won, 1 - won,
                 1 if difficulty == "easy" else 0,
                 1 if difficulty == "medium" else 0,
                 1 if difficulty == "hard" else 0,
                 won if difficulty == "easy" else 0,
                 won if difficulty == "medium" else 0,
                 won if difficulty == "hard" else 0,
                 user_runs, user_runs, user_sixes, user_fours, user_id))
        
        conn.commit()
        conn.close()
    except Exception as e:
        logger.error(f"AI stats save error: {e}")
    
    # Remove match
    del ai_matches[user_id]




async def process_magic_ball(user_num: int, opponent_num: int, match_context: dict) -> dict:
    """
    Process magic ball effects
    Returns: {
        'runs': int,
        'is_wicket': bool,
        'message': str,
        'magic_type': str or None,
        'reveal_delay': float (seconds to wait before revealing)
    }
    """
    # Check if magic ball triggers (15% chance)
    if random.random() > MAGIC_BALL_PROBABILITY:
        # Normal ball
        if user_num == opponent_num:
            return {
                'runs': 0,
                'is_wicket': True,
                'message': None,
                'magic_type': None,
                'reveal_delay': 0
            }
        else:
            return {
                'runs': user_num,
                'is_wicket': False,
                'message': None,
                'magic_type': None,
                'reveal_delay': 0
            }
    
    # Magic ball triggered! Select type
    types = list(MAGIC_BALL_WEIGHTS.keys())
    weights = list(MAGIC_BALL_WEIGHTS.values())
    magic_type = random.choices(types, weights=weights)[0]
    
    emoji = MAGIC_BALL_EMOJIS[magic_type]
    name = MAGIC_BALL_NAMES[magic_type]
    
    # Process based on type
    if magic_type == MagicBallType.FREEZE:
        # 🧊 Freeze Ball - Guaranteed dot
        return {
            'runs': 0,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n❄️ You are frozen! No runs possible!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.FIRE:
        # 🔥 Fire Ball - Guaranteed six
        return {
            'runs': 6,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n💥 BOOM! Guaranteed SIX!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.GHOST:
        # 👻 Ghost Ball - Random hidden result with reveal
        ghost_result = random.choice([0, 1, 4, 6, 'wicket'])
        
        if ghost_result == 'wicket':
            is_wicket = True
            runs = 0
            reveal_msg = "👻 GHOST REVEALED: WICKET! 💀"
        else:
            is_wicket = False
            runs = ghost_result
            reveal_msg = f"👻 GHOST REVEALED: {runs} RUNS! 🎃"
        
        return {
            'runs': runs,
            'is_wicket': is_wicket,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n🌫️ Result hidden...\n👁️ Revealing soon...\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 3,  # 3 seconds delay
            'reveal_message': reveal_msg
        }
    
    elif magic_type == MagicBallType.DOUBLE:
        # ⚡ Double Ball - Doubles the runs
        if user_num == opponent_num:
            # Wicket, but doubled effect cancels it (lucky!)
            return {
                'runs': 0,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🍀 LUCKY! Double effect saved you from wicket!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
        else:
            doubled_runs = user_num * 2
            return {
                'runs': doubled_runs,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n⚡ Runs DOUBLED!\n📊 {user_num} × 2 = {doubled_runs} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
    
    elif magic_type == MagicBallType.SHIELD:
        # 🛡️ Shield Ball - Cannot get out
        if user_num == opponent_num:
            # Shield protects from wicket
            return {
                'runs': 1,  # Get 1 run instead of wicket
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🛡️ PROTECTED! Shield saved you!\n🎁 Bonus: 1 run granted!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
        else:
            # Normal runs
            return {
                'runs': user_num,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🛡️ Shield active (no effect on runs)\n📊 {user_num} runs scored!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
    
    elif magic_type == MagicBallType.REVERSE:
        # 🔄 Reverse Ball - Opponent's number becomes yours
        if user_num == opponent_num:
            # Same number - reverse does nothing, just normal dot
            return {
                'runs': 0,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🔄 Numbers reversed but were same!\n📊 Dot ball!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
        else:
            # You get opponent's number as runs
            return {
                'runs': opponent_num,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🔄 REVERSED! You scored opponent's number!\n📊 {opponent_num} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
    
    elif magic_type == MagicBallType.WILD:
        # 🎲 Wild Ball - Completely random (0-6)
        wild_runs = random.randint(0, 6)
        return {
            'runs': wild_runs,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n🎲 CHAOS! Random result!\n📊 {wild_runs} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.SWAP:
        # 🔀 Swap Ball - Numbers swap
        if user_num == opponent_num:
            # Same number, swap does nothing
            return {
                'runs': 0,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🔀 Numbers swapped but were same!\n📊 Dot ball!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
        else:
            # Swap: you get opponent's number
            return {
                'runs': opponent_num,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n🔀 SWAPPED! You got {opponent_num}, they got {user_num}!\n📊 {opponent_num} runs!\n\nOriginal - Your: {user_num} | Opp: {opponent_num}\nSwapped - Your: {opponent_num} | Opp: {user_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
    
    elif magic_type == MagicBallType.TRIPLE:
        # 💎 Triple Ball - Runs × 3!
        if user_num == opponent_num:
            # Triple effect saves from wicket and gives triple runs!
            return {
                'runs': user_num * 3,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n💎 TRIPLE POWER! Saved from wicket!\n📊 {user_num} × 3 = {user_num * 3} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
        else:
            tripled_runs = user_num * 3
            return {
                'runs': tripled_runs,
                'is_wicket': False,
                'message': f"{emoji} <b>{name.upper()}!</b>\n\n💎 TRIPLE POWER!\n📊 {user_num} × 3 = {tripled_runs} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
                'magic_type': magic_type,
                'reveal_delay': 0
            }
    
    elif magic_type == MagicBallType.RAINBOW:
        # 🌈 Rainbow Ball - Lucky 7 runs!
        return {
            'runs': 7,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n🌈 LUCKY SEVEN!\n🎊 Magical 7 runs granted!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.MAGNET:
        # 🧲 Magnet Ball - Forces both numbers to be same (guaranteed dot)
        return {
            'runs': 0,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n🧲 MAGNETIC FORCE!\n Numbers pulled together!\n📊 Forced dot ball!\n\nYour: {user_num} | Opp: {opponent_num} → Both became same!",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.LUCKY:
        # 🍀 Lucky Ball - Random bonus (4, 6, or special)
        lucky_options = [4, 6, 8, 10]
        lucky_runs = random.choice(lucky_options)
        return {
            'runs': lucky_runs,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n🍀 LUCKY CHARM!\n🎁 Bonus: {lucky_runs} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.REWIND:
        # ⏮️ Rewind Ball - Nullifies this ball (like it never happened)
        return {
            'runs': 0,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n⏮️ TIME REVERSED!\n⏱️ This ball doesn't count!\n🔄 Ball will be replayed!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0,
            'special_flag': 'rewind'  # Special flag to replay ball
        }
    
    elif magic_type == MagicBallType.MYSTERY:
        # 🎭 Mystery Ball - Copies last ball's result
        mystery_runs = random.randint(0, 6)  # Random if no previous ball
        return {
            'runs': mystery_runs,
            'is_wicket': False,
            'message': f"{emoji} <b>{name.upper()}!</b>\n\n🎭 MYSTERY MIMIC!\n📋 Result: {mystery_runs} runs!\n\nYour: {user_num} | Opp: {opponent_num}",
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    elif magic_type == MagicBallType.JACKPOT:
        # 🎰 Jackpot Ball - Either 0 or 12 runs (50-50)
        jackpot_result = random.choice([0, 12])
        if jackpot_result == 0:
            msg = f"{emoji} <b>{name.upper()}!</b>\n\n🎰 JACKPOT SPIN!\n💔 Bad luck! 0 runs!\n\nYour: {user_num} | Opp: {opponent_num}"
        else:
            msg = f"{emoji} <b>{name.upper()}!</b>\n\n🎰 JACKPOT SPIN!\n🎊 MEGA WIN! 12 runs!\n\nYour: {user_num} | Opp: {opponent_num}"
        
        return {
            'runs': jackpot_result,
            'is_wicket': False,
            'message': msg,
            'magic_type': magic_type,
            'reveal_delay': 0
        }
    
    # Fallback (should never reach here)
    return {
        'runs': user_num if user_num != opponent_num else 0,
        'is_wicket': user_num == opponent_num,
        'message': None,
        'magic_type': None,
        'reveal_delay': 0
    }

async def end_innings(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    ✅ FIXED: Proper innings end logic with Super Over support
    """
    # ⚡ SUPER OVER HANDLING
    if match.is_super_over:
        if match.innings == 1:
            await end_super_over_innings(context, group_id, match)
            return
        else:
            await determine_super_over_winner(context, group_id, match)
            return
    
    # 🏏 NORMAL MATCH LOGIC
    if match.innings == 1:
        bat_team = match.current_batting_team
        bowl_team = match.current_bowling_team
        
        first_innings_score = bat_team.score
        match.target = first_innings_score + 1
        
        overs_played = max(bat_team.balls / 6, 0.1)
        rr = round(bat_team.score / overs_played, 2)

        active_batters = [p for p in bat_team.players if p.balls_faced > 0 or p.is_out]
        ib_lines = [
            f"🏆 <b>{html.escape(bat_team.name)}</b> ➔ {bat_team.score}/{bat_team.wickets} ({format_overs(bat_team.balls)} ov)",
            f"📈 <b>Run Rate:</b> {rr}",
            f"🎯 <b>TARGET:</b> {match.target} Runs",
        ]
        if active_batters:
            top_scorer = max(active_batters, key=lambda p: p.runs)
            ib_lines.append(f"🏏 <b>Top Scorer:</b> {html.escape(top_scorer.first_name)} ➔ {top_scorer.runs} ({top_scorer.balls_faced}b)")
        active_bowlers = [p for p in bowl_team.players if p.balls_bowled > 0]
        if active_bowlers:
            best_bowler = max(active_bowlers, key=lambda p: (p.wickets, -p.runs_conceded))
            ib_lines.append(f"🥎 <b>Best Bowler:</b> {html.escape(best_bowler.first_name)} ➔ {best_bowler.wickets}/{best_bowler.runs_conceded}")
        ib_lines.append("⏳ 2nd Innings begins in 30 seconds...")
        msg = themed("⏸ INNINGS BREAK", ib_lines, "🥎")
        
        gif_url = get_random_gif(MatchEvent.INNINGS_BREAK)
        try:
            if gif_url:
                await context.bot.send_animation(group_id, animation=gif_url, caption=msg, parse_mode=ParseMode.HTML)
            else:
                await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)
        except:
            await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)
        
        await asyncio.sleep(30)
        
        # Start 2nd innings
        match.innings = 2
        match.current_over_runs = 0  # Reset for 2nd innings tracking
        match.current_over_wickets = 0
        match.current_batting_team = match.get_other_team(match.current_batting_team)
        match.current_bowling_team = match.get_other_team(match.current_bowling_team)
        
        # ✅ FIX: Reset ball counts so 2nd innings always starts from ball 0
        match.current_batting_team.balls = 0
        
        match.current_batting_team.current_batsman_idx = None
        match.current_batting_team.current_non_striker_idx = None
        match.current_bowling_team.current_bowler_idx = None
        match.current_batting_team.out_players_indices = set()
        
        chase_team = match.current_batting_team
        runs_needed = match.target
        balls_available = match.total_overs * 6
        rrr = round((runs_needed / balls_available) * 6, 2)
        
        chase_lines = [
            f"🏏 <b>{html.escape(chase_team.name)}</b>",
            f"🎯 Need  <b>{runs_needed} runs</b>",
            f"⚾ In  <b>{balls_available} balls</b>  ({match.total_overs} overs)",
            f"📉 Required RR:  <b>{rrr}</b>",
        ]
        start_msg = themed("🚀 THE CHASE IS ON", chase_lines, "🏏")
        
        await context.bot.send_message(group_id, start_msg, parse_mode=ParseMode.HTML)
        await asyncio.sleep(2)
        
        match.waiting_for_batsman = True
        match.waiting_for_bowler = False
        
        captain = match.get_captain(chase_team)
        captain_tag = get_user_tag(captain)
        
        opener_lines = [
            f"👉 {captain_tag}, who's walking in first?",
            f"⌨️ <code>/batting [serial_number]</code>",
        ]
        msg = themed("🏏 SELECT YOUR OPENER", opener_lines, "🏏")

        await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)
        
        match.batsman_selection_time = time.time()
        match.batsman_selection_task = asyncio.create_task(
            batsman_selection_timeout(context, group_id, match)
        )
        
    else:
        # ✅ Second innings complete - determine winner
        await determine_match_winner(context, group_id, match)


async def determine_match_winner(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    ✅ COMPLETE FIX: Proper winner determination with guaranteed message delivery
    """
    logger.info(f"🏆 === DETERMINE WINNER START === Group: {group_id}")
    
    # Set phase immediately to prevent any further ball inputs
    match.phase = GamePhase.MATCH_ENDED
    
    # Get teams
    first = match.batting_first
    second = match.get_other_team(first)
    
    logger.info(f"🏏 First Innings: {first.name} - {first.score}/{first.wickets}")
    logger.info(f"🏏 Second Innings: {second.name} - {second.score}/{second.wickets}")
    logger.info(f"🎯 Target: {match.target}")
    
    winner = None
    loser = None
    margin = ""
    
    # ==========================================
    # 🧮 WINNER CALCULATION (FIXED LOGIC)
    # ==========================================
    
    # Case 1: Second team chased the target
    if second.score >= match.target:
        winner = second
        loser = first
        
        # Calculate wickets remaining
        wickets_lost = second.wickets
        wickets_remaining = len(second.players) - 1 - wickets_lost
        wickets_remaining = max(0, wickets_remaining)
        
        margin = f"{wickets_remaining} Wicket{'s' if wickets_remaining != 1 else ''}"
        logger.info(f"✅ Winner: {winner.name} (Chased target)")
        
    # Case 2: Second team failed to chase
    elif first.score > second.score:
        winner = first
        loser = second
        runs_diff = first.score - second.score
        margin = f"{runs_diff} Run{'s' if runs_diff != 1 else ''}"
        logger.info(f"✅ Winner: {winner.name} (Defended target)")
        
    # Case 3: Tied match → AUTO SUPER OVER
    elif first.score == second.score:
        logger.info("🤝 Match is TIED! Auto-starting Super Over...")

        tie_msg = (
            f"🤝〔 <b>MATCH TIED!</b> 〕🤝\n"
            f"─────────────────\n"
            f"  Both teams scored: <b>{first.score}/{first.wickets}</b>  \n"
            f"─────────────────\n\n"
            f"🔥 <b>SUPER OVER ACTIVATED!</b> 🔥\n"
            f"<i>⏳ Starting in 5 seconds...</i>"
        )
        try:
            await context.bot.send_message(group_id, tie_msg, parse_mode=ParseMode.HTML)
        except Exception as e:
            logger.error(f"❌ Tie message error: {e}")

        await asyncio.sleep(5)

        # DO NOT delete match → hand control to super over
        try:
            await start_super_over(context, group_id, match)
        except Exception as e:
            logger.error(f"❌ Super over start error: {e}")
            # Fallback: save as TIE and clean up
            try:
                await update_player_stats_after_match(match, None, None)
                await save_match_to_history(match, "TIE")
            except: pass
            try:
                if match.main_message_id:
                    await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
            except: pass
            if group_id in active_matches:
                del active_matches[group_id]

        logger.info("✅ Tie → Super Over triggered")
        return
    
    # ==========================================
    # ✅ VALIDATE WINNER EXISTS
    # ==========================================
    if not winner or not loser:
        logger.error("❌ CRITICAL: Winner/Loser not determined!")
        try:
            await context.bot.send_message(
                group_id,
                "⚠️ <b>Error determining match result.</b>\nPlease contact support.",
                parse_mode=ParseMode.HTML
            )
        except: pass
        
        if group_id in active_matches:
            del active_matches[group_id]
        return
    
    logger.info(f"🏆 FINAL: Winner={winner.name}, Loser={loser.name}, Margin={margin}")
    
    # ==========================================
    # 💾 UPDATE STATS & HISTORY (Non-blocking)
    # ==========================================
    try:
        logger.info("💾 Saving stats...")
        await update_player_stats_after_match(match, winner, loser)
        await save_match_to_history(match, winner.name)
        update_h2h_stats(match)
        logger.info("✅ Stats saved successfully")
    except Exception as e:
        logger.error(f"❌ Stats save error: {e}")
    
    # ==========================================
    # 🎉 SEND VICTORY MESSAGE (GUARANTEED - 3 ATTEMPTS)
    # ==========================================
    victory_sent = False
    
    for attempt in range(3):
        try:
            logger.info(f"📣 Victory message attempt {attempt + 1}/3...")
            await send_victory_message(context, group_id, match, winner, loser, margin)
            victory_sent = True
            logger.info("✅ Victory message sent successfully")
            break
        except Exception as e:
            logger.error(f"❌ Victory attempt {attempt + 1} failed: {e}")
            await asyncio.sleep(1)
    
    # Ultra fallback if all attempts fail
    if not victory_sent:
        try:
            fallback = f"🏆 {winner.name} WON by {margin}!"
            await context.bot.send_message(group_id, fallback)
            logger.info("✅ Fallback victory message sent")
        except Exception as e:
            logger.error(f"❌ CRITICAL: Even fallback failed: {e}")
    
    await asyncio.sleep(4)
    
    # ==========================================
    # 📋 SEND SCORECARD (With error handling)
    # ==========================================
    try:
        logger.info("📊 Sending scorecard...")
        await send_final_scorecard(context, group_id, match)
        await asyncio.sleep(3)
        logger.info("✅ Scorecard sent")
    except Exception as e:
        logger.error(f"❌ Scorecard error: {e}")
        # Try simple text scorecard
        try:
            simple_card = (
                f"📊 <b>MATCH SUMMARY</b>\n\n"
                f"🧊 {first.name}: {first.score}/{first.wickets}\n"
                f"🔥 {second.name}: {second.score}/{second.wickets}\n\n"
                f"🏆 Winner: {winner.name}"
            )
            await context.bot.send_message(group_id, simple_card, parse_mode=ParseMode.HTML)
        except: pass
    
    # ==========================================
    # 📋 SEND SCORECARD (With error handling)
    # ==========================================
    try:
        logger.info("📊 Sending scorecard...")
        
        # === TEAM MODE SCORECARD IMAGE ===
        if match.game_mode == "TEAM":
            # Note: Ensure 'generate_team_scorecard_image' function is defined
            # If img is a PIL object, you might need to convert it to bytes (bio) first like:
            # bio = io.BytesIO()
            # img.save(bio, 'JPEG')
            # bio.seek(0)
            
            img = generate_team_scorecard_image(match) 
            
            # Agar function direct image object return kar raha hai to use save karke bhejein:
            import io
            bio = io.BytesIO()
            img.save(bio, 'PNG')
            bio.seek(0)

            await context.bot.send_photo(
                chat_id=match.group_id,
                photo=bio,  # img object directly work nahi karega, bio use karein
                parse_mode="HTML"
            )
        # ---------------------------------

        await send_final_scorecard(context, group_id, match) # Existing Text Scorecard
        await asyncio.sleep(3)
        logger.info("✅ Scorecard sent")
    except Exception as e:
        logger.error(f"❌ Scorecard error: {e}")


    # ==========================================
    # 🌟 SEND POTM (With error handling)
    # ==========================================
    try:
        logger.info("🌟 Sending POTM...")
        await send_potm_message(context, group_id, match)
        logger.info("✅ POTM sent")
    except Exception as e:
        logger.error(f"❌ POTM error: {e}")
        # Try simple POTM
        try:
            all_players = first.players + second.players
            best_p = max(all_players, key=lambda p: p.runs + (p.wickets * 20))
            simple_potm = f"🌟 <b>PLAYER OF THE MATCH:</b> {best_p.first_name}"
            await context.bot.send_message(group_id, simple_potm, parse_mode=ParseMode.HTML)
        except: pass

    # ==========================================
    # 📰 NEWSPAPER HEADLINE IMAGE + SHARE BUTTON
    # ==========================================
    try:
        logger.info("📰 Generating newspaper headline image...")

        # Find top scorer across both teams
        all_players_end = first.players + second.players
        top_scorer = max(all_players_end, key=lambda p: p.runs) if all_players_end else None
        top_scorer_name = top_scorer.first_name if top_scorer else "Unknown"
        top_scorer_runs = top_scorer.runs if top_scorer else 0

        # Get MOM name (already set on match object by send_potm_message)
        mom_player_id = getattr(match, 'player_of_match', None)
        mom_name = top_scorer_name  # fallback
        if mom_player_id:
            for _p in all_players_end:
                if _p.user_id == mom_player_id:
                    mom_name = _p.first_name
                    break

        # Build MOM speech for caption
        mom_speech_text = generate_mom_speech(mom_name, top_scorer_runs, 0, getattr(match, 'group_name', ''))

        newspaper_bio = await asyncio.to_thread(
            generate_newspaper_image, match, winner, loser,
            top_scorer_name, top_scorer_runs, mom_name, margin
        )

        if newspaper_bio:
            # Share button → Telegram share deep link
            try:
                share_text = (
                    f"{winner.name} won by {margin} 🏆 | "
                    f"{winner.name} {winner.score}/{winner.wickets} "
                    f"vs {loser.name} {loser.score}/{loser.wickets} | "
                    f"Top scorer: {top_scorer_name} {top_scorer_runs} | "
                    f"#CricoVerse"
                )
                encoded_text = quote_plus(share_text)
                share_markup = InlineKeyboardMarkup([[
                    InlineKeyboardButton(
                        "📤 Share Result",
                        url=f"https://t.me/share/url?url=https%3A%2F%2Ft.me%2FCricoVerseBot&text={encoded_text}"
                    )
                ]])
            except Exception:
                share_markup = None

            await context.bot.send_photo(
                chat_id=group_id,
                photo=newspaper_bio,
                caption=mom_speech_text,
                parse_mode=ParseMode.HTML,
                reply_markup=share_markup
            )
            logger.info("✅ Newspaper image + MOM speech sent")
        else:
            logger.warning("⚠️ Newspaper image generation returned None")

    except Exception as e:
        logger.error(f"❌ Newspaper image error: {e}")
    
    await asyncio.sleep(2)

    
    # ==========================================
    # 🧹 CLEANUP
    # ==========================================
    try:
        if match.main_message_id:
            await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
    except: pass
    
    if group_id in active_matches:
        del active_matches[group_id]

    logger.info("🏁 Match ended successfully")
    logger.info(f"🏆 === DETERMINE WINNER END ===\n")

async def testwin_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """DEBUG: Force test winner determination"""
    user = update.effective_user
    if user.id != OWNER_ID: return
    
    chat = update.effective_chat
    if chat.id not in active_matches:
        await update.message.reply_text("No active match")
        return
    
    match = active_matches[chat.id]
    
    # Force set phase and call winner determination
    match.phase = GamePhase.MATCH_ENDED
    await determine_match_winner(context, chat.id, match)
    """
    ✅ COMPLETE FIX: Proper winner determination and message delivery
    """
    logger.info(f"🏆 === DETERMINE WINNER START === Group: {group_id}")
    
    # Get teams
    first = match.batting_first
    second = match.get_other_team(first)
    
    logger.info(f"📊 First Innings: {first.name} - {first.score}/{first.wickets}")
    logger.info(f"📊 Second Innings: {second.name} - {second.score}/{second.wickets}")
    logger.info(f"🎯 Target: {match.target}")
    
    winner = None
    loser = None
    margin = ""
    
    # ==========================================
    # 🧮 WINNER CALCULATION (FIXED LOGIC)
    # ==========================================
    
    # Case 1: Second team chased the target
    if second.score >= match.target:
        winner = second
        loser = first
        
        # Calculate wickets remaining
        wickets_lost = second.wickets
        wickets_remaining = len(second.players) - 1 - wickets_lost  # Total - 1 (for partner) - lost
        wickets_remaining = max(0, wickets_remaining)
        
        margin = f"{wickets_remaining} Wicket{'s' if wickets_remaining != 1 else ''}"
        logger.info(f"✅ Winner: {winner.name} (Chased target)")
        
    # Case 2: Second team failed to chase
    elif first.score > second.score:
        winner = first
        loser = second
        runs_diff = first.score - second.score
        margin = f"{runs_diff} Run{'s' if runs_diff != 1 else ''}"
        logger.info(f"✅ Winner: {winner.name} (Defended target)")
        
    # Case 3: Tied match
    elif first.score == second.score:
        logger.info("🤝 Match is TIED!")
        
        tie_msg = (
            f"🤝 <b>MATCH TIED!</b> 🤝\n"
            f"─────────────────\n"
            f"Both teams scored: <b>{first.score}/{first.wickets}</b>\n\n"
            f"🎲 What a thrilling finish!\n"
            f"─────────────────"
        )
        
        await context.bot.send_message(group_id, tie_msg, parse_mode=ParseMode.HTML)
        
        # Update stats for tie
        await update_player_stats_after_match(match, None, None)
        await save_match_to_history(match, "TIE")
        
        # Cleanup
        try:
            if match.main_message_id:
                await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
        except: pass
        
        if group_id in active_matches:
            del active_matches[group_id]
        
        logger.info("✅ Tie match handled successfully")
        return
    
    # ==========================================
    # ✅ VALIDATE WINNER EXISTS
    # ==========================================
    if not winner or not loser:
        logger.error("❌ CRITICAL: Winner/Loser not determined!")
        await context.bot.send_message(
            group_id,
            "⚠️ <b>Error determining match result.</b>\nPlease contact support.",
            parse_mode=ParseMode.HTML
        )
        
        # Force cleanup
        if group_id in active_matches:
            del active_matches[group_id]
        return
    
    logger.info(f"🏆 FINAL: Winner={winner.name}, Loser={loser.name}, Margin={margin}")
    
    # ==========================================
    # 📊 UPDATE STATS & HISTORY
    # ==========================================
    try:
        logger.info("💾 Saving stats...")
        await update_player_stats_after_match(match, winner, loser)
        await save_match_to_history(match, winner.name)
        update_h2h_stats(match)
        logger.info("✅ Stats saved successfully")
    except Exception as e:
        logger.error(f"❌ Stats save error: {e}")
    
    # ==========================================
    # 🎉 SEND VICTORY MESSAGE (GUARANTEED)
    # ==========================================
    try:
        logger.info("📢 Sending victory message...")
        await send_victory_message(context, group_id, match, winner, loser, margin)
        await asyncio.sleep(4)
        logger.info("✅ Victory message sent")
    except Exception as e:
        logger.error(f"❌ Victory message error: {e}")
        # Fallback simple message
        fallback_msg = (
            f"🏆 <b>{winner.name.upper()} WON!</b> 🏆\n"
            f"─────────────────\n"
            f"Won by: <b>{margin}</b>\n\n"
            f"📊 {first.name}: {first.score}/{first.wickets}\n"
            f"📊 {second.name}: {second.score}/{second.wickets}\n"
            f"─────────────────"
        )
        await context.bot.send_message(group_id, fallback_msg, parse_mode=ParseMode.HTML)
        await asyncio.sleep(3)
    
    # ==========================================
    # 📋 SEND SCORECARD
    # ==========================================
    try:
        logger.info("📊 Sending scorecard...")
        await send_final_scorecard(context, group_id, match)
        await asyncio.sleep(3)
        logger.info("✅ Scorecard sent")
    except Exception as e:
        logger.error(f"❌ Scorecard error: {e}")
    
    # ==========================================
    # 🌟 SEND POTM
    # ==========================================
    try:
        logger.info("⭐ Sending POTM...")
        await send_potm_message(context, group_id, match)
        logger.info("✅ POTM sent")
    except Exception as e:
        logger.error(f"❌ POTM error: {e}")
    
    # ==========================================
    # 🧹 CLEANUP
    # ==========================================
    try:
        if match.main_message_id:
            await context.bot.unpin_chat_message(chat_id=group_id, message_id=match.main_message_id)
    except: pass
    
    if group_id in active_matches:
        del active_matches[group_id]
    
    logger.info("🏁 Match ended successfully")
    logger.info(f"🏆 === DETERMINE WINNER END ===\n")

async def send_final_scorecard(context: ContextTypes.DEFAULT_TYPE, group_id: int, match: Match):
    """
    📊 PREMIUM MATCH SCORECARD - Professional Design
    """
    
    first_innings = match.batting_first
    second_innings = match.get_other_team(first_innings)
    
    # Helper function for batting card
    def format_batting_card(team, innings_num):
        inn_label = "1st" if innings_num == 1 else "2nd"
        rr = round(team.score / max(team.overs, 0.1), 2)
        extras = getattr(team, 'extras', 0)
        card = f"╭━─────────────────\n"
        card += f"┃ 🏆 {inn_label} INNINGS ➔ {html.escape(team.name)}\n"
        card += f"┃ 📊 {team.score}/{team.wickets} ({format_overs(team.balls)} ) | 📈 RR: {rr}\n"
        card += f"┃ ⚖️ Extras: {extras}\n"
        card += f"┣━─────────────────\n"
        card += f"┃ 🏏 BATTING\n"

        batters = sorted([p for p in team.players if p.balls_faced > 0 or p.is_out],
                        key=lambda x: x.runs, reverse=True)
        for p in batters:
            sr = round((p.runs / max(p.balls_faced, 1)) * 100, 1)
            not_out = "*" if not p.is_out and p.balls_faced > 0 else ""
            card += f"┃ 👤 {html.escape(p.first_name[:16])}{not_out} ➔ {p.runs} ({p.balls_faced}b)  |  SR: {sr}\n"

        card += f"╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        return card

    # Helper function for bowling card
    def format_bowling_card(bowling_team, batting_team_name):
        card = f"╭━─────────────────\n"
        card += f"┃ 🥎 BOWLING\n"

        bowlers = sorted([p for p in bowling_team.players if p.balls_bowled > 0],
                        key=lambda x: (x.wickets, -x.runs_conceded), reverse=True)
        for p in bowlers:
            ov = format_overs(p.balls_bowled)
            econ = round(p.runs_conceded / max(p.balls_bowled / 6, 0.1), 2)
            card += f"┃ 👤 {html.escape(p.first_name[:16])} ➔ {p.wickets}/{p.runs_conceded} ({ov} ) | 📉 Eco: {econ}\n"

        card += f"╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        return card

    # Build Complete Scorecard
    msg = "📊 Cricoverse Scorecard\n"
    msg += format_batting_card(first_innings, 1)
    msg += format_bowling_card(second_innings, first_innings.name)
    
    msg += "\n╠════════════════╣\n"
    # Second Innings
    msg += "<b>🔸 SECOND INNINGS</b>\n\n"
    msg += format_batting_card(second_innings, 2)
    msg += format_bowling_card(first_innings, second_innings.name)
    msg += "\n─────────────────\n\n"
    
    # Match Result
    winner = None
    if second_innings.score >= match.target:
        winner = second_innings
        wickets_remaining = len(winner.players) - 1 - winner.wickets
        margin = f"{wickets_remaining} wicket{'s' if wickets_remaining != 1 else ''}"
    else:
        winner = first_innings
        margin = f"{first_innings.score - second_innings.score} runs"
    
    msg += f"🏆 <b>RESULT:</b> {winner.name} won by {margin}\n\n"
    
    # Key Performances
    all_players = first_innings.players + second_innings.players
    
    # Top Scorer
    top_scorer = max([p for p in all_players if p.balls_faced > 0], 
                    key=lambda x: x.runs, default=None)
    if top_scorer:
        msg += f"⭐ <b>Top Score:</b> {top_scorer.first_name} - {top_scorer.runs}({top_scorer.balls_faced})\n"
    
    # Best Bowler
    best_bowler = max([p for p in all_players if p.balls_bowled > 0], 
                     key=lambda x: (x.wickets, -x.runs_conceded), default=None)
    if best_bowler:
        msg += f"🎯 <b>Best Bowling:</b> {best_bowler.first_name} - {best_bowler.wickets}/{best_bowler.runs_conceded}\n"
    
    # Bug 4 Fix: Use worm graph as the OFFICIAL MATCH SCORECARD image instead of static photo
    # Remove separate worm graph message → worm is embedded in the scorecard
    try:
        worm_bio = await asyncio.to_thread(generate_worm_graph, match)
        if worm_bio:
            first_innings = match.batting_first
            keyboard = InlineKeyboardMarkup([[
                InlineKeyboardButton("➡️ 2nd Innings", callback_data=f"scorecard_worm_{group_id}_2")
            ]])
            await context.bot.send_photo(
                group_id,
                photo=worm_bio,
                caption=msg,
                parse_mode=ParseMode.HTML,
                reply_markup=keyboard
            )
        else:
            raise Exception("Worm graph returned None")
    except Exception as worm_e:
        logger.warning(f"Worm graph for scorecard failed, using fallback: {worm_e}")
        try:
            await context.bot.send_photo(
                group_id,
                photo=MEDIA_ASSETS.get("scorecard"),
                caption=msg,
                parse_mode=ParseMode.HTML
            )
        except:
            await context.bot.send_message(group_id, msg, parse_mode=ParseMode.HTML)


# ╔══════════════════════════════════════════════════════════════════╗
# ║         4K IMAGE GENERATORS  (PIL · 3840×2160)                 ║
# ╚══════════════════════════════════════════════════════════════════╝

_IMG4K_W, _IMG4K_H = 3840, 2160   # true 4K


# ─────────────────────────────────────────────────────────────────
#  WORM GRAPH (Score Progression with Wicket Fall)  BLACK BG
# ─────────────────────────────────────────────────────────────────
def generate_players_squad_image(match) -> Optional[BytesIO]:
    """
    🏏 Cricket-theme Squad Card  —  shows both team rosters on a premium turf field.
    """
    try:
        import math
        SC = 2
        
        # Calculate dynamic height based on player counts (max up to 16 players)
        num_players = max(len(match.team_x.players), len(match.team_y.players), 5)
        H_unscaled = 220 + num_players * 80 + 80
        W, H = 1200 * SC, H_unscaled * SC
        
        img = Image.new("RGBA", (W, H))
        draw = ImageDraw.Draw(img)

        # ── 1. MOWED TURF BACKGROUND ──
        # Grass base
        draw.rectangle([0, 0, W, H], fill=(16, 50, 28, 255))
        
        # Vertical stripes (mowed outfield lawn)
        stripe_w = 60 * SC
        for x in range(0, W, stripe_w):
            if (x // stripe_w) % 2 == 0:
                draw.rectangle([x, 0, x + stripe_w, H], fill=(22, 62, 36, 255))
                
        # Subtle stadium floodlight glow / vignette overlay
        for i in range(20):
            alpha = int(140 * (1 - i / 20))
            offset = i * 4 * SC
            draw.rectangle([offset, offset, W - offset, H - offset], fill=None, outline=(8, 24, 12, alpha), width=4*SC)

        C_GOLD  = (255, 215, 0, 255)
        C_X     = (64, 196, 255, 255)    # Team X — Bright Sky Blue
        C_Y     = (255, 96, 144, 255)    # Team Y — Hot Pink
        C_WHITE = (245, 250, 255, 255)
        C_MUTED = (160, 190, 175, 255)
        PANEL   = (10, 32, 20, 200)      # Deep green frosted glass
        BORDER  = (255, 255, 255, 45)    # Glass border

        f_header = _get_font(True, 44 * SC)
        f_team   = _get_font(True, 36 * SC)
        f_name   = _get_font(True, 28 * SC)
        f_stat   = _get_font(False, 22 * SC)
        f_sm     = _get_font(False, 20 * SC)

        # ── 2. HEADER BANNER (Glassmorphism style with gold accent) ──
        draw.rounded_rectangle([40*SC, 30*SC, W-40*SC, 130*SC], radius=24*SC,
                                fill=(10, 28, 16, 220), outline=C_GOLD, width=3*SC)
        
        title = "🏏  PLAYING SQUADS  🏏"
        bbox = draw.textbbox((0, 0), title, font=f_header)
        tw = bbox[2] - bbox[0]
        draw.text(((W - tw) // 2, 52*SC), title, font=f_header, fill=C_GOLD)

        # Match phase sub-label
        phase_map = {
            "match_in_progress": "🔴 LIVE MATCH IN PROGRESS",
            "innings_break": "☕ INNINGS BREAK",
            "toss": "🪙 TOSS UNDERWAY",
            "team_joining": "⏳ LOBBY OPEN",
            "match_ended": "🏆 MATCH COMPLETE",
        }
        phase_txt = phase_map.get(getattr(match, 'phase', None) and match.phase.value, "⚡ CRICOVERSE")
        bbox2 = draw.textbbox((0, 0), phase_txt, font=f_sm)
        draw.text(((W - (bbox2[2] - bbox2[0])) // 2, 98*SC), phase_txt, font=f_sm, fill=C_MUTED)

        # ── 3. SCORE BAR ──
        if match.phase and match.phase.value in ("match_in_progress", "innings_break", "match_ended"):
            score_txt = (f"{match.team_x.name}: {match.team_x.score}/{match.team_x.wickets} ({format_overs(match.team_x.balls)})   "
                         f"vs   {match.team_y.name}: {match.team_y.score}/{match.team_y.wickets} ({format_overs(match.team_y.balls)})")
            bbox3 = draw.textbbox((0, 0), score_txt, font=f_sm)
            sx = max(50*SC, (W - (bbox3[2] - bbox3[0])) // 2)
            draw.text((sx, 142*SC), score_txt, font=f_sm, fill=C_WHITE)

        # ── 4. TWO-COLUMN TEAM PANELS ──
        col_left  = 40*SC
        col_right = W // 2 + 20*SC
        col_w     = W // 2 - 60*SC
        panel_top = 170*SC

        def _status_icon(player, team):
            if player.is_out:
                return "❌"
            if match.current_batting_team == team:
                bat_idx = team.current_batsman_idx
                ns_idx  = team.current_non_striker_idx
                if bat_idx is not None and bat_idx < len(team.players) and team.players[bat_idx].user_id == player.user_id:
                    return "🏏"
                if ns_idx is not None and ns_idx < len(team.players) and team.players[ns_idx].user_id == player.user_id:
                    return "🔄"
            if match.current_bowling_team == team:
                bowl_idx = team.current_bowler_idx
                if bowl_idx is not None and bowl_idx < len(team.players) and team.players[bowl_idx].user_id == player.user_id:
                    return "⚡"
            return "🟢"

        def _draw_team_panel(team, color, x0):
            # Calculate panel height dynamically to contain all players
            panel_h = 75*SC + len(team.players) * 80*SC + 15*SC
            draw.rounded_rectangle([x0, panel_top, x0 + col_w, panel_top + panel_h],
                                   radius=20*SC, fill=PANEL, outline=BORDER, width=2*SC)

            # Team header bar
            draw.rounded_rectangle([x0, panel_top, x0 + col_w, panel_top + 65*SC],
                                   radius=20*SC, fill=(*color[:3], 120), outline=color, width=2*SC)
            
            toss_mark = " 🪙" if getattr(match, 'toss_winner', None) == team else ""
            cap_name = ""
            for p in team.players:
                if p.user_id == team.captain_id:
                    cap_name = f" · 👑 {p.first_name}"
                    break

            team_label = f" {team.name}{toss_mark}{cap_name}"
            draw.text((x0 + 16*SC, panel_top + 15*SC), team_label, font=f_team, fill=C_WHITE)

            # Player rows
            py = panel_top + 75*SC
            for i, player in enumerate(team.players):
                # Glass row style
                row_fill = (255, 255, 255, 18) if i % 2 == 0 else (255, 255, 255, 8)
                draw.rounded_rectangle([x0 + 8*SC, py, x0 + col_w - 8*SC, py + 72*SC],
                                       radius=12*SC, fill=row_fill, outline=BORDER, width=1*SC)

                # Number badge with team primary color
                draw.ellipse([x0+20*SC, py+16*SC, x0+52*SC, py+48*SC], fill=color)
                num_txt = str(i + 1)
                nb = draw.textbbox((0, 0), num_txt, font=f_sm)
                draw.text((x0 + 36*SC - (nb[2]-nb[0])//2, py + 18*SC), num_txt, font=f_sm, fill=(10, 30, 20, 255))

                # Captain/Player tags
                cap_icon = " 👑" if player.user_id == team.captain_id else ""
                status_icon = _status_icon(player, team)
                name_str = f"{player.first_name[:16]}{cap_icon}"
                draw.text((x0 + 68*SC, py + 10*SC), name_str, font=f_name, fill=C_WHITE)

                # Player stats sub-line
                stat_parts = []
                if player.balls_faced > 0 or player.is_out:
                    sr = round((player.runs / max(player.balls_faced, 1)) * 100, 1)
                    stat_parts.append(f"🏏 {player.runs}({player.balls_faced}) SR:{sr}")
                if player.balls_bowled > 0:
                    eco = round(player.runs_conceded / max(player.balls_bowled / 6, 0.1), 1)
                    stat_parts.append(f"⚾ {player.wickets}W/{player.runs_conceded}R Eco:{eco}")
                stat_str = "  ·  ".join(stat_parts) if stat_parts else "Waiting to play…"
                draw.text((x0 + 68*SC, py + 42*SC), stat_str, font=f_stat, fill=C_MUTED)

                # Status icon
                draw.text((x0 + col_w - 48*SC, py + 18*SC), status_icon, font=f_name, fill=C_WHITE)

                py += 80*SC

        _draw_team_panel(match.team_x, C_X, col_left)
        _draw_team_panel(match.team_y, C_Y, col_right)

        # ── 5. FOOTER BRANDING ──
        footer_y = H - 52*SC
        draw.line([(40*SC, footer_y - 10*SC), (W - 40*SC, footer_y - 10*SC)], fill=C_GOLD, width=1*SC)
        brand = "⚡ CRICOVERSE  ·  THE ULTIMATE HAND CRICKET EXPERIENCE"
        fb = draw.textbbox((0, 0), brand, font=f_sm)
        draw.text(((W - (fb[2]-fb[0])) // 2, footer_y), brand, font=f_sm, fill=C_MUTED)

        # Resize to final crisp output
        final_h = H_unscaled
        final = img.convert("RGB").resize((1200, final_h), Image.Resampling.LANCZOS)
        bio = BytesIO()
        final.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio
    except Exception as e:
        logger.error(f"generate_players_squad_image error: {e}")
        return None


def generate_worm_graph(match) -> Optional[BytesIO]:
    """
    Ultra-Premium Worm Chart — Pure Black Stadium Canvas.
    Deep neon glow, wicket markers, live-chase context.
    """
    try:
        SC = 2
        W, H = 1400 * SC, 800 * SC
        PAD_L, PAD_R, PAD_T, PAD_B = 120*SC, 80*SC, 110*SC, 150*SC
        CHART_W = W - PAD_L - PAD_R
        CHART_H = H - PAD_T - PAD_B

        img = Image.new("RGB", (W, H), (0, 0, 0))
        draw = ImageDraw.Draw(img)
        for x in range(-H, W, 160 * SC):
            draw.line([(x, 0), (x + H, H)], fill=(12, 18, 38), width=1 * SC)

        C_X = (0, 210, 255); C_Y = (255, 50, 110)
        C_GOLD = (255, 215, 0); C_GRAY = (80, 100, 140)
        C_GRID = (18, 28, 55); C_WHITE = (235, 245, 255)
        C_ORG  = (255, 145, 0)

        fn_title = _get_font(True, 44 * SC)
        fn_bold  = _get_font(True, 30 * SC)
        fn_reg   = _get_font(False, 22 * SC)
        fn_sm    = _get_font(False, 18 * SC)

        bat_team = getattr(match, "current_batting_team", None)
        ball_log = getattr(match, "ball_by_ball_log", [])

        def build_bb(team_name):
            scores, wkts, total = [0], [False], 0
            for e in ball_log:
                if e.get("batting_team") != team_name:
                    continue
                total += e.get("runs", 0)
                scores.append(total)
                wkts.append(e.get("is_wicket", False) or e.get("wicket", False))
            return scores, wkts

        x_scores, x_wkts = build_bb(match.team_x.name)
        y_scores, y_wkts = build_bb(match.team_y.name)
        total_overs = getattr(match, "total_overs", 5)
        max_score = max(max(x_scores, default=0), max(y_scores, default=0), 10) + 15
        n_balls   = max(len(x_scores), len(y_scores), 2) - 1

        for j in range(7):
            val = int(j * max_score / 6)
            gy  = PAD_T + CHART_H - int(j * CHART_H / 6)
            draw.line([(PAD_L, gy), (PAD_L + CHART_W, gy)], fill=C_GRID, width=1*SC)
            draw.text((PAD_L - 78*SC, gy - 14*SC), str(val), font=fn_reg, fill=C_GRAY)

        for ov in range(total_overs + 1):
            ball_idx = ov * 6
            if ball_idx > n_balls:
                break
            gx = PAD_L + int(ball_idx / n_balls * CHART_W) if n_balls else PAD_L
            draw.line([(gx, PAD_T), (gx, PAD_T + CHART_H)], fill=C_GRID, width=2*SC)
            draw.text((gx - 12*SC, PAD_T + CHART_H + 22*SC), str(ov), font=fn_reg, fill=C_GRAY)

        def to_px(idx, score):
            px = PAD_L + (idx / n_balls * CHART_W) if n_balls > 0 else PAD_L
            py = PAD_T + CHART_H - (score / max_score * CHART_H)
            return px, py

        def draw_neon_worm(scores, color, wkts, is_live):
            pts = [to_px(i, s) for i, s in enumerate(scores)]
            if len(pts) < 2:
                return
            for w in [16, 10, 6, 3]:
                dim = tuple(max(0, c - 140) for c in color)
                draw.line(pts, fill=dim, width=w * SC)
            for i in range(len(pts) - 1):
                runs = (scores[i+1] - scores[i]) if i+1 < len(scores) else 0
                is_w = wkts[i+1] if i+1 < len(wkts) else False
                if runs == 6:
                    seg = C_GOLD
                elif runs == 4:
                    seg = C_ORG
                elif runs == 0 and not is_w:
                    seg = (65, 80, 120)
                else:
                    seg = color
                if is_live and i == len(pts) - 2:
                    x1, y1 = pts[i]; x2, y2 = pts[i+1]
                    for d in range(0, 8, 2):
                        sx = x1+(x2-x1)*d/8; sy = y1+(y2-y1)*d/8
                        ex = x1+(x2-x1)*(d+1)/8; ey = y1+(y2-y1)*(d+1)/8
                        draw.line([(sx, sy), (ex, ey)], fill=seg, width=4*SC)
                else:
                    draw.line([pts[i], pts[i+1]], fill=seg, width=4*SC)
            for i, (px, py) in enumerate(pts):
                runs = (scores[i] - scores[i-1]) if i > 0 else 0
                is_w = wkts[i] if i < len(wkts) else False
                if is_w:
                    draw.ellipse([px-15*SC, py-15*SC, px+15*SC, py+15*SC], fill=(190,22,45), outline=C_GOLD, width=2*SC)
                    draw.text((px-8*SC, py-10*SC), "W", font=fn_sm, fill=C_WHITE)
                elif runs == 6:
                    draw.ellipse([px-10*SC, py-10*SC, px+10*SC, py+10*SC], fill=C_GOLD, outline=C_WHITE, width=1*SC)
                elif runs == 4:
                    draw.ellipse([px-7*SC, py-7*SC, px+7*SC, py+7*SC], fill=C_ORG, outline=C_WHITE, width=1*SC)
                elif runs == 0:
                    draw.ellipse([px-3*SC, py-3*SC, px+3*SC, py+3*SC], fill=(70, 85, 120))
                else:
                    draw.ellipse([px-5*SC, py-5*SC, px+5*SC, py+5*SC], fill=color, outline=C_WHITE, width=1*SC)

        x_live = (bat_team == match.team_x)
        y_live = (bat_team is not None and bat_team != match.team_x)
        draw_neon_worm(x_scores, C_X, x_wkts, x_live)
        if len(y_scores) > 1:
            draw_neon_worm(y_scores, C_Y, y_wkts, y_live)

        title_str = "SCORE WORM  *  " + match.team_x.name + " vs " + match.team_y.name
        draw.text((PAD_L, 22*SC), title_str.upper(), font=fn_title, fill=C_GOLD)

        leg_y = H - 88*SC
        draw.rounded_rectangle([PAD_L-10*SC, leg_y-8*SC, PAD_L+980*SC, leg_y+58*SC],
                                radius=14*SC, fill=(8,12,30), outline=(40,55,100), width=1*SC)
        xwc = sum(1 for w in x_wkts if w)
        ywc = sum(1 for w in y_wkts if w)
        draw.rectangle([PAD_L+10*SC, leg_y+8*SC, PAD_L+40*SC, leg_y+40*SC], fill=C_X)
        xl = "  " + match.team_x.name + "  " + str(x_scores[-1] if x_scores else 0) + "/" + str(xwc) + "  (" + str(len(x_scores)-1) + " balls)"
        draw.text((PAD_L+50*SC, leg_y+4*SC), xl, font=fn_bold, fill=C_X)
        draw.rectangle([PAD_L+500*SC, leg_y+8*SC, PAD_L+530*SC, leg_y+40*SC], fill=C_Y)
        yl = "  " + match.team_y.name + "  " + str(y_scores[-1] if y_scores else 0) + "/" + str(ywc) + "  (" + str(len(y_scores)-1) + " balls)"
        draw.text((PAD_L+540*SC, leg_y+4*SC), yl, font=fn_bold, fill=C_Y)
        draw.text((W-80*SC, leg_y+10*SC), "W=Wicket  6=Gold  4=Orange", font=fn_sm, fill=C_GRAY)

        if getattr(match, "innings", 1) == 2 and getattr(match, "target", 0):
            bat = getattr(match, "current_batting_team", match.team_y)
            need = max(match.target - bat.score, 0)
            balls_left = max(match.total_overs * 6 - bat.balls, 0)
            chase_txt = "CHASE: " + str(need) + " needed from " + str(balls_left) + " balls"
            ctb = draw.textbbox((0,0), chase_txt, font=fn_bold)
            draw.rounded_rectangle([PAD_L, PAD_T-48*SC, PAD_L+(ctb[2]-ctb[0])+36*SC, PAD_T-8*SC],
                                   radius=12*SC, fill=(20,32,65), outline=C_GOLD, width=2*SC)
            draw.text((PAD_L+18*SC, PAD_T-45*SC), chase_txt, font=fn_bold, fill=C_GOLD)

        draw.text((W-82*SC, H-40*SC), "CRICOVERSE ANALYTICS", font=fn_sm, fill=(30,50,90))
        img = img.resize((1400, 800), Image.Resampling.LANCZOS)
        bio = BytesIO()
        img.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio

    except Exception as e:
        print("Worm graph error: " + str(e))
        return None


# ─────────────────────────────────────────────────────────────────
#  MATCH SUMMARY IMAGE  (PIL · black bg, professional design)
# ─────────────────────────────────────────────────────────────────
def _draw_glass_panel(draw, x1, y1, x2, y2, accent_color):
    """Draws a premium translucent panel with glow and border."""
    # Main Glass Body (Translucent)
    fill_c = (15, 20, 45, 180) 
    # Rounded Rect with a subtle glow outline
    draw.rounded_rectangle([x1, y1, x2, y2], radius=25, fill=fill_c, outline=accent_color, width=3)
    
    # Subtle Top Highlight (Glossy effect)
    draw.line([(x1+40, y1+2), (x2-40, y1+2)], fill=(255, 255, 255, 60), width=2)

def generate_ultimate_match_summary(match, winner_name: str) -> Optional[BytesIO]:
    try:
        # Increase internal resolution for smoothness, then downsample
        W, H = 1080, 1920
        img = Image.new("RGBA", (W, H), (5, 10, 25, 255))
        draw = ImageDraw.Draw(img)

        # --- PREMIUM COLORS ---
        C_GOLD = (255, 215, 0, 255)
        C_X = (0, 220, 255, 255)    # Cyber Blue
        C_Y = (255, 50, 120, 255)   # Vivid Pink
        C_WIN = (40, 255, 150, 255) # Neon Green
        C_WHITE = (245, 250, 255, 255)
        C_SUB = (140, 160, 190, 255)

        # --- ENHANCED BACKGROUND GRADIENT ---
        for i in range(H):
            r = int(10 + (20 * i / H))
            g = int(15 + (10 * i / H))
            b = int(40 + (30 * i / H))
            draw.line([(0, i), (W, i)], fill=(r, g, b, 255))

        # --- HEADER (DYNAMIC SLANT) ---
        draw.polygon([(0, 0), (W, 0), (W, 200), (0, 280)], fill=(12, 18, 40, 255))
        draw.text((80, 80), "MATCH SUMMARY", font=_get_font(True, 95), fill=C_GOLD)
        draw.rectangle([80, 195, 450, 202], fill=C_GOLD) 

        # --- WINNER BANNER (SOOTHING NEON) ---
        banner_y = 310
        draw.rectangle([0, banner_y, W, banner_y + 120], fill=(20, 45, 35, 255))
        draw.line([(0, banner_y), (W, banner_y)], fill=C_WIN, width=4)
        draw.line([(0, banner_y + 120), (W, banner_y + 120)], fill=C_WIN, width=4)
        
        result_text = f"🏆 {winner_name.upper()} WON BY {match.margin_text.upper()} 🏆"
        draw.text((W//2, banner_y + 30), result_text, font=_get_font(True, 52), fill=C_WHITE, anchor="mt")

        # --- TEAM PANELS ---
        teams_data = [
            (match.batting_first, C_X, 480), 
            (match.get_other_team(match.batting_first), C_Y, 1100)
        ]

        for team, accent, py in teams_data:
            # Drawing the Glassmorphism Panel
            _draw_glass_panel(draw, 45, py, W-45, py + 580, accent)
            
            # Team Name & Huge Score
            draw.text((90, py + 45), team.name.upper(), font=_get_font(True, 60), fill=accent)
            score_txt = f"{team.score}/{team.wickets}"
            draw.text((90, py + 120), score_txt, font=_get_font(True, 120), fill=C_WHITE)
            
            # Overs & RR (Pill Style)
            rr = round(team.score / max(team.balls / 6, 0.1), 2)
            ov_txt = f"{format_overs(team.balls)} OVERS • {rr} RR"
            draw.rounded_rectangle([W-480, py+60, W-90, py+125], radius=15, fill=(35, 50, 90, 255), outline=accent, width=2)
            draw.text((W-285, py+75), ov_txt, font=_get_font(True, 32), fill=C_WHITE, anchor="mt")

            # --- BATTERS LIST (ALIGNED & DETAILED) ---
            draw.text((90, py + 280), "KEY PERFORMANCES", font=_get_font(True, 35), fill=C_GOLD)
            draw.line([(90, py + 325), (350, py + 325)], fill=C_GOLD, width=3)

            batters = sorted([p for p in team.players if p.balls_faced > 0], key=lambda x: x.runs, reverse=True)[:3]
            for i, p in enumerate(batters):
                yy = py + 355 + (i * 70)
                # Player Name
                draw.text((110, yy), p.first_name.upper(), font=_get_font(False, 38), fill=C_WHITE)
                # Runs and SR
                sr = round((p.runs / p.balls_faced) * 100, 1) if p.balls_faced > 0 else 0
                stat_str = f"{p.runs} ({p.balls_faced})  •  {sr} SR"
                draw.text((W-110, yy), stat_str, font=_get_font(True, 38), fill=C_WHITE, anchor="ra")

        # --- PLAYER OF THE MATCH (EPIC FOOTER) ---
        potm_y = 1720
        # Hexagonal Style Box
        draw.polygon([(60, potm_y), (W-60, potm_y), (W-30, potm_y+150), (30, potm_y+150)], fill=(15, 25, 55, 255), outline=C_GOLD, width=4)
        
        potm = max(match.team_x.players + match.team_y.players, key=lambda p: (p.runs * 1.5) + (p.wickets * 25))
        draw.text((W//2, potm_y + 25), "PLAYER OF THE MATCH", font=_get_font(True, 38), fill=C_GOLD, anchor="mt")
        potm_info = f"{potm.name.upper()} • {potm.runs} runs & {potm.wickets} wickets".upper()
        draw.text((W//2, potm_y + 75), potm_info, font=_get_font(True, 45), fill=C_WHITE, anchor="mt")

        # Branding
        draw.text((W//2, H-60), "CRICORA • THE NEXT GEN EXPERIENCE", font=_get_font(False, 28), fill=C_SUB, anchor="mt")

        # Convert to RGB before saving
        final_img = img.convert("RGB")
        bio = BytesIO()
        final_img.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio

    except Exception as e:
        print(f"God-Level Template Error: {e}")
        return None

# ─────────────────────────────────────────────────────────────────
#  MID-MATCH LIVE SCORE CARD IMAGE (sent randomly every 2 overs)
# ─────────────────────────────────────────────────────────────────
def generate_mid_match_image(match) -> Optional[BytesIO]:
    """
    💎 BROADCAST-MASTER LIVE DASHBOARD:
    • Glassmorphism with Dynamic Blur Simulation
    • Geometric Vector Accents for Tactical Look
    • Smooth Anti-Aliasing (Super-sampled rendering)
    • Neon-Gradient Ball Badges
    """
    try:
        # Internal Scaling for Ultra Smoothness (2x)
        SC = 2
        W, H = 1920 * SC, 1080 * SC
        img = Image.new("RGBA", (W, H), (4, 6, 18, 255))
        draw = ImageDraw.Draw(img)

        # ── Palette (Enhanced Contrast) ──
        C_GOLD, C_WHITE = (255, 210, 50, 255), (245, 250, 255, 255)
        C_X, C_Y = (0, 190, 255, 255), (255, 60, 110, 255) # Electric Blue & Hot Pink
        C_GREEN, C_RED = (0, 255, 140, 255), (255, 70, 85, 255)
        C_PANEL = (15, 20, 45, 180) # Translucent Glass
        C_GRID = (25, 35, 65, 255)

        # ── 1. Dynamic Background ──
        # Subtle Diagonal Stripes for Modern Tech Feel
        for i in range(0, W + H, 100 * SC):
            draw.line([(i, 0), (i - H, H)], fill=(20, 30, 60, 255), width=2 * SC)

        # ── 2. Header (Glass Pill) ──
        header_rect = [W//2 - 400*SC, 40*SC, W//2 + 400*SC, 130*SC]
        draw.rounded_rectangle(header_rect, radius=45*SC, fill=(20, 25, 55, 255), outline=C_RED, width=4*SC)
        _draw_text_centered_glow(draw, "🔴  LIVE MATCH CENTER", W//2, 60*SC, _get_font(True, 45*SC), C_WHITE)

        bat_team = match.current_batting_team
        bowl_team = match.current_bowling_team

        if bat_team and bowl_team:
            bat_color = C_X if bat_team == match.team_x else C_Y
            bowl_color = C_Y if bat_team == match.team_x else C_X

            # ── 3. MAIN SCORE PANEL (Glassmorphism) ──
            # Left: Batting Info
            main_py = 180 * SC
            draw.rounded_rectangle([80*SC, main_py, W//2 - 30*SC, main_py + 360*SC], radius=50*SC, fill=C_PANEL, outline=bat_color, width=5*SC)
            
            # Team Name & Huge Score
            draw.text((130*SC, main_py + 40*SC), f"🏏 {bat_team.name.upper()}", font=_get_font(True, 50*SC), fill=bat_color)
            score_str = f"{bat_team.score}/{bat_team.wickets}"
            draw.text((130*SC, main_py + 100*SC), score_str, font=_get_font(True, 150*SC), fill=C_WHITE)
            
            # Overs in a pill
            ov_txt = f"({format_overs(bat_team.balls)} OV)"
            draw.text((750*SC, main_py + 175*SC), ov_txt, font=_get_font(True, 80*SC), fill=(160, 180, 210, 255))

            # CRR/RRR Stats Row
            rr = round(bat_team.score / max(bat_team.balls / 6, 0.1), 2)
            draw.text((130*SC, main_py + 280*SC), f"CRR: {rr}", font=_get_font(True, 40*SC), fill=C_WHITE)
            
            if match.innings == 2 and match.target > 0:
                needed = match.target - bat_team.score
                balls_left = (match.total_overs * 6) - bat_team.balls
                draw.text((450*SC, main_py + 280*SC), f"NEED {needed} OFF {balls_left}B", font=_get_font(True, 40*SC), fill=C_GOLD)

            # Right: Bowling Summary Info
            draw.rounded_rectangle([W//2 + 30*SC, main_py, W - 80*SC, main_py + 360*SC], radius=50*SC, fill=(10, 15, 35, 150), outline=bowl_color, width=3*SC)
            draw.text((W//2 + 80*SC, main_py + 40*SC), f"⚾ {bowl_team.name.upper()}", font=_get_font(True, 50*SC), fill=bowl_color)
            draw.text((W//2 + 80*SC, main_py + 120*SC), f"{bowl_team.score}/{bowl_team.wickets}", font=_get_font(True, 100*SC), fill=(180, 200, 230, 255))

            # ── 4. PLAYER CARDS (Geometric Detail) ──
            card_py = 580 * SC
            # Batsmen Card
            draw.rounded_rectangle([80*SC, card_py, W//2 - 30*SC, card_py + 280*SC], radius=35*SC, fill=C_PANEL, outline=(50, 60, 110, 255), width=2*SC)
            draw.text((120*SC, card_py + 20*SC), "AT THE CREASE", font=_get_font(True, 35*SC), fill=C_GOLD)
            draw.line([(120*SC, card_py + 70*SC), (400*SC, card_py + 70*SC)], fill=C_GOLD, width=3*SC)

            # Striker (Smooth Highlight)
            striker = bat_team.players[bat_team.current_batsman_idx] if bat_team.current_batsman_idx is not None else None
            if striker:
                draw.text((120*SC, card_py + 90*SC), f"★ {striker.first_name.upper()}", font=_get_font(True, 55*SC), fill=C_WHITE)
                draw.text((650*SC, card_py + 95*SC), f"{striker.runs} ({striker.balls_faced})", font=_get_font(True, 55*SC), fill=C_GREEN, anchor="ra")

            # Bowler Card
            draw.rounded_rectangle([W//2 + 30*SC, card_py, W - 80*SC, card_py + 280*SC], radius=35*SC, fill=C_PANEL, outline=(50, 60, 110, 255), width=2*SC)
            draw.text((W//2 + 70*SC, card_py + 20*SC), "ACTIVE BOWLER", font=_get_font(True, 35*SC), fill=C_GOLD)
            
            if bowl_team.current_bowler_idx is not None:
                bowler = bowl_team.players[bowl_team.current_bowler_idx]
                draw.text((W//2 + 70*SC, card_py + 90*SC), f"⚡ {bowler.first_name.upper()}", font=_get_font(True, 55*SC), fill=C_WHITE)
                draw.text((W - 130*SC, card_py + 95*SC), f"{bowler.wickets}/{bowler.runs_conceded}", font=_get_font(True, 55*SC), fill=C_Y, anchor="ra")
                draw.text((W//2 + 70*SC, card_py + 180*SC), f"ECO: {bowler.get_economy()} | {format_overs(bowler.balls_bowled)} OV", font=_get_font(False, 35*SC), fill=(160, 175, 210, 255))

            # ── 5. RECENT BALLS (Smooth Glow Badges) ──
            last6 = match.last_6_balls[-6:]
            if last6:
                bx_start = W//2 - 350*SC
                by = 920 * SC
                draw.text((bx_start - 180*SC, by + 15*SC), "RECENT:", font=_get_font(True, 40*SC), fill=(120, 135, 170, 255))
                
                for bi, ball in enumerate(last6):
                    r = ball.get("runs", 0) if isinstance(ball, dict) else (ball if isinstance(ball, int) else 0)
                    w = ball.get("wicket", False) if isinstance(ball, dict) else False
                    
                    # Modern Color Logic
                    b_color = C_RED if w else ((160, 80, 255, 255) if r >= 6 else ((40, 160, 255, 255) if r >= 4 else (60, 70, 100, 255)))
                    
                    bx = bx_start + (bi * 115 * SC)
                    # Glow Ring
                    draw.ellipse([bx-4*SC, by-4*SC, bx+84*SC, by+84*SC], outline=b_color, width=2*SC)
                    # Main Ball
                    draw.ellipse([bx+5*SC, by+5*SC, bx+75*SC, by+75*SC], fill=b_color)
                    txt = "W" if w else (str(r) if r > 0 else "•")
                    draw.text((bx + 40*SC, by + 10*SC), txt, font=_get_font(True, 45*SC), fill=C_WHITE, anchor="mt")

        # ── 6. Footer (Premium Branding) ──
        draw.line([(100*SC, 1020*SC), (W-100*SC, 1020*SC)], fill=(45, 60, 120, 255), width=2*SC)
        footer_txt = "⚡ CRICORA ULTIMATE | THE PREMIUM CRICKET EXPERIENCE"
        draw.text((W//2, 1045*SC), footer_txt, font=_get_font(False, 30*SC), fill=(110, 130, 170, 255), anchor="mt")

        # FINAL SMOOTHING: Resize down (LANCZOS)
        img = img.convert("RGB").resize((1920, 1080), Image.Resampling.LANCZOS)
        
        bio = BytesIO()
        img.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio

    except Exception as e:
        print(f"Mid-Match Error: {e}")
        return None

# ─────────────────────────────────────────────────────────────────
#  SOLO TOP BATSMEN IMAGE  (sent at solo game end)
# ─────────────────────────────────────────────────────────────────
def generate_solo_top3_image(sorted_players) -> Optional[BytesIO]:
    """
    🥇 GOD-LEVEL 4K PODIUM:
    • 3D-Style Pedestal Layout for 1st, 2nd, and 3rd
    • Glassmorphism Floating Cards with Material Depth
    • Victory Aura Rays & Particle System
    • Smooth Anti-Aliasing via 2x Downsampling
    """
    try:
        if not sorted_players: return None

        # 4K Internal Rendering for Smoothness (Anti-Aliasing)
        SC = 2
        W, H = 1920 * SC, 1080 * SC
        img = Image.new("RGBA", (W, H), (5, 8, 22, 255))
        draw = ImageDraw.Draw(img)

        # --- COLORS ---
        C_GOLD, C_SILVER, C_BRONZE = (255, 215, 0, 255), (192, 192, 192, 255), (205, 127, 50, 255)
        C_WIN, C_WHITE = (0, 255, 150, 255), (245, 250, 255, 255)
        C_PANEL = (15, 20, 45, 200)

        # 1. ENHANCED VICTORY BACKGROUND
        # Deep space gradient with victory rays
        for i in range(H):
            draw.line([(0, i), (W, i)], fill=(10 + i//100, 15 + i//150, 35 + i//80, 255))
        
        cx_bg, cy_bg = W // 2, H // 2 + 200*SC
        for angle in range(0, 360, 10):
            rad = math.radians(angle)
            ex, ey = cx_bg + 2000*math.cos(rad), cy_bg + 2000*math.sin(rad)
            draw.line([(cx_bg, cy_bg), (ex, ey)], fill=(30, 45, 90, 100), width=3*SC)

        # 2. PODIUM DATA
        top3 = sorted_players[:3]
        
        # Slots: (Player, Rank_Index, Center_X, Elevation, Card_Scale, Color)
        slots = []
        if len(top3) >= 3:
            slots = [
                (top3[1], 1, W//2 - 550*SC, 420*SC, 0.85, C_SILVER), # 2nd Left
                (top3[2], 2, W//2 + 550*SC, 480*SC, 0.80, C_BRONZE), # 3rd Right
                (top3[0], 0, W//2, 300*SC, 1.0, C_GOLD)             # 1st Center
            ]
        elif len(top3) == 2:
            slots = [
                (top3[1], 1, W//2 - 300*SC, 400*SC, 0.9, C_SILVER), 
                (top3[0], 0, W//2 + 300*SC, 300*SC, 1.0, C_GOLD)
            ]
        else:
            slots = [(top3[0], 0, W//2, 320*SC, 1.1, C_GOLD)]

        # 3. DRAW SLOTS (Z-INDEX AWARE)
        # Hum 1st place (Rank 0) ko sabse aakhir mein draw karenge taaki wo upar dikhe
        slots.sort(key=lambda x: x[1], reverse=True)

        for p, rank_idx, cx, sy, scale, color in slots:
            cw, ch = int(500 * SC * scale), int(620 * SC * scale)
            px1, py1 = cx - cw // 2, sy
            px2, py2 = cx + cw // 2, sy + ch

            # Glassmorphism Card with Elevation Glow
            glow_color = (*color[:3], 60)
            draw.rounded_rectangle([px1-15*SC, py1-15*SC, px2+15*SC, py2+15*SC], radius=45*SC, fill=glow_color)
            draw.rounded_rectangle([px1, py1, px2, py2], radius=40*SC, fill=C_PANEL, outline=color, width=4*SC)

            # Medal Emoji / Rank Number
            medals = ["🥇", "🥈", "🥉"]
            _draw_text_centered_glow(draw, medals[rank_idx], cx, py1 - 70*SC, _get_font(True, 100*SC), color)

            # Player Stats (Using first_name to avoid attribute errors)
            p_name = getattr(p, 'first_name', 'PLAYER').upper()
            draw.text((cx, py1 + 80*SC), p_name, font=_get_font(True, int(55*SC * scale)), fill=C_WHITE, anchor="mt")
            draw.line([(cx - 80*SC, py1 + 160*SC), (cx + 80*SC, py1 + 160*SC)], fill=color, width=3*SC)
            
            score_txt = f"{p.runs} ({p.balls_faced})"
            draw.text((cx, py1 + 220*SC), score_txt, font=_get_font(True, int(85*SC * scale)), fill=C_WIN, anchor="mt")
            
            sr = round((p.runs / max(p.balls_faced, 1)) * 100, 1)
            draw.text((cx, py1 + 330*SC), f"SR: {sr}", font=_get_font(True, int(45*SC * scale)), fill=C_GOLD if sr > 140 else C_WHITE, anchor="mt")

            # Boundaries Badge
            if hasattr(p, 'boundaries') and (p.boundaries > 0 or getattr(p, 'sixes', 0) > 0):
                badge_rect = [cx - 150*SC*scale, py2 - 90*SC*scale, cx + 150*SC*scale, py2 - 30*SC*scale]
                draw.rounded_rectangle(badge_rect, radius=15*SC, fill=(25, 35, 70, 255))
                b_txt = f"4s: {p.boundaries} • 6s: {getattr(p, 'sixes', 0)}"
                draw.text((cx, py2 - 75*SC*scale), b_txt, font=_get_font(False, int(32*SC * scale)), fill=C_WHITE, anchor="mt")

        # 4. VICTORY OVERLAY (Particles around Champion)
        random.seed(42)
        for _ in range(80):
            ptx, pty = random.randint(W//2 - 600*SC, W//2 + 600*SC), random.randint(150*SC, 700*SC)
            draw.ellipse([ptx, pty, ptx+6*SC, pty+6*SC], fill=random.choice([C_GOLD, C_WHITE, C_WIN, (255,255,255,100)]))

        # 5. FOOTER & BRANDING
        draw.text((W//2, H - 150*SC), f"🏆 BATTLE CHAMPION: {getattr(top3[0], 'first_name', 'PLAYER').upper()} 🏆", font=_get_font(True, 65*SC), fill=C_GOLD, anchor="mt")
        draw.text((W//2, H - 60*SC), "⚡ CRICORA • SOLO BATTLE SERIES", font=_get_font(False, 30*SC), fill=(140, 160, 200, 255), anchor="mt")

        # Final Rescale (LANCZOS) for makhan-smooth edges
        final_img = img.convert("RGB").resize((1920, 1080), Image.Resampling.LANCZOS)
        
        bio = BytesIO()
        final_img.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio
        
    except Exception as e:
        print(f"Podium Error: {e}")
        return None

