async def add_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """➕ Smart add: editing phase -> uses editing_team; live match -> reply or /add @user1 @user2 then team picker"""
    chat = update.effective_chat
    user = update.effective_user
    if chat.id not in active_matches:
        await update.message.reply_text("🚫 No active match!", parse_mode=ParseMode.HTML)
        return
    match = active_matches[chat.id]

    # ── EDITING PHASE ──
    if match.phase == GamePhase.TEAM_EDIT:
        await add_player_command(update, context)
        return

    # ── LIVE MATCH ──
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text("⚠️ Cannot add players in current match phase.", parse_mode=ParseMode.HTML)
        return

    if user.id != match.host_id:
        await update.message.reply_text("🚧 <b>HOST ONLY!</b> Only the host can add players mid-game.", parse_mode=ParseMode.HTML)
        return

    # Collect target users: reply + args together (mass support)
    targets = []

    # 1. Reply target
    if update.message.reply_to_message and update.message.reply_to_message.from_user:
        ru = update.message.reply_to_message.from_user
        if not ru.is_bot:
            targets.append((ru.id, ru.username or "", ru.first_name or str(ru.id)))

    # 2. Args targets (@username or user_id)
    for arg in (context.args or []):
        if arg.startswith("@"):
            uname = arg[1:].lower()
            found = False
            for uid, data in user_data.items():
                if data.get("username", "").lower() == uname:
                    targets.append((uid, data.get("username", ""), data.get("first_name", uname)))
                    found = True
                    break
            if not found:
                try:
                    chat_obj = await context.bot.get_chat(arg)
                    targets.append((chat_obj.id, chat_obj.username or "", chat_obj.first_name or arg))
                except Exception:
                    pass
        elif arg.lstrip("-").isdigit():
            uid_int = int(arg)
            try:
                chat_obj = await context.bot.get_chat(uid_int)
                targets.append((chat_obj.id, chat_obj.username or "", chat_obj.first_name or str(uid_int)))
            except Exception:
                targets.append((uid_int, "", str(uid_int)))

    # Deduplicate
    seen = set()
    unique_targets = []
    for t in targets:
        if t[0] not in seen:
            seen.add(t[0])
            unique_targets.append(t)
    targets = unique_targets

    if not targets:
        await update.message.reply_text(
            "ℹ️ <b>ADD PLAYER (Live Match)</b>\n"
            "─────────────────\n"
            "<b>Reply to a message:</b>  reply + <code>/add</code>\n"
            "<b>By username (mass):</b>  <code>/add @user1 @user2 ...</code>\n"
            "<b>By user ID (mass):</b>   <code>/add 12345 67890 ...</code>\n\n"
            "Bot will then ask which team to add them to.",
            parse_mode=ParseMode.HTML
        )
        return

    # Filter out already-in-team players
    valid_targets = []
    already_in = []
    for (uid, uname, fname) in targets:
        if match.team_x.get_player(uid) or match.team_y.get_player(uid):
            already_in.append(fname)
        else:
            valid_targets.append((uid, uname, fname))

    warning = ""
    if already_in:
        warning = f"\n⚠️ Already in a team: {', '.join(already_in)}"

    if not valid_targets:
        await update.message.reply_text(f"⚠️ All mentioned players are already in a team!{warning}", parse_mode=ParseMode.HTML)
        return

    # Store pending in bot_data
    pending_key = f"addpending_{chat.id}_{user.id}"
    context.bot_data[pending_key] = valid_targets  # list of (uid, uname, fname)

    uid_str = ",".join(str(t[0]) for t in valid_targets)[:200]
    names_display = ", ".join(f"<b>{html.escape(t[2])}</b>" for t in valid_targets)

    keyboard = InlineKeyboardMarkup([[
        InlineKeyboardButton(f"🔵 {match.team_x.name}", callback_data=f"addpick_X_{chat.id}_{user.id}"),
        InlineKeyboardButton(f"🔴 {match.team_y.name}", callback_data=f"addpick_Y_{chat.id}_{user.id}"),
    ]])

    await update.message.reply_text(
        f"➕ <b>ADD PLAYER(S) — CHOOSE TEAM</b>\n"
        f"─────────────────\n"
        f"👤 Player(s): {names_display}{warning}\n\n"
        f"👇 Which team should they join?",
        parse_mode=ParseMode.HTML,
        reply_markup=keyboard
    )


async def addpick_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle team picker for /add command"""
    query = update.callback_query
    await query.answer()
    user = query.from_user
    parts = query.data.split("_")
    # addpick_X_chatid_userid
    if len(parts) < 4:
        await query.answer("❌ Invalid data.", show_alert=True)
        return
    team_letter = parts[1]
    try:
        chat_id = int(parts[2])
        host_id = int(parts[3])
    except (ValueError, IndexError):
        await query.answer("❌ Invalid data.", show_alert=True)
        return

    if user.id != host_id:
        await query.answer("🚫 Only the host can pick the team!", show_alert=True)
        return

    if chat_id not in active_matches:
        await query.message.edit_text("❌ No active match.", parse_mode=ParseMode.HTML)
        return
    match = active_matches[chat_id]
    team = match.team_x if team_letter == "X" else match.team_y

    pending_key = f"addpending_{chat_id}_{host_id}"
    targets = context.bot_data.pop(pending_key, [])

    if not targets:
        await query.message.edit_text("⚠️ Session expired. Please use /add again.", parse_mode=ParseMode.HTML)
        return

    added = []
    skipped = []

    for (uid, uname, fname) in targets:
        if match.team_x.get_player(uid) or match.team_y.get_player(uid):
            skipped.append(fname)
            continue
        if uid not in user_data:
            user_data[uid] = {
                "user_id": uid, "username": uname, "first_name": fname,
                "started_at": datetime.now().isoformat(), "total_matches": 0
            }
            init_player_stats(uid)
            save_data()
        new_player = Player(uid, uname, fname)
        team.add_player(new_player)
        added.append(fname)

    added_str = ", ".join(f"<b>{html.escape(n)}</b>" for n in added) if added else "None"
    skip_str = (f"\n⚠️ Already in team (skipped): {', '.join(skipped)}" if skipped else "")

    await query.message.edit_text(
        f"✅ <b>ADDED → TEAM {team_letter} ({html.escape(team.name)})</b>\n"
        f"─────────────────\n"
        f"🎯 Added: {added_str}{skip_str}\n"
        f"📊 Team size: <b>{len(team.players)}</b>\n\n"
        f"<i>Added mid-game by Host</i>",
        parse_mode=ParseMode.HTML
    )


async def remove_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """➖ /remove [serial_number] — then choose which team via buttons."""
    chat = update.effective_chat
    user = update.effective_user
    if chat.id not in active_matches:
        await update.message.reply_text(
            themed("🚫 NO MATCH", ["No active match found."], "❌"),
            parse_mode=ParseMode.HTML
        )
        return
    match = active_matches[chat.id]

    # ── EDITING PHASE ──
    if match.phase == GamePhase.TEAM_EDIT:
        await remove_player_command(update, context)
        return

    # ── LIVE MATCH ──
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text(
            themed("⚠️ WRONG PHASE", ["Cannot remove players in the current match phase."], "⚠️"),
            parse_mode=ParseMode.HTML
        )
        return

    if user.id != match.host_id:
        await update.message.reply_text(
            themed("🚧 HOST ONLY", ["Only the <b>host</b> can remove players mid-game."], "🚧"),
            parse_mode=ParseMode.HTML
        )
        return

    if not context.args:
        await update.message.reply_text(
            themed("📋 REMOVE PLAYER", [
                "Usage: <code>/remove [serial number]</code>",
                "Then select the team via the buttons.",
                "",
                "🧊 <b>Team X lineup:</b>",
                *[f"  {i}. {p.first_name}" for i, p in enumerate(match.team_x.players, 1)],
                "",
                "🔥 <b>Team Y lineup:</b>",
                *[f"  {i}. {p.first_name}" for i, p in enumerate(match.team_y.players, 1)],
            ], "📋"),
            parse_mode=ParseMode.HTML
        )
        return

    try:
        serial = int(context.args[0])
    except ValueError:
        await update.message.reply_text(
            themed("❌ INVALID", ["Please provide a valid serial number. Example: <code>/remove 3</code>"], "❌"),
            parse_mode=ParseMode.HTML
        )
        return

    # Show team selection buttons
    preview_lines = [
        f"🔢 Serial selected: <b>#{serial}</b>",
        "Choose which team this player belongs to:",
        "",
        "🧊 <b>Team X:</b> " + (match.team_x.players[serial - 1].first_name if 0 < serial <= len(match.team_x.players) else "—"),
        "🔥 <b>Team Y:</b> " + (match.team_y.players[serial - 1].first_name if 0 < serial <= len(match.team_y.players) else "—"),
    ]
    keyboard = InlineKeyboardMarkup([[
        InlineKeyboardButton("🧊 Team X", callback_data=f"remove_player_X_{chat.id}_{serial}"),
        InlineKeyboardButton("🔥 Team Y", callback_data=f"remove_player_Y_{chat.id}_{serial}"),
    ]])
    await update.message.reply_text(
        themed("➖ REMOVE PLAYER", preview_lines, "➖"),
        parse_mode=ParseMode.HTML,
        reply_markup=keyboard
    )


async def remove_player_team_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle team selection for /remove [serial] command."""
    query = update.callback_query
    await query.answer()

    user = query.from_user
    data = query.data  # remove_player_X_<group_id>_<serial>

    try:
        parts = data.split("_")
        team_letter = parts[2]          # X or Y
        group_id = int(parts[3])
        serial = int(parts[4])
    except Exception:
        await query.answer("Invalid data!", show_alert=True)
        return

    if group_id not in active_matches:
        await query.answer("No active match!", show_alert=True)
        return

    match = active_matches[group_id]

    if user.id != match.host_id:
        await query.answer("Only the host can remove players!", show_alert=True)
        return

    team = match.team_x if team_letter == "X" else match.team_y

    if serial < 1 or serial > len(team.players):
        try:
            await query.edit_message_text(
                themed("⚠️ NOT FOUND", [f"Player #{serial} not found in Team {team_letter}."], "⚠️"),
                parse_mode=ParseMode.HTML,
            )
        except Exception:
            pass
        return

    player = team.players[serial - 1]

    # Prevent removing active players
    if team == match.current_batting_team:
        s_id = team.players[team.current_batsman_idx].user_id if team.current_batsman_idx is not None else None
        ns_id = team.players[team.current_non_striker_idx].user_id if team.current_non_striker_idx is not None else None
        if player.user_id in (s_id, ns_id):
            await query.edit_message_text(
                themed("🚧 BLOCKED", [f"{player.first_name} is currently <b>batting</b> and cannot be removed."], "🚧"),
                parse_mode=ParseMode.HTML,
            )
            return
    if team == match.current_bowling_team:
        b_id = team.players[team.current_bowler_idx].user_id if team.current_bowler_idx is not None else None
        if player.user_id == b_id:
            await query.edit_message_text(
                themed("🚧 BLOCKED", [f"{player.first_name} is currently <b>bowling</b> and cannot be removed."], "🚧"),
                parse_mode=ParseMode.HTML,
            )
            return

    team.remove_player(player.user_id)

    try:
        await query.edit_message_text(
            themed("✅ PLAYER REMOVED", [
                f"👤 <b>{html.escape(player.first_name)}</b> removed from <b>Team {team_letter}</b>.",
                f"📊 Team {team_letter} now has {len(team.players)} players.",
            ], "✅"),
            parse_mode=ParseMode.HTML,
        )
    except Exception:
        pass





async def mid_game_add_logic(update: Update, context: ContextTypes.DEFAULT_TYPE, team_name: str):
    """🤝 Unified Add Logic (Reply / Username / ID) → Host Only"""
    chat = update.effective_chat
    user = update.effective_user
    if chat.id not in active_matches:
        await update.message.reply_text(
            "🚫 <b>NO ACTIVE MATCH!</b>\n\n"
            "Start a match first.",
            parse_mode=ParseMode.HTML
        )
        return
    match = active_matches[chat.id]
    if user.id != match.host_id:
        await update.message.reply_text(
            "🚧 <b>HOST ONLY!</b>\n\n"
            "Only the host can add players mid-game!",
            parse_mode=ParseMode.HTML
        )
        return
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text(
            "⏳ <b>MATCH NOT IN PROGRESS!</b>\n\n"
            "Can only add players during live match!",
            parse_mode=ParseMode.HTML
        )
        return
    # Identify target user
    target_user = None
    if update.message.reply_to_message:
        target_user = update.message.reply_to_message.from_user
    elif context.args:
        arg = context.args[0]
        if arg.startswith("@"):
            username = arg[1:].lower()
            for uid, data in user_data.items():
                if data.get("username", "").lower() == username:
                    try:
                        target_user = await context.bot.get_chat(uid)
                    except:
                        pass
                    break
        elif arg.isdigit():
            try:
                target_user = await context.bot.get_chat(int(arg))
            except:
                pass
    if not target_user:
        await update.message.reply_text(
            f"ℹ️ <b>ADD PLAYER USAGE</b>\n"
            f"─────────────────\n\n"
            f"<b>Reply Method:</b>\n"
            f"<code>/add{team_name.lower()}</code>\n\n"
            f"<b>Username Method:</b>\n"
            f"<code>/add{team_name.lower()} @username</code>\n\n"
            f"<b>User ID Method:</b>\n"
            f"<code>/add{team_name.lower()} 123456789</code>\n\n"
            f"─────────────────",
            parse_mode=ParseMode.HTML
        )
        return
    team = match.team_x if team_name == "X" else match.team_y
    if match.team_x.get_player(target_user.id) or match.team_y.get_player(target_user.id):
        await update.message.reply_text(
            "⚠️ <b>PLAYER ALREADY IN A TEAM!</b>\n\n"
            "This player is already assigned.",
            parse_mode=ParseMode.HTML
        )
        return
    if target_user.id not in user_data:
        user_data[target_user.id] = {
            "user_id": target_user.id,
            "username": target_user.username or "",
            "first_name": target_user.first_name,
            "started_at": datetime.now().isoformat(),
            "total_matches": 0
        }
        init_player_stats(target_user.id)
        save_data()

    # ✅ Check if player has started the bot before adding
    bot_username = context.bot.username
    started = await check_user_started_bot(context.bot, target_user.id)

    new_player = Player(target_user.id, target_user.username or "", target_user.first_name)
    team.add_player(new_player)
    target_tag = get_user_tag(target_user)

    not_started_warning = ""
    if not started:
        not_started_warning = (
            f"\n\n⚠️ <b>Warning:</b> {html.escape(target_user.first_name)} hasn't started the bot!\n"
            f"👉 Ask them to start: <a href='https://t.me/{bot_username}'>@{bot_username}</a>\n"
            f"<i>They won't receive bowl/bat DMs until they do!</i>"
        )

    team_label = "X" if team == match.team_x else "Y"
    await update.message.reply_text(
        f"╭━━ TEAM {team_label} ━━━━━━━━━━━━━━━\n"
        f"┃ 👤 Added: {target_tag}\n"
        f"┃ 👥 Team Size: {len(team.players)}\n"
        f"╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        f"{not_started_warning}",
        parse_mode=ParseMode.HTML,
        disable_web_page_preview=True
    )

async def mid_game_remove_logic(update: Update, context: ContextTypes.DEFAULT_TYPE, team_name: str):
    """🗑 Unified Remove Logic → Host Only"""
    chat = update.effective_chat
    user = update.effective_user
    if chat.id not in active_matches:
        await update.message.reply_text(
            "🚫 <b>NO ACTIVE MATCH!</b>\n\n"
            "Start a match first.",
            parse_mode=ParseMode.HTML
        )
        return
    match = active_matches[chat.id]
    if user.id != match.host_id:
        await update.message.reply_text(
            "🚧 <b>HOST ONLY!</b>\n\n"
            "Only the host can remove players mid-game!",
            parse_mode=ParseMode.HTML
        )
        return
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text(
            "⏳ <b>MATCH NOT IN PROGRESS!</b>\n\n"
            "Can only remove players during match!",
            parse_mode=ParseMode.HTML
        )
        return
    target_user_id = None
    if update.message.reply_to_message:
        target_user_id = update.message.reply_to_message.from_user.id
    elif context.args:
        arg = context.args[0]
        if arg.startswith("@"):
            username = arg[1:].lower()
            for uid, data in user_data.items():
                if data.get("username", "").lower() == username:
                    target_user_id = uid
                    break
        elif arg.isdigit():
            target_user_id = int(arg)
    if not target_user_id:
        await update.message.reply_text(
            f"ℹ️ <b>REMOVE PLAYER USAGE</b>\n"
            f"─────────────────\n\n"
            f"<b>Reply Method:</b>\n"
            f"<code>/remove{team_name.lower()}</code>\n\n"
            f"<b>Username Method:</b>\n"
            f"<code>/remove{team_name.lower()} @username</code>\n\n"
            f"<b>User ID Method:</b>\n"
            f"<code>/remove{team_name.lower()} 123456789</code>\n\n"
            f"─────────────────",
            parse_mode=ParseMode.HTML
        )
        return
    team = match.team_x if team_name == "X" else match.team_y
    player = team.get_player(target_user_id)
    if not player:
        await update.message.reply_text(
            f"⚠️ <b>PLAYER NOT FOUND!</b>\n\n"
            f"Player is not in Team {team_name}!",
            parse_mode=ParseMode.HTML
        )
        return
    # Prevent removing active players
    if team == match.current_batting_team:
        if team.current_batsman_idx is not None and team.players[team.current_batsman_idx].user_id == target_user_id:
            await update.message.reply_text(
                "🚧 <b>CANNOT REMOVE STRIKER!</b>\n\n"
                "Current striker cannot be removed.",
                parse_mode=ParseMode.HTML
            )
            return
        if team.current_non_striker_idx is not None and team.players[team.current_non_striker_idx].user_id == target_user_id:
            await update.message.reply_text(
                "🚧 <b>CANNOT REMOVE NON-STRIKER!</b>\n\n"
                "Current non-striker cannot be removed.",
                parse_mode=ParseMode.HTML
            )
            return
    if team == match.current_bowling_team:
        if team.current_bowler_idx is not None and team.players[team.current_bowler_idx].user_id == target_user_id:
            await update.message.reply_text(
                "🚧 <b>CANNOT REMOVE BOWLER!</b>\n\n"
                "Current bowler cannot be removed.",
                parse_mode=ParseMode.HTML
            )
            return
    team.remove_player(target_user_id)
    await update.message.reply_text(
        f"❎ <b>PLAYER REMOVED → TEAM {team_name}</b>\n"
        f"─────────────────\n\n"
        f"🎯 <b>Player:</b> {player.first_name}\n"
        f"📊 <b>Team Size:</b> {len(team.players)}\n\n"
        f"─────────────────\n"
        f"<i>Removed by Host mid-game</i>",
        parse_mode=ParseMode.HTML
    )


async def team_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /team [team_name] — Show auction team details
    Displays: Full squad, remaining purse, bought players, slots left
    """
    chat = update.effective_chat
    user = update.effective_user

    if chat.id not in active_auctions:
        await update.message.reply_text(
            "🚫 <b>NO ACTIVE AUCTION!</b>\n\nStart an auction first.",
            parse_mode=ParseMode.HTML
        )
        return

    auction = active_auctions[chat.id]

    if not auction.teams:
        await update.message.reply_text(
            "⚠️ <b>No teams registered yet!</b>\n\nTeams will appear once bidders join.",
            parse_mode=ParseMode.HTML
        )
        return

    # If a specific team name is requested
    team_name_query = " ".join(context.args).strip() if context.args else None

    if team_name_query:
        # Find matching team (case-insensitive)
        matched = None
        for tname, tobj in auction.teams.items():
            if tname.lower() == team_name_query.lower():
                matched = (tname, tobj)
                break
        if not matched:
            team_list = "\n".join(f"• {t}" for t in auction.teams.keys())
            await update.message.reply_text(
                f"❌ Team <b>{html.escape(team_name_query)}</b> not found.\n\n"
                f"📋 <b>Available teams:</b>\n{team_list}",
                parse_mode=ParseMode.HTML
            )
            return
        teams_to_show = [matched]
    else:
        # Show all teams
        teams_to_show = list(auction.teams.items())

    for tname, team in teams_to_show:
        bidder_tag = ""
        if team.bidder_id:
            bidder_tag = f"<a href='tg://user?id={team.bidder_id}'>{html.escape(team.bidder_name or tname)}</a>"
        else:
            bidder_tag = html.escape(tname)

        squad_count = len(team.players)
        purse_used = team.total_spent
        purse_left = team.purse_remaining

        msg = f"╭━━ 🏆 {html.escape(tname.upper())} ━━━━━━━━━━━━━━━\n"
        msg += f"┃ 👑 Bidder: {bidder_tag}\n"
        msg += f"┃ 💰 Purse Remaining: <b>{purse_left} Coins</b>\n"
        msg += f"┃ 💸 Total Spent: {purse_used} Coins\n"
        msg += f"┃ 👥 Squad Size: {squad_count}\n"
        msg += f"┣━─────────────────\n"

        if team.players:
            msg += f"┃ 🏏 BOUGHT PLAYERS\n"
            msg += f"┃ ─────────────────\n"
            for i, p in enumerate(team.players, 1):
                p_id = p.get('player_id', '')
                p_name = p.get('player_name', 'Unknown')
                p_price = p.get('price', 0)
                p_tag = f"<a href='tg://user?id={p_id}'>{html.escape(p_name)}</a>" if p_id else html.escape(p_name)
                msg += f"┃ {i}. {p_tag} — <b>{p_price} 🪙</b>\n"
        else:
            msg += f"┃ 🏏 BOUGHT PLAYERS\n"
            msg += f"┃ ─────────────────\n"
            msg += f"┃ <i>No players bought yet.</i>\n"

        msg += f"╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n"

        await update.message.reply_text(msg, parse_mode=ParseMode.HTML, disable_web_page_preview=True)


def _build_auction_summary_pages(auction: "Auction") -> list:
    """Build paginated pages for auction summary (/list)."""
    sold_players = auction.sold_players
    unsold_players = auction.unsold_players
    remaining = auction.player_pool
    sold_count = len(sold_players)
    unsold_count = len(unsold_players)
    remaining_count = len(remaining)
    total = sold_count + unsold_count + remaining_count

    header = (
        f"📊 <b>CRICOVERSE AUCTION SUMMARY</b>\n"
        f"╭━─────────────────\n"
        f"┃ ✅ Sold: <b>{sold_count}</b>  |  ❌ Unsold: <b>{unsold_count}</b>  |  ⏳ Remaining: <b>{remaining_count}</b>\n"
        f"┃ 📦 Total Pool: <b>{total}</b>\n"
        f"╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n"
    )

    # Team purse summary block
    team_block = ""
    if auction.teams:
        team_block = "╭━━ 💰 TEAM PURSE STATUS ━━━━━━━━━━━━━━━\n"
        for tname, tobj in sorted(auction.teams.items(), key=lambda x: x[1].purse_remaining, reverse=True):
            squad_n = len(tobj.players)
            team_block += f"┃ 🏆 {html.escape(tname)}: <b>{tobj.purse_remaining} 🪙</b> left | {squad_n} players\n"
        team_block += "╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n"

    # Build entries for sold players
    sold_entries = []
    for i, sp in enumerate(sold_players, 1):
        p_id = sp.get('player_id', '')
        p_name = sp.get('player_name', 'Unknown')
        p_tag = f"<a href='tg://user?id={p_id}'>{html.escape(p_name)}</a>" if p_id else html.escape(p_name)
        sold_entries.append(f"┃ {i}. {p_tag}\n┃    ↳ 👥 {html.escape(str(sp.get('team','?')))} — 🪙 {sp.get('price',0)}\n")

    # Build entries for unsold players
    unsold_entries = []
    for up in unsold_players:
        u_name = up.get('player_name', 'Unknown') if isinstance(up, dict) else str(up)
        u_id = up.get('player_id', '') if isinstance(up, dict) else ''
        u_tag = f"<a href='tg://user?id={u_id}'>{html.escape(u_name)}</a>" if u_id else html.escape(u_name)
        base = up.get('base_price', 0) if isinstance(up, dict) else 0
        unsold_entries.append(f"┃ 🔴 {u_tag} (Base: {base} 🪙)\n")

    pages = []
    PAGE_LIMIT = 3500

    # Page builder helper
    def new_page_base(page_num):
        return (
            f"📊 <b>AUCTION SUMMARY</b>\n"
            f"─────────────────\n"
        )

    current = header + team_block
    # Add sold section header
    current += f"╭━━ ✅ SOLD PLAYERS ({sold_count}) ━━━━━━━━━━━━━━━\n"
    if not sold_entries:
        current += "┃ <i>No players sold yet.</i>\n"
    for entry in sold_entries:
        if len(current) + len(entry) > PAGE_LIMIT:
            pages.append(current + "╰━━━━━━━━━━━━━━━━━━━━━━━━━━")
            current = new_page_base(len(pages) + 1) + f"╭━━ ✅ SOLD (continued) ━━━━━━━━━━━━━━━\n"
        current += entry
    current += "╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n"

    # Add unsold section
    current += f"╭━━ ❌ UNSOLD PLAYERS ({unsold_count}) ━━━━━━\n"
    if not unsold_entries:
        current += "┃ <i>No unsold players.</i>\n"
    for entry in unsold_entries:
        if len(current) + len(entry) > PAGE_LIMIT:
            pages.append(current + "╰━━━━━━━━━━━━━━━━━━━━━━━━━━")
            current = new_page_base(len(pages) + 1) + f"╭━━ ❌ UNSOLD (continued) ━━━━━━\n"
        current += entry
    current += "╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n"

    # Remaining pool list
    if remaining:
        rem_line = "⏳ <b>Remaining Pool:</b> " + ", ".join(html.escape(rp.get('player_name','?')) for rp in remaining)
        if len(current) + len(rem_line) + 5 > PAGE_LIMIT:
            pages.append(current)
            current = new_page_base(len(pages) + 1)
        current += "\n" + rem_line

    pages.append(current)
    return pages


def _auction_list_keyboard(chat_id: int, page_idx: int, total_pages: int) -> InlineKeyboardMarkup:
    """Prev / page indicator / Next keyboard for auction summary."""
    nav = []
    if page_idx > 0:
        nav.append(InlineKeyboardButton("⬅️ Prev", callback_data=f"auclist_{chat_id}_{page_idx - 1}"))
    nav.append(InlineKeyboardButton(f"📄 {page_idx + 1}/{total_pages}", callback_data="noop"))
    if page_idx < total_pages - 1:
        nav.append(InlineKeyboardButton("Next ➡️", callback_data=f"auclist_{chat_id}_{page_idx + 1}"))
    close = [InlineKeyboardButton("❌ Close", callback_data="auclist_close")]
    return InlineKeyboardMarkup([nav, close])


async def auclist_page_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle Prev/Next for auction summary pagination."""
    query = update.callback_query
    await query.answer()
    try:
        # Format: auclist_{chat_id}_{page_idx}
        data = query.data[len("auclist_"):]  # "{chat_id}_{page_idx}"
        last_us = data.rfind("_")
        chat_id = int(data[:last_us])
        page_idx = int(data[last_us + 1:])
    except (IndexError, ValueError):
        return

    if chat_id not in active_auctions:
        await query.answer("Auction ended!", show_alert=True)
        return

    auction = active_auctions[chat_id]
    pages = _build_auction_summary_pages(auction)
    total_pages = len(pages)

    if page_idx < 0 or page_idx >= total_pages:
        await query.answer("Invalid page!", show_alert=True)
        return

    page_text = pages[page_idx] + f"\n\n<i>Page {page_idx + 1} of {total_pages}</i>"
    kb = _auction_list_keyboard(chat_id, page_idx, total_pages)
    try:
        await query.edit_message_text(page_text, parse_mode=ParseMode.HTML, reply_markup=kb, disable_web_page_preview=True)
    except Exception as e:
        logger.error(f"auclist_page_callback error: {e}")


async def auclist_close_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Close/delete auction summary message."""
    query = update.callback_query
    await query.answer()
    try:
        await query.message.delete()
    except Exception:
        try:
            await query.edit_message_reply_markup(reply_markup=None)
        except Exception:
            pass


