def _lb_query(metric: str, offset: int = 0, page_size: int = 10):
    """Fetch leaderboard data for a metric with pagination"""
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()
    rows = []
    title = ""

    if metric == "runs":
        c.execute("""
            SELECT user_id, first_name,
                   (COALESCE(total_runs,0) + COALESCE(team_total_runs,0)) AS tr,
                   (COALESCE(matches_played,0) + COALESCE(team_matches_played,0)) AS mp
            FROM user_stats
            WHERE (COALESCE(total_runs,0) + COALESCE(team_total_runs,0)) > 0
            ORDER BY tr DESC
        """)
        all_rows = c.fetchall()
        title = "🏃 TOP RUN SCORERS → ALL TIME"
        total = len(all_rows)
        rows = all_rows[offset:offset+page_size]
    elif metric == "wickets":
        c.execute("""
            SELECT user_id, first_name,
                   (COALESCE(total_wickets,0) + COALESCE(team_total_wickets,0)) AS tw
            FROM user_stats
            WHERE (COALESCE(total_wickets,0) + COALESCE(team_total_wickets,0)) > 0
            ORDER BY tw DESC
        """)
        all_rows = c.fetchall()
        title = "⚾ TOP WICKET TAKERS → ALL TIME"
        total = len(all_rows)
        rows = all_rows[offset:offset+page_size]
    elif metric == "wins":
        c.execute("""
            SELECT user_id, first_name,
                   (COALESCE(matches_won,0) + COALESCE(team_matches_won,0)) AS tw,
                   (COALESCE(matches_played,0) + COALESCE(team_matches_played,0)) AS tp
            FROM user_stats
            WHERE (COALESCE(matches_won,0) + COALESCE(team_matches_won,0)) > 0
            ORDER BY tw DESC
        """)
        all_rows = c.fetchall()
        title = "🏆 MOST MATCH WINS"
        total = len(all_rows)
        rows = all_rows[offset:offset+page_size]
    elif metric == "winrate":
        c.execute("""
            SELECT user_id, first_name,
                   (COALESCE(matches_won,0) + COALESCE(team_matches_won,0)) AS tw,
                   (COALESCE(matches_played,0) + COALESCE(team_matches_played,0)) AS tp
            FROM user_stats
            WHERE (COALESCE(matches_played,0) + COALESCE(team_matches_played,0)) >= 5
            ORDER BY CAST(tw AS REAL)/tp DESC
        """)
        all_rows = c.fetchall()
        title = "🎯 BEST WIN RATE (min 5 matches)"
        total = len(all_rows)
        rows = all_rows[offset:offset+page_size]
    elif metric == "sixes":
        c.execute("""
            SELECT user_id, first_name,
                   (COALESCE(total_sixes,0) + COALESCE(team_total_sixes,0)) AS ts
            FROM user_stats
            WHERE (COALESCE(total_sixes,0) + COALESCE(team_total_sixes,0)) > 0
            ORDER BY ts DESC
        """)
        all_rows = c.fetchall()
        title = "🚀 MOST SIXES HIT"
        total = len(all_rows)
        rows = all_rows[offset:offset+page_size]
    elif metric == "mom":
        c.execute("""
            SELECT user_id, first_name, COALESCE(player_of_match_count,0) AS mom
            FROM user_stats
            WHERE COALESCE(player_of_match_count,0) > 0
            ORDER BY mom DESC
        """)
        all_rows = c.fetchall()
        title = "🌟 MOST MAN OF MATCH AWARDS"
        total = len(all_rows)
        rows = all_rows[offset:offset+page_size]
    else:
        total = 0

    conn.close()
    return title, rows, total


async def leaderboard_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle leaderboard tab buttons with pagination - show only Back after selection"""
    query = update.callback_query
    await query.answer()
    data = query.data.replace("lb_", "")

    # Back button → restore main leaderboard menu
    if data == "back":
        main_text  = "🏆 <b>CRICOVERSE GLOBAL LEADERBOARD</b>\n"
        main_text += "─────────────────\n"
        main_text += "🌍 Stats across <b>all groups</b> · All time\n"
        main_text += "─────────────────\n"
        main_text += "👇 <i>Choose a category to view rankings:</i>"
        main_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🏃 Top Runs",    callback_data="lb_runs_0"),
             InlineKeyboardButton("⚾ Top Wickets", callback_data="lb_wickets_0")],
            [InlineKeyboardButton("🏆 Most Wins",   callback_data="lb_wins_0"),
             InlineKeyboardButton("🎯 Win Rate",    callback_data="lb_winrate_0")],
            [InlineKeyboardButton("🚀 Most Sixes",  callback_data="lb_sixes_0"),
             InlineKeyboardButton("🌟 MOM Awards",  callback_data="lb_mom_0")],
        ])
        try:
            await query.edit_message_caption(caption=main_text, parse_mode=ParseMode.HTML, reply_markup=main_kb)
        except:
            await query.edit_message_text(main_text, parse_mode=ParseMode.HTML, reply_markup=main_kb)
        return

    parts = data.rsplit("_", 1)
    if len(parts) == 2 and parts[1].isdigit():
        metric = parts[0]
        offset = int(parts[1])
    else:
        metric = data
        offset = 0

    PAGE_SIZE = 10
    title, rows, total = _lb_query(metric, offset, PAGE_SIZE)

    medals = ["🥇","🥈","🥉","4️⃣","5️⃣","6️⃣","7️⃣","8️⃣","9️⃣","🔟"]
    lines = []

    if metric == "runs":
        for i, row in enumerate(rows):
            uid, name, tr, mp = row
            rank = offset + i + 1
            avg = round(tr/max(mp,1),1)
            medal = medals[i] if offset == 0 and i < 10 else f"<b>#{rank}</b>"
            lines.append(f"{medal} <a href='tg://user?id={uid}'>{html.escape(name or 'Player')}</a>  {tr} runs  avg {avg}")
    elif metric == "wickets":
        for i, row in enumerate(rows):
            uid, name, tw = row
            rank = offset + i + 1
            medal = medals[i] if offset == 0 and i < 10 else f"<b>#{rank}</b>"
            lines.append(f"{medal} <a href='tg://user?id={uid}'>{html.escape(name or 'Player')}</a>  {tw} wkts")
    elif metric == "wins":
        for i, row in enumerate(rows):
            uid, name, tw, tp = row
            rank = offset + i + 1
            medal = medals[i] if offset == 0 and i < 10 else f"<b>#{rank}</b>"
            lines.append(f"{medal} <a href='tg://user?id={uid}'>{html.escape(name or 'Player')}</a>  {tw}W / {tp} played")
    elif metric == "winrate":
        for i, row in enumerate(rows):
            uid, name, tw, tp = row
            rank = offset + i + 1
            wr = round(tw/max(tp,1)*100,1)
            medal = medals[i] if offset == 0 and i < 10 else f"<b>#{rank}</b>"
            lines.append(f"{medal} <a href='tg://user?id={uid}'>{html.escape(name or 'Player')}</a>  {wr}%  ({tw}/{tp})")
    elif metric == "sixes":
        for i, row in enumerate(rows):
            uid, name, ts = row
            rank = offset + i + 1
            medal = medals[i] if offset == 0 and i < 10 else f"<b>#{rank}</b>"
            lines.append(f"{medal} <a href='tg://user?id={uid}'>{html.escape(name or 'Player')}</a>  {ts} 🚀")
    elif metric == "mom":
        for i, row in enumerate(rows):
            uid, name, mom = row
            rank = offset + i + 1
            medal = medals[i] if offset == 0 and i < 10 else f"<b>#{rank}</b>"
            lines.append(f"{medal} <a href='tg://user?id={uid}'>{html.escape(name or 'Player')}</a>  {mom} 🌟")

    text  = f"🏆 <b>{title}</b>\n"
    text += "─────────────────\n"
    if total > 0:
        text += f"📊 #{offset+1}–#{min(offset+PAGE_SIZE, total)} of {total} players\n"
    text += "─────────────────\n\n"
    if lines:
        text += "\n".join(lines)
    else:
        text += "<i>No data yet → play some matches! 🏏</i>"
    text += "\n\n─────────────────"

    # Only show Prev/Next navigation + Back (NO category tabs)
    bottom_row = []
    if offset > 0:
        bottom_row.append(InlineKeyboardButton("◀️ Prev", callback_data=f"lb_{metric}_{max(0,offset-PAGE_SIZE)}"))
    if offset + PAGE_SIZE < total:
        bottom_row.append(InlineKeyboardButton("▶️ Next", callback_data=f"lb_{metric}_{offset+PAGE_SIZE}"))

    kb_rows = []
    if bottom_row:
        kb_rows.append(bottom_row)
    kb_rows.append([InlineKeyboardButton("🔙 Back", callback_data="lb_back")])
    kb = InlineKeyboardMarkup(kb_rows)

    try:
        await query.edit_message_caption(caption=text, parse_mode=ParseMode.HTML, reply_markup=kb)
    except:
        try:
            await query.edit_message_text(text, parse_mode=ParseMode.HTML, reply_markup=kb)
        except Exception:
            await query.message.reply_text(text, parse_mode=ParseMode.HTML, reply_markup=kb)



# ═══════════════════════════════════════════════════════════════
# CLONE BOT SYSTEM → Owner Only
# Each clone = separate subprocess with its own DB files
# ═══════════════════════════════════════════════════════════════

def _save_clone_bots_meta():
    """Persist clone metadata to disk so it survives restarts."""
    try:
        saveable = {}
        for token, info in CLONE_BOTS.items():
            saveable[token] = {k: v for k, v in info.items() if k != "process"}
        with open(CLONE_BOTS_FILE, "w") as f:
            json.dump(saveable, f, indent=2)
    except Exception as e:
        logger.error(f"Failed to save clone meta: {e}")


def _load_clone_bots_meta():
    """Load persisted clone metadata on startup."""
    global CLONE_BOTS
    try:
        if os.path.exists(CLONE_BOTS_FILE):
            with open(CLONE_BOTS_FILE, "r") as f:
                data = json.load(f)
            for token, info in data.items():
                info["process"] = None  # process handle not persisted
                CLONE_BOTS[token] = info
            logger.info(f"✅ Loaded {len(CLONE_BOTS)} clone bot entries")
    except Exception as e:
        logger.error(f"Failed to load clone meta: {e}")


def _generate_clone_script(token: str, clone_id: str) -> str:
    """
    Read the current bot script and return a modified version:
    - BOT_TOKEN replaced with clone token
    - DB_PATH and TOURNAMENT_DB_PATH use clone-specific filenames
    - CLONE_BOTS system disabled (clones cannot create sub-clones)
    - OWNER_ID kept same (so owner still has full control)
    """
    script_path = os.path.abspath(__file__)
    with open(script_path, "r", encoding="utf-8") as f:
        source = f.read()

    # Replace token
    source = source.replace(
        f'BOT_TOKEN = "{BOT_TOKEN}"',
        f'BOT_TOKEN = "{token}"  # CLONE BOT → DO NOT EDIT'
    )

    # Replace DB paths with clone-specific ones
    source = source.replace(
        f'DB_PATH = "resume1.db"',
        f'DB_PATH = "clone_{clone_id}_main.db"'
    )
    source = source.replace(
        f'TOURNAMENT_DB_PATH = "tournament.db"',
        f'TOURNAMENT_DB_PATH = "clone_{clone_id}_tournament.db"'
    )

    # Replace clone bots file so sub-clones don't share parent's file
    source = source.replace(
        f'CLONE_BOTS_FILE = "clone_bots.json"',
        f'CLONE_BOTS_FILE = "clone_{clone_id}_clones.json"'
    )

    return source


def _launch_clone_process(token: str, clone_id: str, script_path: str) -> "subprocess.Popen | None":
    """Launch the clone script as a separate subprocess."""
    import subprocess
    import sys
    try:
        proc = subprocess.Popen(
            [sys.executable, script_path],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            start_new_session=True  # detach from parent process group
        )
        logger.info(f"🤖 Clone {clone_id} launched as PID {proc.pid}")
        return proc
    except Exception as e:
        logger.error(f"Failed to launch clone {clone_id}: {e}")
        return None


async def clone_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /clone <bot_token>
    Owner only → Generates a full copy of this bot with the given token,
    runs it as a separate process with its own databases. Valid for 1 month.
    """
    user = update.effective_user
    if user.id != OWNER_ID:
        # Silently ignore for non-owners
        return

    if not context.args:
        # Count active clones
        active_count = len(CLONE_BOTS)
        lines = []
        for tok, info in CLONE_BOTS.items():
            uname = info.get("bot_username", "?")
            exp = info.get("expires_at", "")[:10]
            pid = info.get("pid")
            status = "🟢 Running" if (pid and _is_pid_alive(pid)) else "🔴 Stopped"
            lines.append(f"• @{uname} → expires {exp} → {status}")

        text = (
            f"🤖 <b>CLONE BOT SYSTEM</b>\n"
            f"─────────────────\n\n"
            f"<b>Usage:</b> <code>/clone [bot_token]</code>\n\n"
            f"Creates a 100% identical copy of CricoVerse running under a different bot token.\n"
            f"Each clone has its own database and runs for <b>1 month</b>.\n\n"
            f"📊 <b>Active clones: {active_count}</b>\n"
        )
        if lines:
            text += "\n".join(lines)
        await update.message.reply_text(text, parse_mode=ParseMode.HTML)
        return

    token = context.args[0].strip()

    if ":" not in token or len(token) < 30:
        await update.message.reply_text("❌ Invalid bot token format!")
        return

    # Already running?
    if token in CLONE_BOTS:
        info = CLONE_BOTS[token]
        expires = info.get("expires_at", "")[:10]
        pid = info.get("pid")
        alive = _is_pid_alive(pid) if pid else False
        status = "🟢 Running" if alive else "🔴 Process died (restarting...)"
        if not alive:
            # Try to restart
            clone_id = info.get("clone_id", token[:8])
            script_path = info.get("script_path", "")
            if script_path and os.path.exists(script_path):
                proc = _launch_clone_process(token, clone_id, script_path)
                if proc:
                    CLONE_BOTS[token]["pid"] = proc.pid
                    _save_clone_bots_meta()
                    await update.message.reply_text(
                        f"♻️ Clone @{info.get('bot_username')} restarted (PID {proc.pid})\n"
                        f"📅 Still expires: {expires}",
                        parse_mode=ParseMode.HTML
                    )
                    return
        await update.message.reply_text(
            f"⚠️ Clone already exists for this token\n"
            f"🤖 @{info.get('bot_username', '?')} → {status}\n"
            f"📅 Expires: {expires}",
            parse_mode=ParseMode.HTML
        )
        return

    # Verify token
    status_msg = await update.message.reply_text("⏳ Verifying token...")
    try:
        import aiohttp as _aiohttp
        _conn = _aiohttp.TCPConnector(ssl=False)
        async with _aiohttp.ClientSession(connector=_conn) as _sess:
            async with _sess.get(
                f"https://api.telegram.org/bot{token}/getMe",
                timeout=_aiohttp.ClientTimeout(total=12)
            ) as _resp:
                _data = await _resp.json()
        if not _data.get("ok"):
            await status_msg.edit_text("❌ Invalid bot token → Telegram rejected it!")
            return
        bot_username = _data["result"].get("username", "Unknown")
        bot_name = _data["result"].get("first_name", "Clone")
    except Exception as e:
        await status_msg.edit_text(f"❌ Could not verify token: {e}")
        return

    await status_msg.edit_text("⚙️ Generating clone script...")

    # Generate unique clone ID
    clone_id = token.split(":")[0]  # use bot ID part as clone_id

    # Generate and write clone script
    clone_script_path = os.path.join(
        os.path.dirname(os.path.abspath(__file__)),
        f"clone_{clone_id}.py"
    )
    try:
        clone_source = await asyncio.to_thread(_generate_clone_script, token, clone_id)
        with open(clone_script_path, "w", encoding="utf-8") as f:
            f.write(clone_source)
    except Exception as e:
        await status_msg.edit_text(f"❌ Failed to generate clone script: {e}")
        return

    await status_msg.edit_text("🚀 Launching clone process...")

    # Launch subprocess
    proc = await asyncio.to_thread(_launch_clone_process, token, clone_id, clone_script_path)
    if not proc:
        await status_msg.edit_text("❌ Failed to launch clone process. Check server logs.")
        return

    expires_at = (datetime.now() + timedelta(days=30)).isoformat()
    expiry_date = (datetime.now() + timedelta(days=30)).strftime("%d %b %Y")

    CLONE_BOTS[token] = {
        "clone_id": clone_id,
        "bot_username": bot_username,
        "bot_name": bot_name,
        "expires_at": expires_at,
        "reminder_sent": False,
        "groups": [],
        "pid": proc.pid,
        "script_path": clone_script_path,
    }
    _save_clone_bots_meta()

    await status_msg.edit_text(
        f"✅ <b>CLONE BOT LAUNCHED!</b>\n"
        f"─────────────────\n"
        f"🤖 <b>Bot:</b> @{bot_username} ({bot_name})\n"
        f"🆔 <b>PID:</b> <code>{proc.pid}</code>\n"
        f"📅 <b>Valid until:</b> {expiry_date}\n\n"
        f"✅ Running as a separate process with its own database.\n"
        f"⚠️ Auto-shutdown in 1 month. Reminder sent 1 day before.\n"
        f"─────────────────",
        parse_mode=ParseMode.HTML
    )

    try:
        await context.bot.send_message(
            chat_id=SUPPORT_GROUP_ID,
            text=(
                f"🤖 <b>NEW CLONE BOT LAUNCHED</b>\n"
                f"🤖 @{bot_username} | PID: {proc.pid}\n"
                f"📅 Expires: {expiry_date}"
            ),
            parse_mode=ParseMode.HTML
        )
    except:
        pass


def _is_pid_alive(pid: int) -> bool:
    """Check if a process with given PID is still running."""
    import subprocess
    try:
        import os as _os
        _os.kill(pid, 0)
        return True
    except (OSError, ProcessLookupError):
        return False


async def clone_expiry_checker_job(context: ContextTypes.DEFAULT_TYPE):
    """Daily job: remind owner 1 day before clone expiry, kill expired clones."""
    try:
        now = datetime.now()
        to_remove = []

        for token, info in list(CLONE_BOTS.items()):
            expires_at_str = info.get("expires_at")
            if not expires_at_str:
                continue
            try:
                expires_at = datetime.fromisoformat(expires_at_str)
            except:
                continue

            days_left = (expires_at - now).days
            bot_username = info.get("bot_username", "Unknown")
            expiry_str = expires_at.strftime("%d %b %Y")
            pid = info.get("pid")

            # ── 1 day reminder ──
            if days_left == 1 and not info.get("reminder_sent"):
                info["reminder_sent"] = True
                _save_clone_bots_meta()

                try:
                    await context.bot.send_message(
                        chat_id=OWNER_ID,
                        text=(
                            f"⚠️ <b>CLONE BOT EXPIRING TOMORROW!</b>\n"
                            f"─────────────────\n"
                            f"🤖 @{bot_username}\n"
                            f"📅 Expires: {expiry_str}\n\n"
                            f"Use <code>/clone [new_token]</code> to create a fresh clone."
                        ),
                        parse_mode=ParseMode.HTML
                    )
                except Exception as e:
                    logger.error(f"Clone reminder DM failed: {e}")

                for gid in info.get("groups", []):
                    try:
                        await context.bot.send_message(
                            chat_id=gid,
                            text=(
                                f"⚠️ <b>BOT GOING OFFLINE IN 1 DAY!</b>\n"
                                f"─────────────────\n"
                                f"This bot (@{bot_username}) will stop working in <b>1 day</b>.\n"
                                f"Please discuss with the owner to continue using this bot.\n"
                                f"─────────────────"
                            ),
                            parse_mode=ParseMode.HTML
                        )
                    except:
                        pass

            # ── Auto-kill expired clones ──
            elif days_left < 0:
                to_remove.append(token)

                # Kill the subprocess
                if pid and _is_pid_alive(pid):
                    try:
                        import os as _os
                        import signal as _sig
                        _os.kill(pid, _sig.SIGTERM)
                        logger.info(f"🛑 Sent SIGTERM to clone PID {pid} (@{bot_username})")
                    except Exception as e:
                        logger.error(f"Failed to kill clone PID {pid}: {e}")

                # Remove clone script
                script_path = info.get("script_path", "")
                if script_path and os.path.exists(script_path):
                    try:
                        os.remove(script_path)
                    except:
                        pass

                # Notify groups
                for gid in info.get("groups", []):
                    try:
                        await context.bot.send_message(
                            chat_id=gid,
                            text=(
                                f"🛑 <b>BOT HAS GONE OFFLINE</b>\n"
                                f"─────────────────\n"
                                f"This bot's authorization has expired.\n"
                                f"Contact the owner to restore access.\n"
                                f"─────────────────"
                            ),
                            parse_mode=ParseMode.HTML
                        )
                    except:
                        pass

                try:
                    await context.bot.send_message(
                        chat_id=OWNER_ID,
                        text=f"🛑 Clone @{bot_username} (PID {pid}) auto-stopped → 1 month expired.",
                        parse_mode=ParseMode.HTML
                    )
                except:
                    pass

                logger.info(f"🛑 Auto-stopped clone @{bot_username} - expired")

        for token in to_remove:
            CLONE_BOTS.pop(token, None)

        if to_remove:
            _save_clone_bots_meta()

    except Exception as e:
        logger.error(f"Clone expiry checker error: {e}")




# ═══════════════════════════════════════════════════════════════
# SPAM TRACKER → per-user, per-group rate limiting
# ═══════════════════════════════════════════════════════════════
_spam_tracker: Dict[str, float] = {}   # key = f"{user_id}:{group_id}"
_SPAM_WINDOW = 1.5   # seconds → min gap between game-related commands

def _is_spamming(user_id: int, group_id: int) -> bool:
    key = f"{user_id}:{group_id}"
    now = time.time()
    last = _spam_tracker.get(key, 0.0)
    if now - last < _SPAM_WINDOW:
        return True
    _spam_tracker[key] = now
    return False

# ═══════════════════════════════════════════════════════════════
# BATTING / BOWLING QUEUE  (/qbatting, /qbowling)
# ═══════════════════════════════════════════════════════════════
# queue: {group_id: {"batting": [user_id, ...], "bowling": [user_id, ...]}}
_selection_queues: Dict[int, Dict[str, list]] = defaultdict(lambda: {"batting": [], "bowling": []})

def _get_queue(group_id: int, kind: str) -> list:
    return _selection_queues[group_id][kind]

def _clear_queue(group_id: int, kind: str):
    _selection_queues[group_id][kind].clear()

async def qbatting_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Queue a batsman for next wicket: /qbatting [serial]  (captain or host, max 3)"""
    chat = update.effective_chat
    user = update.effective_user
    if chat.type == "private":
        return
    if chat.id not in active_matches:
        await update.message.reply_text("🚫 No active match in this group!", parse_mode=ParseMode.HTML)
        return
    match = active_matches[chat.id]
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        await update.message.reply_text("⏳ Match is not in progress yet!", parse_mode=ParseMode.HTML)
        return
    bat_team = match.current_batting_team
    if bat_team is None:
        await update.message.reply_text("⚠️ Batting team not set yet. Wait for toss!", parse_mode=ParseMode.HTML)
        return
    # Allow batting captain OR host
    is_captain = bool(bat_team.captain_id and user.id == bat_team.captain_id)
    is_host = (user.id == match.host_id)
    if not is_captain and not is_host:
        m = await update.message.reply_text("🚫 Only the batting captain or host can queue batsmen!", parse_mode=ParseMode.HTML)
        asyncio.create_task(_auto_delete(context, chat.id, m.message_id, 5))
        return
    if not context.args:
        # Show current queue status
        q = _get_queue(chat.id, "batting")
        queue_display = ""
        if q:
            names = [bat_team.get_player(uid).first_name for uid in q if bat_team.get_player(uid)]
            queue_display = f"\n📋 <b>Current Queue:</b> {', '.join(names)}"
        await update.message.reply_text(
            f"🏏 <b>BATTING QUEUE</b>\n"
            f"─────────────────\n"
            f"ℹ️ <b>Usage:</b> <code>/qbatting [serial]</code>\n"
            f"Pre-queue next batsman (up to 3){queue_display}\n\n"
            f"📊 Use /players to see serial numbers.",
            parse_mode=ParseMode.HTML
        )
        return
    try:
        serial = int(context.args[0])
    except ValueError:
        await update.message.reply_text("❌ Invalid serial number. Use: <code>/qbatting [number]</code>", parse_mode=ParseMode.HTML)
        return
    player = bat_team.get_player_by_serial(serial)
    if not player:
        await update.message.reply_text(f"🚫 No player with serial #{serial}. Use /players to see the list.")
        return
    if player.is_out:
        await update.message.reply_text(f"💀 <b>{player.first_name}</b> is already OUT! Pick another.", parse_mode=ParseMode.HTML)
        return
    q = _get_queue(chat.id, "batting")
    if player.user_id in q:
        await update.message.reply_text(f"⚠️ <b>{player.first_name}</b> is already in the queue.", parse_mode=ParseMode.HTML)
        return
    if len(q) >= 3:
        await update.message.reply_text("🚫 Queue is full (max 3). Remove someone first with /qbatting clear.", parse_mode=ParseMode.HTML)
        return

    # ✅ FIX 2: Show confirmation button before adding
    keyboard = InlineKeyboardMarkup([
        [
            InlineKeyboardButton(f"✅ Confirm → {player.first_name}", callback_data=f"qbat_confirm_{chat.id}_{player.user_id}_{serial}"),
            InlineKeyboardButton("❌ Cancel", callback_data=f"qbat_cancel_{chat.id}")
        ]
    ])
    await update.message.reply_text(
        f"🏏 <b>QUEUE BATSMAN → CONFIRM</b>\n"
        f"─────────────────\n"
        f"👤 <b>Player:</b> {player.first_name} (#{serial})\n"
        f"📋 <b>Queue Position:</b> #{len(q) + 1}\n\n"
        f"👇 Confirm to add to batting queue:",
        parse_mode=ParseMode.HTML,
        reply_markup=keyboard
    )

async def qbatting_confirm_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle qbatting confirmation"""
    query = update.callback_query
    await query.answer()
    user = query.from_user
    parts = query.data.split("_")

    if query.data.startswith("qbat_cancel_"):
        await query.message.edit_text("❌ <b>Queue cancelled.</b>", parse_mode=ParseMode.HTML)
        return

    if query.data.startswith("qbat_confirm_"):
        try:
            group_id = int(parts[2])
            player_uid = int(parts[3])
            serial = int(parts[4])
        except (IndexError, ValueError):
            await query.answer("❌ Invalid data.", show_alert=True)
            return

        if group_id not in active_matches:
            await query.message.edit_text("❌ No active match.", parse_mode=ParseMode.HTML)
            return

        match = active_matches[group_id]
        bat_team = match.current_batting_team

        # Batting captain or host can confirm
        is_captain = bool(bat_team.captain_id and user.id == bat_team.captain_id)
        is_host = (user.id == match.host_id)
        if not is_captain and not is_host:
            await query.answer("🚫 Only the batting captain or host can confirm!", show_alert=True)
            return

        player = bat_team.get_player(player_uid)
        if not player:
            await query.message.edit_text("🚫 Player not found in team.", parse_mode=ParseMode.HTML)
            return
        if player.is_out:
            await query.message.edit_text(f"💀 {player.first_name} is already OUT!", parse_mode=ParseMode.HTML)
            return

        q = _get_queue(group_id, "batting")
        if player_uid in q:
            await query.message.edit_text(f"⚠️ {player.first_name} is already in the queue.", parse_mode=ParseMode.HTML)
            return
        if len(q) >= 3:
            await query.message.edit_text("🚫 Queue is full (max 3).", parse_mode=ParseMode.HTML)
            return

        q.append(player_uid)
        pos = len(q)
        queue_names = [bat_team.get_player(uid).first_name for uid in q if bat_team.get_player(uid)]

        await query.message.edit_text(
            f"✅ <b>BATTING QUEUE UPDATED!</b>\n"
            f"─────────────────\n"
            f"🏏 <b>{player.first_name}</b> added at position #{pos}\n"
            f"📋 <b>Queue:</b> {' → '.join(queue_names)}\n\n"
            f"<i>Next wicket, this batsman walks in automatically!</i>",
            parse_mode=ParseMode.HTML
        )



async def qbowling_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Queue a bowler for next over: /qbowling [serial]  (bowling captain only, max 3)"""
    chat = update.effective_chat
    user = update.effective_user
    if chat.type == "private":
        return
    if chat.id not in active_matches:
        return
    match = active_matches[chat.id]
    if match.phase != GamePhase.MATCH_IN_PROGRESS:
        return
    bowl_team = match.current_bowling_team
    if user.id != bowl_team.captain_id:
        m = await update.message.reply_text("🚫 Only the bowling captain can queue bowlers!", parse_mode=ParseMode.HTML)
        asyncio.create_task(_auto_delete(context, chat.id, m.message_id, 5))
        return
    if not context.args:
        q = _get_queue(chat.id, "bowling")
        queue_display = ""
        if q:
            names = [bowl_team.get_player(uid).first_name for uid in q if bowl_team.get_player(uid)]
            queue_display = f"\n📋 <b>Current Queue:</b> {', '.join(names)}"
        await update.message.reply_text(
            f"⚾ <b>BOWLING QUEUE</b>\n"
            f"─────────────────\n"
            f"ℹ️ <b>Usage:</b> <code>/qbowling [serial]</code>\n"
            f"Pre-queue next bowler (up to 3){queue_display}\n\n"
            f"📊 Use /players to see serial numbers.",
            parse_mode=ParseMode.HTML
        )
        return
    try:
        serial = int(context.args[0])
    except ValueError:
        await update.message.reply_text("❌ Invalid serial number. Use: <code>/qbowling [number]</code>", parse_mode=ParseMode.HTML)
        return
    player = bowl_team.get_player_by_serial(serial)
    if not player:
        await update.message.reply_text(f"🚫 No player with serial #{serial}. Use /players to see the list.")
        return
    if player.is_bowling_banned:
        await update.message.reply_text(f"🚫 <b>{player.first_name}</b> is banned from bowling this match!", parse_mode=ParseMode.HTML)
        return
    q = _get_queue(chat.id, "bowling")
    if player.user_id in q:
        await update.message.reply_text(f"⚠️ <b>{player.first_name}</b> is already in the bowling queue.", parse_mode=ParseMode.HTML)
        return
    if len(q) >= 3:
        await update.message.reply_text("🚫 Bowling queue is full (max 3).", parse_mode=ParseMode.HTML)
        return

    # ✅ FIX 2: Show confirmation button
    keyboard = InlineKeyboardMarkup([
        [
            InlineKeyboardButton(f"✅ Confirm → {player.first_name}", callback_data=f"qbowl_confirm_{chat.id}_{player.user_id}_{serial}"),
            InlineKeyboardButton("❌ Cancel", callback_data=f"qbowl_cancel_{chat.id}")
        ]
    ])
    await update.message.reply_text(
        f"⚾ <b>QUEUE BOWLER → CONFIRM</b>\n"
        f"─────────────────\n"
        f"👤 <b>Player:</b> {player.first_name} (#{serial})\n"
        f"📊 <b>Stats:</b> {player.wickets}W / {player.runs_conceded}R  ({format_overs(player.balls_bowled)} ov)\n"
        f"📋 <b>Queue Position:</b> #{len(q) + 1}\n\n"
        f"👇 Confirm to add to bowling queue:",
        parse_mode=ParseMode.HTML,
        reply_markup=keyboard
    )

async def qbowling_confirm_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle qbowling confirmation"""
    query = update.callback_query
    await query.answer()
    user = query.from_user
    parts = query.data.split("_")

    if query.data.startswith("qbowl_cancel_"):
        await query.message.edit_text("❌ <b>Queue cancelled.</b>", parse_mode=ParseMode.HTML)
        return

    if query.data.startswith("qbowl_confirm_"):
        try:
            group_id = int(parts[2])
            player_uid = int(parts[3])
            serial = int(parts[4])
        except (IndexError, ValueError):
            await query.answer("❌ Invalid data.", show_alert=True)
            return

        if group_id not in active_matches:
            await query.message.edit_text("❌ No active match.", parse_mode=ParseMode.HTML)
            return

        match = active_matches[group_id]
        bowl_team = match.current_bowling_team

        # Only bowling captain can confirm
        if user.id != bowl_team.captain_id:
            await query.answer("🚫 Only the bowling captain can confirm!", show_alert=True)
            return

        player = bowl_team.get_player(player_uid)
        if not player:
            await query.message.edit_text("🚫 Player not found in bowling team.", parse_mode=ParseMode.HTML)
            return
        if player.is_bowling_banned:
            await query.message.edit_text(f"🚫 {player.first_name} is banned from bowling!", parse_mode=ParseMode.HTML)
            return

        q = _get_queue(group_id, "bowling")
        if player_uid in q:
            await query.message.edit_text(f"⚠️ {player.first_name} is already in the queue.", parse_mode=ParseMode.HTML)
            return
        if len(q) >= 3:
            await query.message.edit_text("🚫 Bowling queue is full (max 3).", parse_mode=ParseMode.HTML)
            return

        q.append(player_uid)
        pos = len(q)
        queue_names = [bowl_team.get_player(uid).first_name for uid in q if bowl_team.get_player(uid)]

        await query.message.edit_text(
            f"✅ <b>BOWLING QUEUE UPDATED!</b>\n"
            f"─────────────────\n"
            f"⚾ <b>{player.first_name}</b> added at position #{pos}\n"
            f"📋 <b>Queue:</b> {' → '.join(queue_names)}\n\n"
            f"<i>Next over, this bowler takes the ball automatically!</i>",
            parse_mode=ParseMode.HTML
        )



def _pop_next_batsman(group_id: int, bat_team) -> Optional[int]:
    """Return next queued batsman index, or None."""
    q = _get_queue(group_id, "batting")
    while q:
        uid = q.pop(0)
        for i, p in enumerate(bat_team.players):
            if p.user_id == uid and not p.is_out:
                return i
    return None

def _pop_next_bowler(group_id: int, bowl_team) -> Optional[int]:
    """Return next queued bowler index, or None."""
    q = _get_queue(group_id, "bowling")
    last_idx = bowl_team.bowler_history[-1] if bowl_team.bowler_history else None
    while q:
        uid = q.pop(0)
        for i, p in enumerate(bowl_team.players):
            if p.user_id == uid and not p.is_bowling_banned and i != last_idx:
                return i
    return None

# ═══════════════════════════════════════════════════════════════
# ENDALL COMMAND  → owner only, stops everything in every group
# ═══════════════════════════════════════════════════════════════
async def endall_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """🛑 /endall → bot owner only. Stops ALL active matches AND auctions in every group."""
    user = update.effective_user
    if user.id != OWNER_ID:
        return  # silent ignore

    stopped_matches = 0
    stopped_auctions = 0

    # End all matches
    for gid in list(active_matches.keys()):
        try:
            match = active_matches[gid]
            match.phase = GamePhase.MATCH_ENDED
            for attr in ("ball_timeout_task", "batsman_selection_task",
                         "bowler_selection_task", "join_phase_task"):
                task = getattr(match, attr, None)
                if task:
                    task.cancel()
            try:
                if match.main_message_id:
                    await context.bot.unpin_chat_message(chat_id=gid, message_id=match.main_message_id)
            except Exception:
                pass
            await context.bot.send_message(
                gid,
                "🛑 <b>MATCH ENDED</b> by bot owner.\n<i>All operations have been stopped.</i>",
                parse_mode=ParseMode.HTML
            )
            del active_matches[gid]
            stopped_matches += 1
        except Exception as e:
            logger.error(f"endall match error {gid}: {e}")

    # End all auctions
    for gid in list(active_auctions.keys()):
        try:
            auction = active_auctions[gid]
            auction.phase = AuctionPhase.AUCTION_ENDED
            if auction.bid_timer_task:
                auction.bid_timer_task.cancel()
            await context.bot.send_message(
                gid,
                "🛑 <b>AUCTION ENDED</b> by bot owner.",
                parse_mode=ParseMode.HTML
            )
            del active_auctions[gid]
            stopped_auctions += 1
        except Exception as e:
            logger.error(f"endall auction error {gid}: {e}")

    # Also clear AI matches
    ai_count = len(ai_matches)
    ai_matches.clear()

    await update.message.reply_text(
        f"✅ <b>ENDALL COMPLETE</b>\n"
        f"─────────────────\n"
        f"🏏 Matches stopped: <b>{stopped_matches}</b>\n"
        f"🏦 Auctions stopped: <b>{stopped_auctions}</b>\n"
        f"🤖 AI matches cleared: <b>{ai_count}</b>",
        parse_mode=ParseMode.HTML
    )

# ═══════════════════════════════════════════════════════════════
# SCORECARD WORM GRAPH → paginated inline (Innings 1 / Innings 2)
# ═══════════════════════════════════════════════════════════════
async def scorecard_worm_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle worm graph pagination buttons: scorecard_worm_{group_id}_{innings}"""
    query = update.callback_query
    await query.answer()
    try:
        parts = query.data.split("_")
        group_id = int(parts[2])
        innings_num = int(parts[3])
    except Exception:
        return

    match = active_matches.get(group_id)
    # If match already ended we still have the data in the query message context
    # Rebuild scorecard text from batting_first / second
    if not match:
        await query.answer("Match data not available.", show_alert=True)
        return

    first_innings = match.batting_first
    second_innings = match.get_other_team(first_innings) if first_innings else None

    target_team = first_innings if innings_num == 1 else second_innings
    if not target_team:
        await query.answer("Innings data not found.", show_alert=True)
        return

    try:
        worm_bio = await asyncio.to_thread(generate_worm_graph, match)
    except Exception:
        worm_bio = None

    inn_label = "1st" if innings_num == 1 else "2nd"
    caption = (
        f"📈 <b>WORM GRAPH → {inn_label} Innings</b>\n"
        f"🏏 {target_team.name}: <b>{target_team.score}/{target_team.wickets}</b> "
        f"({format_overs(target_team.balls)} ov)"
    )

    # Toggle button → arrow direction depends on current innings
    other_inn = 2 if innings_num == 1 else 1
    if innings_num == 1:
        nav_label = "➡️ 2nd Innings"
    else:
        nav_label = "⬅️ 1st Innings"
    keyboard = InlineKeyboardMarkup([[
        InlineKeyboardButton(nav_label, callback_data=f"scorecard_worm_{group_id}_{other_inn}")
    ]])

    try:
        if worm_bio:
            media = InputMediaPhoto(media=worm_bio, caption=caption, parse_mode=ParseMode.HTML)
            try:
                await query.message.edit_media(media=media, reply_markup=keyboard)
            except Exception:
                # Fallback: if edit fails (e.g. original was text), send new photo
                await query.message.reply_photo(photo=worm_bio, caption=caption,
                                                parse_mode=ParseMode.HTML, reply_markup=keyboard)
        else:
            try:
                await query.message.edit_text(caption, parse_mode=ParseMode.HTML, reply_markup=keyboard)
            except Exception:
                await query.message.reply_text(caption, parse_mode=ParseMode.HTML, reply_markup=keyboard)
    except Exception as e:
        logger.error(f"Worm pagination error: {e}")


def _cv_wrap(draw, text: str, font, width: int, max_lines: int = 4) -> list:
    words = str(text).split()
    lines, cur = [], ""
    for word in words:
        test = f"{cur} {word}".strip()
        if draw.textlength(test, font=font) <= width:
            cur = test
        else:
            if cur:
                lines.append(cur)
            cur = word
            if len(lines) >= max_lines:
                break
    if cur and len(lines) < max_lines:
        lines.append(cur)
    return lines


def _cv_safe_name(value, limit=18):
    return _clean_display_name(str(value or "Player"), limit).upper()


def _cv_draw_panel(draw, xy, radius, fill, outline=None, width=2):
    draw.rounded_rectangle(xy, radius=radius, fill=fill, outline=outline, width=width)


def generate_worm_graph(match) -> Optional[BytesIO]:
    """Broadcast-style score progression card with clearer axes, live chase context and wicket markers."""
    try:
        import math
        SC = 2
        W, H = 1600 * SC, 900 * SC
        img = Image.new("RGBA", (W, H), (6, 9, 24, 255))
        draw = ImageDraw.Draw(img)

        # Premium dark stadium gradient background
        _draw_multi_gradient_bg(img, [(7, 10, 24), (16, 26, 52), (8, 12, 26)])

        # Subtle grid lines on black
        for x in range(-H, W, 150 * SC):
            draw.line([(x, 0), (x + H, H)], fill=(18, 22, 38, 80), width=2 * SC)

        C_X, C_Y = (52, 185, 255, 255), (255, 83, 130, 255)
        C_GOLD, C_WHITE, C_MUTED = (255, 213, 74, 255), (242, 247, 255, 255), (150, 169, 205, 255)
        C_GRID = (48, 65, 112, 100)
        PAD_L, PAD_R, PAD_T, PAD_B = 130*SC, 90*SC, 185*SC, 150*SC
        CW, CH = W - PAD_L - PAD_R, H - PAD_T - PAD_B

        f_title = _get_font(True, 54*SC)
        f_sub = _get_font(False, 25*SC)
        f_axis = _get_font(False, 22*SC)
        f_bold = _get_font(True, 28*SC)
        f_big = _get_font(True, 44*SC)

        def innings_points(team_name):
            scores, wkts, balls = [0], [False], [0]
            total = 0
            for entry in getattr(match, "ball_by_ball_log", []):
                if entry.get("batting_team") != team_name:
                    continue
                total += int(entry.get("runs", 0) or 0)
                scores.append(total)
                wkts.append(bool(entry.get("is_wicket") or entry.get("wicket")))
                balls.append(len(scores) - 1)
            return scores, wkts, balls

        xs, xw, xb = innings_points(match.team_x.name)
        ys, yw, yb = innings_points(match.team_y.name)
        max_balls = max(getattr(match, "total_overs", 5) * 6, len(xs)-1, len(ys)-1, 1)
        max_score = max(max(xs or [0]), max(ys or [0]), getattr(match.team_x, "score", 0), getattr(match.team_y, "score", 0), 12)
        max_score = int(math.ceil((max_score + 12) / 10.0) * 10)

        # Main glass board
        _cv_draw_panel(draw, [48*SC, 38*SC, W-48*SC, H-42*SC], 34*SC, (10, 16, 38, 232), (58, 78, 138, 255), 2*SC)
        draw.text((82*SC, 64*SC), "SCORE WORM", font=f_title, fill=C_GOLD)
        draw.text((86*SC, 126*SC), f"{match.team_x.name} vs {match.team_y.name}  |  {getattr(match, 'total_overs', 0)} overs", font=f_sub, fill=C_MUTED)

        # Team scores banners
        score_box_w = 310 * SC
        for idx, (team, color, x1) in enumerate([(match.team_x, C_X, W - 725*SC), (match.team_y, C_Y, W - 390*SC)]):
            _cv_draw_panel(draw, [x1, 66*SC, x1+score_box_w, 142*SC], 18*SC, (19, 29, 62, 235), color, 2*SC)
            draw.text((x1+22*SC, 80*SC), _cv_safe_name(team.name, 14), font=f_axis, fill=color)
            draw.text((x1+22*SC, 105*SC), f"{team.score}/{team.wickets} ({format_overs(team.balls)})", font=f_bold, fill=C_WHITE)

        # ── DETAILED AXIS ──
        # Detailed 10 y-grid lines
        for j in range(11):
            val = int(j * max_score / 10)
            y = PAD_T + CH - int(j * CH / 10)
            draw.line([(PAD_L, y), (PAD_L+CW, y)], fill=C_GRID, width=1*SC)
            draw.text((PAD_L-72*SC, y-13*SC), str(val), font=f_axis, fill=C_MUTED)

        # Detailed X-grid lines per Over
        for ov in range(0, getattr(match, "total_overs", 5) + 1):
            ball = ov * 6
            x = PAD_L + int(ball / max_balls * CW)
            draw.line([(x, PAD_T), (x, PAD_T+CH)], fill=(48, 65, 112, 100), width=1*SC)
            draw.text((x-10*SC, PAD_T+CH+24*SC), str(ov), font=f_axis, fill=C_MUTED)

        def px(ball, score):
            return (PAD_L + int(ball / max_balls * CW), PAD_T + CH - int(score / max_score * CH))

        def draw_series(scores, wkts, color, live):
            pts = [px(i, s) for i, s in enumerate(scores)]
            if len(pts) < 2:
                return

            # Draw semi-transparent area fill underneath the curve
            fill_polygon = [(PAD_L, PAD_T + CH)] + pts + [(pts[-1][0], PAD_T + CH)]
            fill_color = tuple(color[:3]) + (35,) # alpha=35
            overlay = Image.new("RGBA", (W, H))
            o_draw = ImageDraw.Draw(overlay)
            o_draw.polygon(fill_polygon, fill=fill_color)
            nonlocal img, draw
            img = Image.alpha_composite(img, overlay)
            draw = ImageDraw.Draw(img)

            # Draw glowing line
            glow = tuple(max(0, c - 115) for c in color[:3]) + (255,)
            for width in [18, 12, 7]:
                draw.line(pts, fill=glow, width=width*SC, joint="curve")
            draw.line(pts, fill=color, width=5*SC, joint="curve")

            if live:
                lx, ly = pts[-1]
                draw.ellipse([lx-18*SC, ly-18*SC, lx+18*SC, ly+18*SC], fill=(20, 25, 45, 255), outline=C_GOLD, width=4*SC)

            # Draw markers
            for i, (x, y) in enumerate(pts[1:], 1):
                run = scores[i] - scores[i-1]
                is_w = wkts[i] if i < len(wkts) else False
                if is_w:
                    draw.ellipse([x-15*SC, y-15*SC, x+15*SC, y+15*SC], fill=(220, 38, 64, 255), outline=C_WHITE, width=2*SC)
                    draw.text((x, y-12*SC), "W", font=f_axis, fill=C_WHITE, anchor="ma")
                elif run == 4:
                    # Draw orange dot for fours
                    draw.ellipse([x-9*SC, y-9*SC, x+9*SC, y+9*SC], fill=(255, 157, 57, 255), outline=C_WHITE, width=1*SC)
                # Note: Run == 6 is deliberately NOT drawn with any marker dot, as requested by the user.

        draw_series(xs, xw, C_X, getattr(match, "current_batting_team", None) == match.team_x)
        draw_series(ys, yw, C_Y, getattr(match, "current_batting_team", None) == match.team_y)

        # Chase details
        if getattr(match, "innings", 1) == 2 and getattr(match, "target", 0):
            bat = getattr(match, "current_batting_team", match.team_y)
            need = max(match.target - bat.score, 0)
            balls_left = max(getattr(match, "total_overs", 0) * 6 - bat.balls, 0)
            chase = f"CHASE: {need} needed from {balls_left} balls"
            _cv_draw_panel(draw, [PAD_L, H-112*SC, PAD_L+520*SC, H-62*SC], 16*SC, (24, 34, 68, 240), C_GOLD, 2*SC)
            draw.text((PAD_L+24*SC, H-99*SC), chase, font=f_bold, fill=C_GOLD)

        draw.text((PAD_L, H-55*SC), f"■ {match.team_x.name}", font=f_bold, fill=C_X)
        draw.text((PAD_L+340*SC, H-55*SC), f"■ {match.team_y.name}", font=f_bold, fill=C_Y)
        draw.text((W-82*SC, H-55*SC), "CRICOVERSE LIVE ANALYTICS", font=f_axis, fill=C_MUTED, anchor="ra")

        final = img.convert("RGB").resize((1600, 900), Image.Resampling.LANCZOS)
        bio = BytesIO()
        final.save(bio, "PNG", optimize=True)
        bio.seek(0)
        return bio
    except Exception as e:
        logger.error(f"Enhanced worm graph error: {e}")
        return None


def generate_over_bar_chart(match) -> Optional[BytesIO]:
    """Enhanced over-by-over card with current-over highlight and wicket chips."""
    try:
        SC = 2
        W, H = 1500*SC, 860*SC
        img = Image.new("RGBA", (W, H), (6, 9, 22, 255))
        draw = ImageDraw.Draw(img)
        # Premium dark stadium gradient background
        _draw_multi_gradient_bg(img, [(6, 9, 22), (16, 25, 48), (8, 12, 24)])


        C_X, C_Y = (53, 185, 255, 255), (255, 80, 132, 255)
        C_GOLD, C_WHITE, C_MUTED = (255, 213, 74, 255), (243, 248, 255, 255), (145, 166, 205, 255)
        PAD_L, PAD_R, PAD_T, PAD_B = 100*SC, 70*SC, 170*SC, 140*SC
        CW, CH = W-PAD_L-PAD_R, H-PAD_T-PAD_B
        f_title, f_sub = _get_font(True, 52*SC), _get_font(False, 25*SC)
        f_bold, f_axis = _get_font(True, 28*SC), _get_font(False, 22*SC)

        _cv_draw_panel(draw, [42*SC, 36*SC, W-42*SC, H-38*SC], 30*SC, (11, 18, 42, 235), (55, 76, 132, 255), 2*SC)
        draw.text((84*SC, 62*SC), "OVER BY OVER", font=f_title, fill=C_GOLD)
        draw.text((88*SC, 124*SC), f"{match.team_x.name} {match.team_x.score}/{match.team_x.wickets}  vs  {match.team_y.name} {match.team_y.score}/{match.team_y.wickets}", font=f_sub, fill=C_MUTED)

        def data(team, runs_attr, wkts_attr):
            runs = list(getattr(match, runs_attr, []))
            wkts = list(getattr(match, wkts_attr, []))
            return runs, wkts + [0] * max(0, len(runs) - len(wkts))

        xr, xw = data(match.team_x, "team_x_over_runs", "team_x_over_wickets")
        yr, yw = data(match.team_y, "team_y_over_runs", "team_y_over_wickets")
        live_team = getattr(match, "current_batting_team", None)
        live_runs = getattr(match, "current_over_runs", 0)
        live_wkts = getattr(match, "current_over_wickets", 0)
        if live_runs or live_wkts:
            if live_team == match.team_x:
                xr, xw = xr + [live_runs], xw + [live_wkts]
            elif live_team == match.team_y:
                yr, yw = yr + [live_runs], yw + [live_wkts]

        n = max(len(xr), len(yr), 1)
        start = max(0, n - 8)
        xr, yr = xr[start:], yr[start:]
        xw, yw = xw[start:], yw[start:]
        n = max(len(xr), len(yr), 1)
        xr += [0] * (n - len(xr)); yr += [0] * (n - len(yr))
        xw += [0] * (n - len(xw)); yw += [0] * (n - len(yw))
        max_runs = max(xr + yr + [8]) + 4

        for j in range(5):
            val = int(j * max_runs / 4)
            y = PAD_T + CH - int(j * CH / 4)
            draw.line([(PAD_L, y), (PAD_L+CW, y)], fill=(48, 65, 112, 150), width=1*SC)
            draw.text((PAD_L-56*SC, y-12*SC), str(val), font=f_axis, fill=C_MUTED)

        slot = CW // n
        bw = int(slot * 0.26)
        base = PAD_T + CH

        def bar(x1, x2, value, wickets, color, live=False):
            bh = max(8*SC, int(value / max_runs * CH))
            y1, y2 = base - bh, base
            fill = (64, 232, 153, 255) if live else color
            draw.rounded_rectangle([x1+5*SC, y1+8*SC, x2+5*SC, y2], radius=10*SC, fill=(0,0,0,80))
            draw.rounded_rectangle([x1, y1, x2, y2], radius=10*SC, fill=fill, outline=(255,255,255,100), width=1*SC)
            draw.text(((x1+x2)//2, y1-35*SC), str(value), font=f_bold, fill=C_WHITE, anchor="ma")
            if wickets:
                draw.ellipse([(x1+x2)//2-17*SC, y1-76*SC, (x1+x2)//2+17*SC, y1-42*SC], fill=(230, 45, 68, 255), outline=C_GOLD, width=2*SC)
                draw.text(((x1+x2)//2, y1-73*SC), str(wickets), font=f_axis, fill=C_WHITE, anchor="ma")

        for i in range(n):
            cx = PAD_L + i*slot + slot//2
            over_no = start + i + 1
            x_live = live_team == match.team_x and i == n-1 and (live_runs or live_wkts)
            y_live = live_team == match.team_y and i == n-1 and (live_runs or live_wkts)
            bar(cx-bw-8*SC, cx-8*SC, xr[i], xw[i], C_X, x_live)
            bar(cx+8*SC, cx+bw+8*SC, yr[i], yw[i], C_Y, y_live)
            label = f"OV {over_no}" + (" LIVE" if x_live or y_live else "")
            draw.text((cx, base+28*SC), label, font=f_axis, fill=C_GOLD if x_live or y_live else C_MUTED, anchor="ma")

        draw.text((PAD_L, H-58*SC), f"■ {match.team_x.name}", font=f_bold, fill=C_X)
        draw.text((PAD_L+330*SC, H-58*SC), f"■ {match.team_y.name}", font=f_bold, fill=C_Y)
        draw.text((W-80*SC, H-58*SC), "Last 8 overs | dots hidden, wickets shown as red chips", font=f_axis, fill=C_MUTED, anchor="ra")
        final = img.convert("RGB").resize((1500, 860), Image.Resampling.LANCZOS)
        bio = BytesIO(); final.save(bio, "PNG", optimize=True); bio.seek(0); return bio
    except Exception as e:
        logger.error(f"Enhanced over chart error: {e}")
        return None


def generate_mid_match_image(match) -> Optional[BytesIO]:
    """Premium mid-match score bug with chase equation, players, and recent balls."""
    try:
        SC = 2
        W, H = 1920*SC, 1080*SC
        img = Image.new("RGBA", (W, H), (6, 9, 24, 255))
        draw = ImageDraw.Draw(img)
        _draw_multi_gradient_bg(img, [(5, 8, 22), (12, 22, 54), (8, 11, 28)])
        for x in range(-H, W, 170*SC):
            draw.line([(x, 0), (x+H, H)], fill=(26, 40, 92, 80), width=2*SC)

        C_GOLD, C_WHITE, C_MUTED = (255, 213, 74, 255), (244, 249, 255, 255), (150, 170, 208, 255)
        C_X, C_Y, C_GREEN, C_RED = (55, 187, 255, 255), (255, 82, 132, 255), (57, 230, 146, 255), (240, 62, 83, 255)
        f_title, f_score = _get_font(True, 72*SC), _get_font(True, 170*SC)
        f_big, f_med, f_sm = _get_font(True, 52*SC), _get_font(True, 34*SC), _get_font(False, 28*SC)
        bat = getattr(match, "current_batting_team", None) or match.team_x
        bowl = getattr(match, "current_bowling_team", None) or match.team_y
        bat_color = C_X if bat == match.team_x else C_Y
        bowl_color = C_Y if bat == match.team_x else C_X

        _cv_draw_panel(draw, [60*SC, 50*SC, W-60*SC, H-55*SC], 38*SC, (11, 17, 39, 232), (58, 80, 140, 255), 2*SC)
        draw.text((100*SC, 82*SC), "LIVE MATCH CENTER", font=f_title, fill=C_GOLD)
        draw.text((W-100*SC, 105*SC), datetime.now().strftime("%H:%M"), font=f_med, fill=C_MUTED, anchor="ra")

        _cv_draw_panel(draw, [100*SC, 190*SC, W//2-35*SC, 575*SC], 32*SC, (16, 25, 58, 238), bat_color, 4*SC)
        draw.text((140*SC, 225*SC), _cv_safe_name(bat.name, 20), font=f_big, fill=bat_color)
        draw.text((135*SC, 285*SC), f"{bat.score}/{bat.wickets}", font=f_score, fill=C_WHITE)
        draw.text((145*SC, 490*SC), f"{format_overs(bat.balls)} OVERS  |  CRR {round(bat.score / max(bat.balls/6, 0.1), 2)}", font=f_med, fill=C_MUTED)

        _cv_draw_panel(draw, [W//2+35*SC, 190*SC, W-100*SC, 575*SC], 32*SC, (14, 21, 49, 228), bowl_color, 3*SC)
        draw.text((W//2+80*SC, 225*SC), _cv_safe_name(bowl.name, 20), font=f_big, fill=bowl_color)
        draw.text((W//2+80*SC, 300*SC), f"{bowl.score}/{bowl.wickets}", font=_get_font(True, 104*SC), fill=C_WHITE)
        if getattr(match, "innings", 1) == 2 and getattr(match, "target", 0):
            need = max(match.target - bat.score, 0)
            balls_left = max(match.total_overs*6 - bat.balls, 0)
            rrr = round(need / max(balls_left/6, 0.1), 2) if need else 0
            draw.text((W//2+80*SC, 440*SC), f"NEED {need} FROM {balls_left}  |  RRR {rrr}", font=f_med, fill=C_GOLD)
        else:
            draw.text((W//2+80*SC, 440*SC), f"PROJECTED {int((bat.score / max(bat.balls, 1)) * match.total_overs * 6)}", font=f_med, fill=C_GOLD)

        y = 625*SC
        _cv_draw_panel(draw, [100*SC, y, W//2-35*SC, y+250*SC], 26*SC, (15, 23, 52, 230), (55, 72, 130, 255), 2*SC)
        _cv_draw_panel(draw, [W//2+35*SC, y, W-100*SC, y+250*SC], 26*SC, (15, 23, 52, 230), (55, 72, 130, 255), 2*SC)
        draw.text((140*SC, y+24*SC), "AT THE CREASE", font=f_med, fill=C_GOLD)
        striker = bat.players[bat.current_batsman_idx] if getattr(bat, "current_batsman_idx", None) is not None else None
        non = bat.players[bat.current_non_striker_idx] if getattr(bat, "current_non_striker_idx", None) is not None else None
        if striker:
            draw.text((140*SC, y+82*SC), f"★ {_cv_safe_name(striker.first_name, 18)}", font=f_big, fill=C_WHITE)
            draw.text((W//2-90*SC, y+86*SC), f"{striker.runs} ({striker.balls_faced})", font=f_big, fill=C_GREEN, anchor="ra")
        if non:
            draw.text((140*SC, y+158*SC), _cv_safe_name(non.first_name, 18), font=f_med, fill=C_MUTED)
            draw.text((W//2-90*SC, y+158*SC), f"{non.runs} ({non.balls_faced})", font=f_med, fill=C_MUTED, anchor="ra")

        draw.text((W//2+75*SC, y+24*SC), "BOWLER", font=f_med, fill=C_GOLD)
        bowler = bowl.players[bowl.current_bowler_idx] if getattr(bowl, "current_bowler_idx", None) is not None else None
        if bowler:
            draw.text((W//2+75*SC, y+90*SC), _cv_safe_name(bowler.first_name, 18), font=f_big, fill=C_WHITE)
            draw.text((W-150*SC, y+96*SC), f"{bowler.wickets}/{bowler.runs_conceded}", font=f_big, fill=C_RED, anchor="ra")
            draw.text((W//2+75*SC, y+166*SC), f"{format_overs(bowler.balls_bowled)} OV  |  ECO {bowler.get_economy()}", font=f_med, fill=C_MUTED)

        last6 = getattr(match, "last_6_balls", [])[-6:]
        bx = 650*SC
        by = 930*SC
        draw.text((100*SC, by+18*SC), "RECENT", font=f_med, fill=C_MUTED)
        for i, ball in enumerate(last6):
            r = ball.get("runs", 0) if isinstance(ball, dict) else int(ball or 0)
            is_w = bool(ball.get("wicket") or ball.get("is_wicket")) if isinstance(ball, dict) else False
            color = C_RED if is_w else (C_GOLD if r == 6 else ((255, 150, 65, 255) if r == 4 else (65, 82, 130, 255)))
            cx = bx + i*115*SC
            draw.ellipse([cx, by, cx+74*SC, by+74*SC], fill=color, outline=(255,255,255,120), width=2*SC)
            draw.text((cx+37*SC, by+13*SC), "W" if is_w else str(r), font=f_big, fill=C_WHITE, anchor="ma")

        final = img.convert("RGB").resize((1920, 1080), Image.Resampling.LANCZOS)
        bio = BytesIO(); final.save(bio, "PNG", optimize=True); bio.seek(0); return bio
    except Exception as e:
        logger.error(f"Enhanced mid match image error: {e}")
        return None


def generate_solo_top3_image(sorted_players) -> Optional[BytesIO]:
    """Cleaner solo podium card with champion spotlight and compact stats."""
    try:
        if not sorted_players:
            return None
        import math
        SC = 2
        W, H = 1920*SC, 1080*SC
        img = Image.new("RGBA", (W, H), (10, 35, 18, 255))
        draw = ImageDraw.Draw(img)

        # ── 1. BACKGROUND TURF & VIGNETTE ──
        # Turf horizontal bands
        draw.rectangle([0, 0, W, H], fill=(12, 40, 20, 255))
        stripe_h = 80 * SC
        for y in range(0, H, stripe_h):
            if (y // stripe_h) % 2 == 0:
                draw.rectangle([0, y, W, y + stripe_h], fill=(16, 52, 26, 255))

        # Crease / Boundary arc running behind podiums
        draw.arc([W//2 - 700*SC, H - 400*SC, W//2 + 700*SC, H + 200*SC], 
                 start=180, end=360, fill=(255, 255, 255, 75), width=6*SC)

        # Stadium lights spotlight effect
        spotlight = Image.new("RGBA", (W, H))
        s_draw = ImageDraw.Draw(spotlight)
        # Left beam
        s_draw.polygon([(0, 0), (W//2 - 250*SC, H), (W//2 + 100*SC, H)], fill=(255, 255, 220, 20))
        # Right beam
        s_draw.polygon([(W, 0), (W//2 - 100*SC, H), (W//2 + 250*SC, H)], fill=(255, 255, 220, 20))
        # Halo glow at center champion
        s_draw.ellipse([W//2 - 400*SC, 300*SC, W//2 + 400*SC, H], fill=(255, 255, 240, 15))
        img = Image.alpha_composite(img, spotlight)
        draw = ImageDraw.Draw(img)

        # Victory rays radiating from center champion card base
        for angle in range(200, 340, 10):
            rad = math.radians(angle)
            ex = W//2 + int(1500*SC*math.cos(rad))
            ey = 580*SC + int(1500*SC*math.sin(rad))
            draw.line([(W//2, 580*SC), (ex, ey)], fill=(255, 235, 160, 22), width=3*SC)

        C_GOLD, C_SILVER, C_BRONZE = (255, 215, 0, 255), (200, 210, 225, 255), (205, 127, 50, 255)
        C_WHITE, C_MUTED, C_GREEN = (244, 248, 255, 255), (160, 185, 170, 255), (78, 228, 140, 255)
        
        f_title = _get_font(True, 70*SC)
        f_name  = _get_font(True, 44*SC)
        f_score = _get_font(True, 86*SC)
        f_med   = _get_font(False, 30*SC)

        # Title Header
        draw.text((W//2, 68*SC), "🏆 CRICOVERSE SOLO CHAMPIONS 🏆", font=f_title, fill=C_GOLD, anchor="ma")
        draw.text((W//2, 142*SC), "Top performers from the free-for-all match", font=f_med, fill=C_MUTED, anchor="ma")

        # ── 2. DRAW 3D PEDESTALS ──
        # Coordinates for Pedestals: Left (Silver), Center (Gold), Right (Bronze)
        ped_y_gold = 580 * SC
        ped_y_silver = 660 * SC
        ped_y_bronze = 700 * SC
        ped_base_y = H - 150 * SC

        # 2nd Place (Silver) Pedestal
        draw.rounded_rectangle([W//2 - 720*SC, ped_y_silver, W//2 - 360*SC, ped_base_y], radius=15*SC, fill=(100, 110, 120, 255), outline=C_SILVER, width=4*SC)
        draw.ellipse([W//2 - 720*SC, ped_y_silver - 15*SC, W//2 - 360*SC, ped_y_silver + 15*SC], fill=(130, 140, 150, 255), outline=C_SILVER, width=4*SC)
        draw.text((W//2 - 540*SC, ped_y_silver + 50*SC), "2", font=_get_font(True, 120*SC), fill=C_SILVER, anchor="ma")

        # 3rd Place (Bronze) Pedestal
        draw.rounded_rectangle([W//2 + 360*SC, ped_y_bronze, W//2 + 720*SC, ped_base_y], radius=15*SC, fill=(120, 70, 30, 255), outline=C_BRONZE, width=4*SC)
        draw.ellipse([W//2 + 360*SC, ped_y_bronze - 15*SC, W//2 + 720*SC, ped_y_bronze + 15*SC], fill=(145, 90, 50, 255), outline=C_BRONZE, width=4*SC)
        draw.text((W//2 + 540*SC, ped_y_bronze + 50*SC), "3", font=_get_font(True, 100*SC), fill=C_BRONZE, anchor="ma")

        # 1st Place (Gold) Pedestal
        draw.rounded_rectangle([W//2 - 200*SC, ped_y_gold, W//2 + 200*SC, ped_base_y], radius=15*SC, fill=(170, 130, 15, 255), outline=C_GOLD, width=5*SC)
        draw.ellipse([W//2 - 200*SC, ped_y_gold - 20*SC, W//2 + 200*SC, ped_y_gold + 20*SC], fill=(218, 165, 32, 255), outline=C_GOLD, width=5*SC)
        draw.text((W//2, ped_y_gold + 40*SC), "1", font=_get_font(True, 150*SC), fill=C_GOLD, anchor="ma")

        # ── 3. DRAW GLASSMOBILES CARD ON TOP OF PEDESTALS ──
        slots = [
            (0, W//2, 210*SC, 350*SC, C_GOLD),         # Gold Card
            (1, W//2-540*SC, 320*SC, 320*SC, C_SILVER), # Silver Card
            (2, W//2+540*SC, 360*SC, 320*SC, C_BRONZE), # Bronze Card
        ]

        for rank, cx, y, h, color in slots:
            if rank >= len(sorted_players):
                continue
            p = sorted_players[rank]
            w = 400*SC if rank else 450*SC
            # Frosted glass panel with white frosted border
            _cv_draw_panel(draw, [cx-w//2, y, cx+w//2, y+h], 24*SC, (12, 38, 22, 215), (255, 255, 255, 45), 2*SC)
            
            # Gold ring frame for Rank Medal Avatar
            draw.ellipse([cx-55*SC, y-55*SC, cx+55*SC, y+55*SC], fill=(15, 30, 20, 255), outline=color, width=4*SC)
            # Short medal representation text inside ring
            med_lbl = "🥇" if rank == 0 else ("🥈" if rank == 1 else "🥉")
            draw.text((cx, y-25*SC), med_lbl, font=_get_font(True, 38*SC), fill=color, anchor="ma")

            # Player stats
            draw.text((cx, y+70*SC), _cv_safe_name(getattr(p, "first_name", "PLAYER"), 16), font=f_name, fill=C_WHITE, anchor="ma")
            draw.text((cx, y+135*SC), f"{getattr(p, 'runs', 0)} Runs", font=f_score, fill=C_GREEN, anchor="ma")
            draw.text((cx, y+225*SC), f"{getattr(p, 'balls_faced', 0)} balls faced", font=f_med, fill=C_MUTED, anchor="ma")
            
            sr = round(getattr(p, "runs", 0) / max(getattr(p, "balls_faced", 1), 1) * 100, 1)
            draw.text((cx, y+275*SC), f"SR {sr}  |  4s {getattr(p, 'boundaries', 0)}  |  6s {getattr(p, 'sixes', 0)}", font=_get_font(False, 22*SC), fill=C_GOLD, anchor="ma")

        # Champion Footer Highlight
        champ = sorted_players[0]
        draw.text((W//2, H-98*SC), f"🏆 CHAMPION: {_cv_safe_name(getattr(champ, 'first_name', 'PLAYER'), 22).upper()} 🏆", font=_get_font(True, 48*SC), fill=C_GOLD, anchor="ma")
        draw.text((W//2, H-48*SC), "CRICOVERSE ULTIMATE SOLO SERIES", font=f_med, fill=C_MUTED, anchor="ma")

        final = img.convert("RGB").resize((1920, 1080), Image.Resampling.LANCZOS)
        bio = BytesIO(); final.save(bio, "PNG", optimize=True); bio.seek(0); return bio
    except Exception as e:
        logger.error(f"Enhanced solo podium error: {e}")
        return None


def generate_newspaper_image(match, winner: "Team", loser: "Team", top_scorer_name: str,
                               top_scorer_runs: int, mom_name: str, margin: str) -> Optional[BytesIO]:
    """Premium newspaper headline card for post-match sharing."""
    try:
        import random
        from datetime import datetime
        SC = 2
        W, H = 1300*SC, 900*SC
        img = Image.new("RGB", (W, H), (241, 234, 214))
        draw = ImageDraw.Draw(img)
        
        # Newspaper texture noise/grain
        for y in range(0, H, 5*SC):
            shade = random.randint(-6, 6)
            draw.line([(0, y), (W, y)], fill=(236+shade, 229+shade, 207+shade), width=1*SC)
        for _ in range(900):
            x, y = random.randrange(W), random.randrange(H)
            v = random.randint(185, 230)
            draw.point((x, y), fill=(v, v-8, v-25))

        INK, RED, GOLD, MUTED = (24, 20, 14), (170, 28, 32), (132, 93, 24), (98, 91, 80)
        f_mast = _get_font(True, 62*SC, serif=True)
        f_head = _get_font(True, 58*SC, serif=True)
        f_sub = _get_font(False, 30*SC, serif=True)
        f_body = _get_font(False, 25*SC, serif=True)
        f_bold = _get_font(True, 28*SC, serif=True)
        f_small = _get_font(False, 19*SC, serif=True)

        # Headline header
        draw.rectangle([0, 0, W, 112*SC], fill=INK)
        draw.text((W//2, 28*SC), "CRICOVERSE CRICKET TIMES", font=f_mast, fill=(255, 224, 92), anchor="ma")
        draw.rectangle([0, 112*SC, W, 146*SC], fill=GOLD)
        draw.text((30*SC, 119*SC), f"MATCH EDITION | {datetime.now().strftime('%d %b %Y')} | {getattr(match, 'group_name', 'CRICOVERSE')[:38]}", font=f_small, fill=(255,248,224))
        draw.text((W-30*SC, 119*SC), "FINAL RESULT", font=f_small, fill=(255,248,224), anchor="ra")

        headline = f"{winner.name.upper()} WIN BY {margin.upper()}"
        y = 172*SC
        for line in _cv_wrap(draw, headline, f_head, W-80*SC, 3):
            draw.text((42*SC, y), line, font=f_head, fill=RED)
            y += 66*SC
        draw.rectangle([42*SC, y+10*SC, W-42*SC, y+16*SC], fill=INK)
        y += 40*SC

        left, right = 45*SC, W//2 + 35*SC
        col_w = W//2 - 80*SC
        draw.text((left, y), "SCOREBOARD", font=f_bold, fill=GOLD)
        draw.text((right, y), "MATCH REPORT", font=f_bold, fill=GOLD)
        y2 = y + 45*SC
        draw.line([(W//2, y), (W//2, H-80*SC)], fill=(170,160,135), width=2*SC)

        # ── SCOREBOARD BOXES ──
        score_rows = [
            (winner.name, f"{winner.score}/{winner.wickets}", f"{format_overs(winner.balls)} ov"),
            (loser.name, f"{loser.score}/{loser.wickets}", f"{format_overs(loser.balls)} ov"),
        ]
        sy = y2
        for name, score, overs in score_rows:
            draw.rounded_rectangle([left, sy, left+col_w, sy+88*SC], radius=10*SC, fill=(230, 222, 198), outline=(178, 163, 130), width=1*SC)
            draw.text((left+20*SC, sy+16*SC), _cv_safe_name(name, 18), font=f_bold, fill=INK)
            draw.text((left+col_w-20*SC, sy+12*SC), score, font=_get_font(True, 42*SC), fill=RED if name == winner.name else INK, anchor="ra")
            draw.text((left+20*SC, sy+55*SC), overs, font=f_small, fill=MUTED)
            sy += 105*SC

        # ── DYNAMIC TOP 2 PERFORMERS PER TEAM ──
        def _get_top_performers(team):
            # Rank based on fantasy points: runs + wickets * 25
            sorted_players = sorted(team.players, key=lambda p: (getattr(p, "runs", 0) + getattr(p, "wickets", 0) * 25), reverse=True)
            res = []
            for p in sorted_players[:2]:
                parts = []
                if getattr(p, "runs", 0) > 0 or getattr(p, "balls_faced", 0) > 0:
                    parts.append(f"{p.runs} ({p.balls_faced}b)")
                if getattr(p, "balls_bowled", 0) > 0:
                    parts.append(f"{p.wickets}W/{p.runs_conceded}R")
                perf = " & ".join(parts) if parts else "Did not bat/bowl"
                res.append(f"{p.first_name[:12]}: {perf}")
            return res

        win_perf = _get_top_performers(winner)
        lose_perf = _get_top_performers(loser)

        draw.text((left, sy+12*SC), "TEAM TOP PERFORMERS", font=f_bold, fill=GOLD)
        sy += 50*SC
        
        # Winner Performers
        draw.text((left, sy), f"★ {winner.name.upper()}:", font=_get_font(True, 24*SC, serif=True), fill=RED)
        sy += 28*SC
        for item in win_perf:
            draw.text((left+15*SC, sy), item, font=f_body, fill=INK)
            sy += 30*SC
            
        sy += 10*SC
        # Loser Performers
        draw.text((left, sy), f"★ {loser.name.upper()}:", font=_get_font(True, 24*SC, serif=True), fill=INK)
        sy += 28*SC
        for item in lose_perf:
            draw.text((left+15*SC, sy), item, font=f_body, fill=INK)
            sy += 30*SC

        # ── MATCH REPORT STORY ──
        story = (
            f"{winner.name} produced the cleaner finish in a {getattr(match, 'total_overs', 0)}-over contest, "
            f"closing the game by {margin}. {top_scorer_name} set the tone with {top_scorer_runs} runs, "
            f"while {mom_name} walked away with the headline moment."
        )
        ry = y2
        for line in _cv_wrap(draw, story, f_sub, col_w, 7):
            draw.text((right, ry), line, font=f_sub, fill=INK)
            ry += 42*SC
            
        quote = random.choice(_SUBHEADLINES).format(winner=winner.name, loser=loser.name, top_scorer=top_scorer_name)
        ry += 20*SC
        draw.rounded_rectangle([right, ry, right+col_w, ry+118*SC], radius=12*SC, fill=(224, 214, 188), outline=(168, 151, 118), width=1*SC)
        for line in _cv_wrap(draw, quote, f_body, col_w-40*SC, 3):
            draw.text((right+20*SC, ry+18*SC), line, font=f_body, fill=RED)
            ry += 30*SC

        # ── DOUBLE-BORDERED POTM SPOTLIGHT BLOCK ──
        potm_y = ry + 25*SC
        potm_h = 130*SC
        
        # Outer Border
        draw.rectangle([right, potm_y, right+col_w, potm_y+potm_h], outline=GOLD, width=3*SC)
        # Inner Border
        inset = 5 * SC
        draw.rectangle([right+inset, potm_y+inset, right+col_w-inset, potm_y+potm_h-inset], outline=INK, width=1*SC)
        
        # Text Spotlight
        draw.text((right + col_w//2, potm_y + 15*SC), "★ PLAYER OF THE MATCH ★", font=f_bold, fill=RED, anchor="ma")
        draw.text((right + col_w//2, potm_y + 55*SC), mom_name.upper(), font=_get_font(True, 34*SC, serif=True), fill=INK, anchor="ma")
        draw.text((right + col_w//2, potm_y + 98*SC), "Outstanding performance in today's match!", font=f_small, fill=MUTED, anchor="ma")

        # Footer strip
        draw.rectangle([0, H-58*SC, W, H], fill=INK)
        draw.text((30*SC, H-40*SC), "Generated by Cricoverse | Tap Share Headline to post this result", font=f_small, fill=(214, 204, 178))
        
        final = img.resize((1300, 900), Image.Resampling.LANCZOS)
        bio = BytesIO(); final.save(bio, "PNG", optimize=True); bio.seek(0); return bio
    except Exception as e:
        logger.error(f"Enhanced newspaper image error: {e}")
        return None


async def _send_user_notice(update: Update, title: str, body: str, action: str = None, level: str = "info"):
    icons = {
        "info": "ℹ️",
        "success": "✅",
        "warning": "⚠️",
        "error": "❌",
        "live": "🏏",
    }
    text = (
        f"{icons.get(level, 'ℹ️')} <b>{title}</b>\n"
        f"─────────────────\n"
        f"{body}"
    )
    if action:
        text += f"\n\n<i>{action}</i>"
    await update.message.reply_text(text, parse_mode=ParseMode.HTML)


async def game_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Polished game menu with safer messaging."""
    try:
        chat = update.effective_chat
        user = update.effective_user

        if not await check_group_ban(update, context):
            return

        if chat.type == "private":
            await _send_user_notice(
                update,
                "Group Match Required",
                "Cricoverse matches are started inside Telegram groups so everyone can join from the same lobby.",
                "Add me to a group, make me admin, then use /game there.",
                "warning"
            )
            return

        if chat.id in active_matches:
            match = active_matches[chat.id]
            if match.phase == GamePhase.MATCH_ENDED:
                del active_matches[chat.id]
            else:
                await _send_user_notice(
                    update,
                    "Match Already Running",
                    "There is already an active lobby or match in this group.",
                    "Use /scorecard to view it, /players for squads, or /endmatch if the host/admin needs to stop it.",
                    "warning"
                )
                return

        if chat.id not in registered_groups:
            registered_groups[chat.id] = {
                "group_id": chat.id,
                "group_name": chat.title,
                "total_matches": 0,
                "commentary_style": "english"
            }
            save_data()
            try:
                msg = f"🆕 <b>Bot Added to New Group</b>\n🏟 <b>{html.escape(chat.title or 'Unknown Group')}</b>\n🆔 <code>{chat.id}</code>"
                await context.bot.send_message(chat_id=SUPPORT_GROUP_ID, text=msg, parse_mode=ParseMode.HTML)
            except Exception:
                pass

        keyboard = [
            [InlineKeyboardButton("⚔️ Solo Mode", callback_data="mode_solo"),
             InlineKeyboardButton("🤖 AI Mode (DM)", callback_data="mode_ai")],
            [InlineKeyboardButton("👥 Team Mode", callback_data="mode_team")],
            [InlineKeyboardButton("📝 Registration", callback_data="tour_registration_mode"),
             InlineKeyboardButton("🏦 Auction", callback_data="tour_auction_mode")],
            [InlineKeyboardButton("🏆 Tournament Mode", callback_data="mode_tournament")]
        ]

        msg = (
            f"╭━─────────────────\n"
            f"┃ 👥 <b>𝗧𝗲𝗮𝗺 𝗠𝗼𝗱𝗲</b>\n"
            f"┃ ↳ Captains, toss, innings & scorecards.\n"
            f"┣━─────────────────\n"
            f"┃ 👤 <b>𝗦𝗼𝗹𝗼 𝗠𝗼𝗱𝗲</b>\n"
            f"┃ ↳ Free-for-all battle!\n"
            f"┣━─────────────────\n"
            f"┃ 🤖 <b>𝗔𝗜 𝗠𝗼𝗱𝗲</b>\n"
            f"┃ ↳ Private challenge in your DMs.\n"
            f"┣━─────────────────\n"
            f"┃ 🏆 <b>𝗧𝗼𝘂𝗿𝗻𝗮𝗺𝗲𝗻𝘁 / 𝗔𝘂𝗰𝘁𝗶𝗼𝗻</b>\n"
            f"┃ ↳ League tools for approved groups.\n"
            f"┣━─────────────────\n"
            f"┃ 👤 Requested by: {html.escape(user.first_name or 'Player')}\n"
            f"╰━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        )

        try:
            await context.bot.send_photo(
                chat_id=chat.id,
                photo=MEDIA_ASSETS.get("mode_select", "https://t.me/cricoverse/7"),
                caption=msg,
                reply_markup=InlineKeyboardMarkup(keyboard),
                parse_mode=ParseMode.HTML
            )
        except Exception:
            await context.bot.send_message(
                chat_id=chat.id,
                text=msg,
                reply_markup=InlineKeyboardMarkup(keyboard),
                parse_mode=ParseMode.HTML
            )
    except Exception as e:
        logger.error(f"Critical error in polished game_command: {e}", exc_info=True)
        try:
            await _send_user_notice(update, "Could Not Open Game Menu", "Something went wrong while preparing the match menu.", "Please try /game again in a few seconds.", "error")
        except Exception:
            pass


async def extend_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Professional lobby extension command."""
    chat_id = update.effective_chat.id
    user_id = update.effective_user.id
    match = active_matches.get(chat_id)
    if not match:
        await _send_user_notice(update, "No Active Match", "There is no active lobby or match to extend.", "Use /game to start a new match.", "warning")
        return

    try:
        member = await context.bot.get_chat_member(chat_id, user_id)
        is_admin = member.status in ["creator", "administrator"]
    except Exception:
        is_admin = False

    if not is_admin:
        await _send_user_notice(update, "Admin Only", "Only group admins can extend lobby or match time.", None, "error")
        return

    if not context.args:
        await _send_user_notice(
            update,
            "Extension Time Needed",
            "Please provide the number of seconds to add.",
            "Example: /extend 60 | Maximum: 180 seconds.",
            "info"
        )
        return

    try:
        seconds = int(context.args[0])
    except ValueError:
        await _send_user_notice(update, "Invalid Time", "The extension must be a number of seconds.", "Example: /extend 90", "error")
        return

    if seconds <= 0 or seconds > 180:
        await _send_user_notice(update, "Extension Out of Range", "You can add between 1 and 180 seconds.", "Try /extend 60.", "warning")
        return

    if getattr(match, "game_mode", None) == "SOLO" or match.phase == GamePhase.SOLO_JOINING:
        match.solo_join_end_time += seconds
        await _send_user_notice(update, "Solo Lobby Extended", f"Added <b>{seconds} seconds</b> to the solo joining lobby.", "Players can still join from the lobby buttons.", "success")
        return

    match.last_activity = time.time() + seconds
    new_deadline = datetime.fromtimestamp(match.last_activity)
    await _send_user_notice(
        update,
        "Match Time Extended",
        f"Added <b>{seconds} seconds</b> to the current phase.\nNew deadline: <b>{new_deadline.strftime('%I:%M:%S %p')}</b>",
        "Keep the match moving so the timer does not auto-close the phase.",
        "success"
    )


async def groupapprove_unified_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Single /groupapprove entry point so duplicate handlers do not hide tournament approval."""
    user = update.effective_user
    if user.id not in [OWNER_ID, SECOND_APPROVER_ID]:
        return
    await groupapprove_tournament_command(update, context)


async def noop_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Absorb disabled pagination buttons cleanly."""
    query = update.callback_query
    if query:
        await query.answer("You're already on this page.", show_alert=False)


_legacy_scorecard_command = scorecard_command
_legacy_players_command = players_command
_legacy_momentum_command = momentum_command
_legacy_strikemap_command = strikemap_command


async def scorecard_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    if chat and chat.id not in active_matches:
        await _send_user_notice(
            update,
            "No Active Match",
            "There is no live match in this chat yet.",
            "Use /game to open the match menu and start a new game.",
            "warning"
        )
        return
    await _legacy_scorecard_command(update, context)


async def players_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    if chat and chat.id not in active_matches:
        await _send_user_notice(
            update,
            "No Active Squad",
            "No team or solo lobby is active right now.",
            "Start with /game, then use /players after users join.",
            "warning"
        )
        return
    await _legacy_players_command(update, context)


async def momentum_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    if chat and chat.id not in active_matches:
        await _send_user_notice(
            update,
            "Momentum Not Available",
            "Momentum cards need an active match with ball-by-ball data.",
            "Start a match with /game and play at least one over.",
            "info"
        )
        return
    await _legacy_momentum_command(update, context)


async def strikemap_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat = update.effective_chat
    match = active_matches.get(chat.id) if chat else None
    if not match:
        await _send_user_notice(
            update,
            "Strike Map Not Available",
            "Strike maps need an active match and scoring data.",
            "Start a match with /game, then use /strikemap after a few balls.",
            "info"
        )
        return
    await _legacy_strikemap_command(update, context)


async def setup_public_bot_commands(application: Application):
    """Keep Telegram's command menu focused on user-facing commands."""
    commands = [
        BotCommand("game", "Start a cricket match"),
        BotCommand("help", "Rules, modes, and quick guide"),
        BotCommand("mystats", "Your profile card and stats"),
        BotCommand("scorecard", "Live scorecard and worm graph"),
        BotCommand("players", "Current squads and player status"),
        BotCommand("momentum", "Momentum dashboard image"),
        BotCommand("strikemap", "Strike map image"),
        BotCommand("lb", "Global leaderboard"),
        BotCommand("gcsettings", "Group settings for admins"),
        BotCommand("endmatch", "End the current match"),
    ]
    try:
        await application.bot.set_my_commands(commands)
    except Exception as e:
        logger.warning(f"Could not set public bot commands: {e}")


